import type { Article } from '../../../common/types/law.types';

export const ARTICLES_CONST_BUENOS_AIRES: Article[] = [
  { id: 'const-buenos-aires-art-1', lawId: 'const-buenos-aires', number: '1', title: '', text: `La Provincia de Buenos Aires, como parte integrante de la República Argentina, constituida bajo la forma representativa republicana federal, tiene el libre ejercicio de todos los poderes y derechos que por la Constitución Nacional no hayan sido delegados al Gobierno de la Nación.`, plainLanguageExplanation: 'La Provincia de Buenos Aires integra la Nación Argentina bajo la forma federal y republicana, conservando todos los poderes que la Constitución Nacional no delegó al Estado federal.', practicalEffects: ['La Provincia dicta sus propias leyes en materias de su competencia exclusiva', 'Las leyes provinciales prevalecen sobre los actos del poder municipal'], examples: ['La Provincia de Buenos Aires dicta su propio Código de Procedimiento Penal —distinto al federal— porque la organización procesal es una materia no delegada a la Nación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['autonomía provincial', 'federalismo', 'poderes no delegados'], order: 1, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-2', lawId: 'const-buenos-aires', number: '2', title: '', text: `Todo poder público emana del pueblo; y así éste puede alterar o reformar la presente Constitución, siempre que el bien común lo exija y en la forma que por ella se establece.`, plainLanguageExplanation: 'El poder del Estado emana del pueblo, quien puede reformar la Constitución cuando el bien común lo requiera, siguiendo el procedimiento que ella misma establece.', practicalEffects: ['Los ciudadanos tienen el poder de impulsar reformas constitucionales', 'Ningún poder del Estado puede ejercerse en contra de la voluntad popular'], examples: ['En 1994, los bonaerenses eligieron convencionales constituyentes que reformaron la Constitución provincial, ejerciendo el poder soberano de modificarla conforme al procedimiento que ella misma establece.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['soberanía popular', 'poder constituyente', 'reforma constitucional'], order: 2, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-3', lawId: 'const-buenos-aires', number: '3', title: '', text: `En ningún caso y bajo ninguna circunstancia las autoridades provinciales pueden impedir la vigencia de esta Constitución. Toda alteración, modificación, supresión o reforma de la presente Constitución dispuesta por un poder no constituido o realizada sin respetar los procedimientos en ella previstos, como así también la arrogación ilegítima de funciones de un poder en desmedro de otro, será nula de nulidad absoluta y los actos que de ellos se deriven quedarán sujetos a revisión ulterior. Quienes ordenaren, ejecutaren o consintieren actos o hechos para desplazar inconstitucionalmente a las autoridades constituidas regularmente, y aquellos que ejercieren funciones de responsabilidad o asesoramiento político en cualquiera de los poderes públicos, ya sean nacionales, provinciales o municipales, quedarán inhabilitados a perpetuidad para ejercer cargos o empleos públicos, sin perjuicio de las sanciones civiles y penales que fueren aplicables. También agravian y lesionan la sustancia del orden constitucional los actos de corrupción. La ley creará el Tribunal Social de Responsabilidad Política que tendrá a su cargo examinar los actos de corrupción que pudieren cometer los funcionarios de los poderes públicos, provinciales y municipales. A los habitantes de la Provincia les asiste el derecho de no acatar las órdenes o disposiciones provenientes de los usurpadores de los poderes públicos.`, plainLanguageExplanation: 'Ninguna autoridad puede impedir la vigencia de la Constitución. Los actos que la alteren son nulos y sus autores quedan inhabilitados para ejercer cargos públicos.', practicalEffects: ['Los actos anticonstitucionales son nulos de nulidad absoluta e insanable', 'Los responsables de golpes de Estado quedan inhabilitados perpetuamente para cargos públicos'], examples: ['Si un gobierno de facto interrumpiera el orden constitucional bonaerense, todos sus actos serían nulos de pleno derecho, y quienes participaron —funcionarios, asesores, ejecutores— quedarían inhabilitados para siempre de ejercer cargos públicos en la Provincia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['supremacía constitucional', 'nulidad', 'sedición', 'orden institucional'], order: 3, segments: [
        { id: 'cba-art-3-s1', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-3', articleNumber: '3', segmentType: 'PARAGRAPH', text: 'En ningún caso y bajo ninguna circunstancia las autoridades provinciales pueden impedir la vigencia de esta Constitución. Toda alteración, modificación, supresión o reforma de la presente Constitución dispuesta por un poder no constituido o realizada sin respetar los procedimientos en ella previstos, como así también la arrogación ilegítima de funciones de un poder en desmedro de otro, será nula de nulidad absoluta y los actos que de ellos se deriven quedarán sujetos a revisión ulterior.', plainExplanation: 'La Constitución no puede ser suspendida ni reemplazada por ninguna autoridad, ni siquiera en situaciones de emergencia. Cualquier acto que la altere fuera del procedimiento formal de reforma es automáticamente inválido —sin necesidad de que un juez lo declare— y todos los actos que se hayan dictado en consecuencia pueden ser revisados y anulados.', practicalExample: 'Un decreto del gobernador que suspenda el funcionamiento de la Legislatura sin base constitucional es nulo de pleno derecho: los actos que dicte durante esa suspensión (nombramientos, contratos, leyes) quedan sujetos a revisión y pueden ser declarados inválidos por los tribunales.', references: [], order: 0 },
        { id: 'cba-art-3-s2', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-3', articleNumber: '3', segmentType: 'PARAGRAPH', text: 'Quienes ordenaren, ejecutaren o consintieren actos o hechos para desplazar inconstitucionalmente a las autoridades constituidas regularmente, y aquellos que ejercieren funciones de responsabilidad o asesoramiento político en cualquiera de los poderes públicos, ya sean nacionales, provinciales o municipales, quedarán inhabilitados a perpetuidad para ejercer cargos o empleos públicos, sin perjuicio de las sanciones civiles y penales que fueren aplicables.', plainExplanation: 'No solo quien ejecuta el golpe queda inhabilitado: también el asesor político que redactó el plan, el ministro que firmó los decretos o el funcionario municipal que los acató. La inhabilitación es perpetua y se suma a las penas penales (que pueden incluir prisión) y civiles (indemnización por daños).', practicalExample: 'Un intendente que colaboró activamente con un gobierno de facto redactando ordenanzas inconstitucionales queda inhabilitado de por vida para ser concejal, diputado, funcionario provincial o cualquier otro cargo público, aunque haya sido condenado y cumplido la pena penal.', references: [], order: 1 },
        { id: 'cba-art-3-s3', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-3', articleNumber: '3', segmentType: 'PARAGRAPH', text: 'También agravian y lesionan la sustancia del orden constitucional los actos de corrupción. La ley creará el Tribunal Social de Responsabilidad Política que tendrá a su cargo examinar los actos de corrupción que pudieren cometer los funcionarios de los poderes públicos, provinciales y municipales.', plainExplanation: 'La Constitución equipara la corrupción a los atentados contra el orden institucional: ambos dañan los fundamentos del Estado democrático. Crea un Tribunal Social de Responsabilidad Política para investigar actos de corrupción de funcionarios a nivel provincial y municipal —mecanismo adicional e independiente de la justicia penal ordinaria.', practicalExample: 'Un concejal que cobra coimas para aprobar una habilitación comercial no solo comete el delito de cohecho (art. 256 CP), sino que lesiona el orden constitucional. Puede ser investigado tanto por la justicia penal como por el Tribunal Social de Responsabilidad Política.', references: [], order: 2 },
        { id: 'cba-art-3-s4', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-3', articleNumber: '3', segmentType: 'PARAGRAPH', text: 'A los habitantes de la Provincia les asiste el derecho de no acatar las órdenes o disposiciones provenientes de los usurpadores de los poderes públicos.', plainExplanation: 'Este párrafo reconoce expresamente el derecho a la resistencia civil: si alguien usurpa el poder público sin legitimidad constitucional, los ciudadanos no están obligados a obedecer sus órdenes. Es el fundamento jurídico de la desobediencia civil ante regímenes de facto.', practicalExample: 'Si durante un golpe de Estado un "ministro" de facto ordenara a los empleados públicos continuar trabajando bajo las nuevas autoridades, los empleados tendrían derecho constitucional a negarse sin que ello les genere responsabilidad disciplinaria.', references: [], order: 3 },
      ], amendments: [] },
  { id: 'const-buenos-aires-art-4', lawId: 'const-buenos-aires', number: '4', title: '', text: `Los límites territoriales de la Provincia son los que por derecho le corresponden, con arreglo a lo que la Constitución Nacional establece y sin perjuicio de las cesiones o tratados interprovinciales que puedan hacerse autorizados por la Legislatura, por ley sancionada por dos tercios de votos del número total de los miembros de cada Cámara.`, plainLanguageExplanation: 'Los límites territoriales de la Provincia son los reconocidos por derecho según la Constitución Nacional, pudiendo modificarse por tratados interprovinciales o con la Nación.', practicalEffects: ['La Provincia ejerce plena jurisdicción sobre su territorio delimitado', 'Los límites pueden ajustarse mediante acuerdos interprovinciales ratificados por ley'], examples: ['Si Buenos Aires y Entre Ríos quisieran redelimitar el límite fluvial del Río Paraná, necesitarían firmar un tratado interprovincial aprobado por dos tercios de la Legislatura bonaerense.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['territorio provincial', 'límites geográficos', 'jurisdicción', 'tratados interprovinciales'], order: 4, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-5', lawId: 'const-buenos-aires', number: '5', title: '', text: `La Capital de la Provincia de Buenos Aires es la ciudad de La Plata. Las Cámaras Legislativas, el Poder Ejecutivo y la Suprema Corte de Justicia, funcionarán permanentemente en esta ciudad, salvo los casos en que, por causas extraordinarias, la ley dispusiese transitoriamente otra cosa.`, plainLanguageExplanation: 'La Capital de la Provincia es la ciudad de La Plata, sede permanente de los tres poderes del Estado provincial.', practicalEffects: ['Los poderes Ejecutivo, Legislativo y Judicial funcionan permanentemente en La Plata', 'En situaciones excepcionales pueden trasladarse provisionalmente a otro punto de la Provincia'], examples: ['La Legislatura bonaerense sesiona en el Palacio Legislativo de La Plata. Solo en caso de una catástrofe grave podría trasladarse transitoriamente a otra ciudad, por ley que lo autorice.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['capital provincial', 'La Plata', 'sede del gobierno', 'poderes del Estado'], order: 5, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-6', lawId: 'const-buenos-aires', number: '6', title: '', text: `Se llevará un registro del estado civil de las personas, con carácter uniforme y sin distinción de nacionalidades o creencias religiosas y en la forma que lo establezca la ley.`, plainLanguageExplanation: 'El Estado lleva un registro del estado civil de todas las personas de forma uniforme, sin distinción de nacionalidad ni religión, según lo regule la ley.', practicalEffects: ['Toda persona tiene acceso al registro civil sin discriminación por origen o religión', 'La ley define el procedimiento y los efectos del estado civil'], examples: ['Cuando una persona de nacionalidad peruana y religión budista solicita el acta de nacimiento de su hijo nacido en La Plata, el registro civil la emite exactamente igual que para un ciudadano argentino católico.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['registro civil', 'estado civil', 'igualdad', 'personas'], order: 6, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-7', lawId: 'const-buenos-aires', number: '7', title: '', text: `Es inviolable en el territorio de la provincia el derecho que todo hombre tiene para rendir culto a Dios Todopoderoso, libre y públicamente, según los dictados de su conciencia.`, plainLanguageExplanation: 'Es un derecho inviolable para todos los habitantes rendir culto a Dios de manera libre y pública, conforme a su conciencia.', practicalEffects: ['Ninguna autoridad puede impedir o restringir el ejercicio del culto religioso', 'El derecho de culto es público y no requiere autorización estatal'], examples: ['Una comunidad islámica puede celebrar su oración del viernes en su mezquita de Quilmes sin pedir permiso a ninguna autoridad provincial. La policía no puede disolverla ni exigirle autorización previa.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad religiosa', 'culto', 'inviolabilidad', 'conciencia'], order: 7, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-8', lawId: 'const-buenos-aires', number: '8', title: '', text: `El uso de la libertad religiosa, reconocido en el artículo anterior, queda sujeto a lo que prescriben la moral y el orden público.`, plainLanguageExplanation: 'La libertad religiosa tiene como límite la moral y el orden público, que el Estado puede hacer valer para restringir prácticas que los afecten.', practicalEffects: ['Las prácticas religiosas que vulneren la moral o el orden público pueden ser limitadas por el Estado', 'La libertad religiosa no ampara actos delictivos realizados con motivación religiosa'], examples: ['Una secta que practica rituales con daño físico comprobado a sus miembros puede ser intervenida por el Estado invocando el orden público, aunque los participantes consientan. La libertad religiosa no ampara actos que dañen la integridad de las personas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad religiosa', 'orden público', 'moral', 'límites derechos'], order: 8, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-9', lawId: 'const-buenos-aires', number: '9', title: '', text: `El Gobierno de la Provincia coopera a sostener el culto Católico Apostólico Romano, con arreglo a las prescripciones de la Constitución Nacional.`, plainLanguageExplanation: 'El Gobierno Provincial contribuye a sostener el culto Católico Apostólico Romano conforme a las prescripciones de la Constitución Nacional.', practicalEffects: ['El Estado provincial destina recursos para el sostenimiento del culto católico', 'Esta disposición refleja el Concordato histórico entre Argentina y la Santa Sede'], examples: ['La Provincia puede asignar en su presupuesto anual fondos para el sostenimiento del obispo diocesano de La Plata o el mantenimiento de la catedral, en cumplimiento de esta obligación constitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['culto católico', 'financiamiento estatal', 'Iglesia Católica', 'Concordato'], order: 9, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-10', lawId: 'const-buenos-aires', number: '10', title: '', text: `Todos los habitantes de la provincia son, por su naturaleza, libres e independientes y tienen derecho perfecto de defender y de ser protegidos en su vida, libertad, reputación, seguridad y propiedad. Nadie puede ser privado de estos goces sino por vía de penalidad, con arreglo a la ley anterior al hecho del proceso y previa sentencia legal del juez competente.`, plainLanguageExplanation: 'Todos los habitantes son por naturaleza libres e independientes y tienen derecho a ser protegidos en su vida, libertad, reputación, seguridad y propiedad.', practicalEffects: ['El Estado tiene obligación positiva de proteger estos derechos fundamentales', 'Estos derechos son inherentes a la persona y no dependen de concesión estatal'], examples: ['Si la Provincia intentara confiscar la propiedad de un ciudadano sin sentencia judicial ni indemnización, él podría invocar este artículo ante los tribunales para obtener la nulidad del acto.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos naturales', 'vida', 'libertad', 'seguridad', 'propiedad'], order: 10, segments: [
        { id: 'cba-art-10-s1', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-10', articleNumber: '10', segmentType: 'PARAGRAPH', text: 'Todos los habitantes de la provincia son, por su naturaleza, libres e independientes y tienen derecho perfecto de defender y de ser protegidos en su vida, libertad, reputación, seguridad y propiedad.', plainExplanation: 'Estos derechos no los concede el Estado: son inherentes a la persona humana por su sola condición de tal. El Estado tiene la obligación positiva de protegerlos activamente —no solo de no vulnerarlos—, lo que genera deberes de acción: dictar leyes de seguridad, brindar protección policial, garantizar la propiedad.', practicalExample: 'Un ciudadano que es víctima de una banda de extorsionadores puede exigir al Estado provincial una respuesta efectiva de las fuerzas de seguridad, fundado en el deber de proteger su seguridad y propiedad reconocido en este artículo.', references: [], order: 0 },
        { id: 'cba-art-10-s2', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-10', articleNumber: '10', segmentType: 'PARAGRAPH', text: 'Nadie puede ser privado de estos goces sino por vía de penalidad, con arreglo a la ley anterior al hecho del proceso y previa sentencia legal del juez competente.', plainExplanation: 'Solo una condena penal dictada por un juez competente, basada en una ley anterior al hecho juzgado, puede legítimamente restringir estos derechos. Esto incorpora tres garantías en una sola frase: irretroactividad de la ley penal, reserva de ley para las sanciones, y reserva judicial (solo el juez puede condenar).', practicalExample: 'Un intendente no puede ordenar el cierre definitivo de un negocio ni la detención de su dueño: esas medidas solo proceden por sentencia del juez penal o de faltas, fundada en una ley preexistente.', references: [], order: 1 },
      ], amendments: [] },
  { id: 'const-buenos-aires-art-11', lawId: 'const-buenos-aires', number: '11', title: '', text: `Los habitantes de la provincia son iguales ante la ley, y gozan de los derechos y garantías que establece la Constitución Nacional, los que emanan en su consecuencia a través de los tratados celebrados por la Nación y los que se expresan en esta Constitución. La Provincia no admite distinciones, discriminaciones ni privilegios por razones de sexo, raza, religión, nacionalidad, lengua, ideología, opinión, enfermedades de riesgo, características físicas o cualquier otra condición amparada por las normas constitucionales. Es deber de la Provincia promover el desarrollo integral de las personas garantizando la igualdad de oportunidades y la efectiva participación de todos en la organización política, económica y social.`, plainLanguageExplanation: 'Todos los habitantes son iguales ante la ley y gozan de los derechos reconocidos por la Constitución Nacional, tratados internacionales y normas provinciales.', practicalEffects: ['No se admiten discriminaciones fundadas en origen, sexo, religión, raza u otras condiciones', 'Los tratados internacionales de derechos humanos tienen rango constitucional provincial'], examples: ['Una empresa que rechaza contratar a una candidata por estar embarazada viola este artículo: la discriminación por razón de sexo está expresamente prohibida y el Estado tiene el deber de garantizar igualdad de oportunidades.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['igualdad ante la ley', 'no discriminación', 'derechos humanos', 'tratados'], order: 11, segments: [
        { id: 'cba-art-11-s1', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-11', articleNumber: '11', segmentType: 'PARAGRAPH', text: 'Los habitantes de la provincia son iguales ante la ley, y gozan de los derechos y garantías que establece la Constitución Nacional, los que emanan en su consecuencia a través de los tratados celebrados por la Nación y los que se expresan en esta Constitución.', plainExplanation: 'Los derechos de los habitantes bonaerenses tienen tres fuentes que se suman: la Constitución Nacional (con los tratados de derechos humanos incorporados en el art. 75 inc. 22 CN), los tratados que la Nación celebre en el futuro, y la propia Constitución provincial. La Provincia no puede reducir esos derechos, pero sí ampliarlos.', practicalExample: 'Un juez bonaerense puede aplicar directamente la Convención sobre los Derechos del Niño para resolver un caso de familia, ya que ese tratado forma parte del bloque de derechos que reconoce este artículo.', references: [], order: 0 },
        { id: 'cba-art-11-s2', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-11', articleNumber: '11', segmentType: 'PARAGRAPH', text: 'La Provincia no admite distinciones, discriminaciones ni privilegios por razones de sexo, raza, religión, nacionalidad, lengua, ideología, opinión, enfermedades de riesgo, características físicas o cualquier otra condición amparada por las normas constitucionales.', plainExplanation: 'La lista de causas de discriminación prohibidas es abierta ("cualquier otra condición"): sexo, raza, religión, nacionalidad, idioma, ideología, opinión política, enfermedades (como HIV), características físicas y más. Esto significa que leyes o actos administrativos que establezcan diferencias basadas en estos criterios pueden ser impugnados como inconstitucionales.', practicalExample: 'Una ordenanza municipal que prohíba el acceso a playas públicas a personas con enfermedades crónicas de riesgo (como HIV) es inconstitucional por discriminación por "enfermedades de riesgo", categoría expresamente prohibida por este artículo.', references: [], order: 1 },
        { id: 'cba-art-11-s3', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-11', articleNumber: '11', segmentType: 'PARAGRAPH', text: 'Es deber de la Provincia promover el desarrollo integral de las personas garantizando la igualdad de oportunidades y la efectiva participación de todos en la organización política, económica y social.', plainExplanation: 'La igualdad no es solo formal (todos son iguales ante la ley): la Constitución impone una igualdad material o sustantiva. El Estado debe remover obstáculos reales que impidan a las personas ejercer sus derechos. Esto justifica las políticas de acción afirmativa (cuotas, becas, subsidios) para grupos históricamente desaventajados.', practicalExample: 'La Provincia puede establecer cupos de empleo público para personas con discapacidad (acción afirmativa) precisamente porque este artículo ordena garantizar la igualdad de oportunidades real, no solo declarativa.', references: [], order: 2 },
      ], amendments: [] },
  { id: 'const-buenos-aires-art-12', lawId: 'const-buenos-aires', number: '12', title: '', text: `Todas las personas en la Provincia gozan, entre otros, de los siguientes derechos: 1) A la vida, desde la concepción hasta la muerte natural. 2) A conocer la identidad de origen. 3) Al respecto de la dignidad, al honor, la integridad física, psíquica y moral. 4) A la información y a la comunicación. 5) A la inviolabilidad de los documentos privados y cualquier otra forma de comunicación personal. La ley establecerá los casos de excepción en que por resolución judicial fundada podrá procederse al examen, interferencia o interceptación de los mismos o de la correspondencia epistolar.`, plainLanguageExplanation: 'La Constitución reconoce expresamente una lista de derechos fundamentales: vida desde la concepción, identidad, integridad, honor, intimidad, y libre desarrollo de la personalidad, entre otros.', practicalEffects: ['Estos derechos son directamente operativos y exigibles ante los tribunales', 'La enumeración no excluye otros derechos reconocidos por la Constitución Nacional y tratados'], examples: ['Un adoptado mayor de edad puede iniciar una búsqueda de sus padres biológicos invocando el inc. 2 de este artículo: el derecho a conocer la identidad de origen es exigible directamente ante los tribunales.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos fundamentales', 'vida', 'identidad', 'intimidad', 'integridad'], order: 12, segments: [
        { id: 'cba-art-12-s1', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-12', articleNumber: '12', segmentType: 'INCISO', text: '1) A la vida, desde la concepción hasta la muerte natural.', plainExplanation: 'La Constitución provincial protege la vida desde la concepción, lo que tiene implicancias para la legislación de interrupción voluntaria del embarazo y para el sistema de salud provincial. Establece además un límite: "muerte natural", que se opone a la eutanasia activa.', practicalExample: 'Este inciso es invocado en debates judiciales sobre el alcance de las leyes provinciales de interrupción del embarazo y en casos de pacientes terminales que solicitan sedación paliativa.', references: [], order: 0 },
        { id: 'cba-art-12-s2', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-12', articleNumber: '12', segmentType: 'INCISO', text: '2) A conocer la identidad de origen.', plainExplanation: 'Toda persona tiene derecho a saber quiénes son sus padres biológicos, independientemente de si fue adoptada o concebida por técnicas de reproducción asistida. Este derecho puede ejercerse ante los tribunales de familia con asistencia del Estado.', practicalExample: 'Una persona adoptada a los 3 años puede, al cumplir la mayoría de edad, iniciar una acción judicial para acceder a sus datos de filiación biológica, apoyándose en este inciso y en el Código Civil y Comercial.', references: [], order: 1 },
        { id: 'cba-art-12-s3', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-12', articleNumber: '12', segmentType: 'INCISO', text: '3) Al respeto de la dignidad, al honor, la integridad física, psíquica y moral.', plainExplanation: 'La dignidad humana es el fundamento de todos los derechos. La integridad se protege en sus tres dimensiones: física (no torturas, no maltrato), psíquica (no violencia psicológica) y moral (no humillaciones degradantes). Cualquier violación genera responsabilidad del Estado y de los particulares.', practicalExample: 'Un detenido en una comisaría que recibe trato degradante puede iniciar acción de amparo invocando este inciso para exigir el cese inmediato y reclamar daños y perjuicios al Estado provincial.', references: [], order: 2 },
        { id: 'cba-art-12-s4', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-12', articleNumber: '12', segmentType: 'INCISO', text: '4) A la información y a la comunicación.', plainExplanation: 'El derecho a la información tiene dos dimensiones: recibir información (acceso a datos de interés público, noticias, conocimiento) y comunicarla (libertad de expresión activa). El Estado no puede obstaculizar ninguna de las dos sin causa constitucional suficiente.', practicalExample: 'Un periodista que solicita información pública a un organismo provincial puede invocar este inciso junto con la Ley de Acceso a la Información Pública para obtener datos sobre contratos estatales.', references: [], order: 3 },
        { id: 'cba-art-12-s5', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-12', articleNumber: '12', segmentType: 'INCISO', text: '5) A la inviolabilidad de los documentos privados y cualquier otra forma de comunicación personal. La ley establecerá los casos de excepción en que por resolución judicial fundada podrá procederse al examen, interferencia o interceptación de los mismos o de la correspondencia epistolar.', plainExplanation: 'Las cartas, correos electrónicos, mensajes de texto, chats y cualquier comunicación privada son inviolables. Solo un juez, mediante resolución fundada, puede ordenar su interceptación en los casos que la ley autorice (como en investigaciones penales graves). Una prueba obtenida de forma clandestina sin orden judicial es nula.', practicalExample: 'Los mensajes de WhatsApp de un imputado solo pueden ser usados como prueba si fueron obtenidos con autorización judicial previa. Si la fiscalía los consiguió accediendo al celular sin orden, el juez debe declarar la nulidad de esa prueba.', references: [], order: 4 },
      ], amendments: [] },
  { id: 'const-buenos-aires-art-13', lawId: 'const-buenos-aires', number: '13', title: '', text: `La libertad de expresar pensamientos y opiniones por cualquier medio, es un derecho asegurado a los habitantes de la Provincia. La Legislatura no dictará medidas preventivas, ni leyes o reglamentos que coarten, restrinjan o limiten el uso de la libertad de prensa. Solamente podrán calificarse de abusos de la libertad de prensa los hechos constitutivos de delitos comunes. La determinación de sus penas incumbirá a la Legislatura y su juzgamiento a los jueces y tribunales ordinarios. Mientras no se dicte la ley correspondiente, se aplicarán las sanciones determinadas por el Código Penal de la Nación. Los delitos cometidos por medio de la prensa nunca se reputarán flagelantes. No se podrá secuestrar las imprentas y sus accesorios como instrumentos del delito durante los procesos. Se admitirá siempre la prueba como descargo, cuando se trate de la conducta oficial de los funcionarios o empleados públicos.`, plainLanguageExplanation: 'La libertad de expresión por cualquier medio está garantizada. No pueden dictarse medidas preventivas ni leyes que la limiten por razones políticas o religiosas.', practicalEffects: ['El Estado no puede censurar expresiones antes de su publicación (prohibición de censura previa)', 'Sí puede establecer responsabilidades posteriores por abusos de la libertad de expresión'], examples: ['Un periodista que publica una nota crítica de un funcionario provincial no puede ser silenciado antes de la publicación. Si la nota contiene afirmaciones falsas y dañosas, el funcionario puede reclamar daños después, pero no impedir la publicación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de expresión', 'censura previa', 'prensa', 'opinión'], order: 13, segments: [
        { id: 'cba-art-13-s1', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-13', articleNumber: '13', segmentType: 'PARAGRAPH', text: 'La libertad de expresar pensamientos y opiniones por cualquier medio, es un derecho asegurado a los habitantes de la Provincia. La Legislatura no dictará medidas preventivas, ni leyes o reglamentos que coarten, restrinjan o limiten el uso de la libertad de prensa.', plainExplanation: 'La prohibición de la censura previa es absoluta: el Estado no puede impedir la publicación de ideas, noticias ni opiniones antes de que se difundan. Tampoco puede dictar leyes que en la práctica tengan ese efecto (censura indirecta). La responsabilidad por los abusos solo puede exigirse después de la publicación, nunca antes.', practicalExample: 'Si un juez provincial dictara una medida cautelar ordenando a un portal de noticias no publicar una investigación periodística, esa medida sería inconstitucional por constituir censura previa, y el afectado podría solicitar su levantamiento inmediato.', references: [], order: 0 },
        { id: 'cba-art-13-s2', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-13', articleNumber: '13', segmentType: 'PARAGRAPH', text: 'Solamente podrán calificarse de abusos de la libertad de prensa los hechos constitutivos de delitos comunes. La determinación de sus penas incumbirá a la Legislatura y su juzgamiento a los jueces y tribunales ordinarios. Mientras no se dicte la ley correspondiente, se aplicarán las sanciones determinadas por el Código Penal de la Nación.', plainExplanation: 'Los "abusos de prensa" solo son aquellos que configuran delitos del derecho común (calumnias, injurias, incitación a la violencia). No hay delitos especiales "de prensa": los mismos jueces ordinarios que juzgan delitos comunes juzgan los cometidos a través de medios de comunicación.', practicalExample: 'Un conductor radial que difama a una persona puede ser procesado por calumnias e injurias bajo el Código Penal común. No existe un "tribunal de prensa" especial ni penas agravadas por tratarse de un medio de comunicación.', references: [], order: 1 },
        { id: 'cba-art-13-s3', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-13', articleNumber: '13', segmentType: 'PARAGRAPH', text: 'Los delitos cometidos por medio de la prensa nunca se reputarán flagelantes. No se podrá secuestrar las imprentas y sus accesorios como instrumentos del delito durante los procesos.', plainExplanation: 'Dos garantías adicionales: los delitos de prensa nunca se consideran "en flagrancia" (no permite detención sin orden judicial inmediata) y las instalaciones de los medios —imprentas, equipos, servidores— no pueden ser secuestrados como instrumentos del delito durante el proceso, lo que evita que el medio deje de funcionar por la persecución penal.', practicalExample: 'Durante la investigación penal a un diario por una publicación presuntamente difamatoria, el juez no puede ordenar el secuestro de las rotativas del medio: la imprenta no puede ser incautada como instrumento del delito.', references: [], order: 2 },
        { id: 'cba-art-13-s4', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-13', articleNumber: '13', segmentType: 'PARAGRAPH', text: 'Se admitirá siempre la prueba como descargo, cuando se trate de la conducta oficial de los funcionarios o empleados públicos.', plainExplanation: 'Esta es la consagración provincial de la doctrina "real malicia" aplicada a la conducta de funcionarios: cuando un medio publica información sobre el desempeño de un funcionario público, este puede demostrar la verdad como defensa. El funcionario que se siente difamado no puede ganar si el periodista prueba que los hechos publicados son verídicos.', practicalExample: 'Un ministro provincial demanda a un periodista por publicar que firmó contratos irregulares. El periodista puede presentar como prueba de descargo los contratos, facturas y correos que demuestran la irregularidad: si acredita la verdad del hecho, queda exento de responsabilidad.', references: [], order: 3 },
      ], amendments: [] },
  { id: 'const-buenos-aires-art-14', lawId: 'const-buenos-aires', number: '14', title: '', text: `Queda asegurado a todos los habitantes de la Provincia el derecho de reunión pacífica para tratar asuntos públicos o privados, con tal que no turben el orden público, así como el de petición individual o colectiva, ante todas y cada una de sus autoridades, sea para solicitar gracia o justicia, instruir a sus representantes o para pedir la reparación de agravios. En ningún caso una reunión de personas podrá atribuirse la representación ni los derechos del pueblo, ni peticionar en su nombre, y los que lo hicieren cometer delito de sedición.`, plainLanguageExplanation: 'Se garantiza el derecho de reunión pacífica para tratar asuntos públicos o privados, y el de petición individual o colectiva a las autoridades.', practicalEffects: ['Las reuniones pacíficas no requieren autorización previa del Estado', 'Las autoridades deben responder las peticiones formuladas por los ciudadanos'], examples: ['Un grupo de vecinos puede convocar una asamblea barrial en la plaza sin pedir permiso municipal. Si el intendente la prohíbe preventivamente, los vecinos pueden solicitar amparo invocando el derecho de reunión pacífica reconocido por este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de reunión', 'derecho de petición', 'orden público', 'asociación'], order: 14, segments: [
        { id: 'cba-art-14-s1', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-14', articleNumber: '14', segmentType: 'PARAGRAPH', text: 'Queda asegurado a todos los habitantes de la Provincia el derecho de reunión pacífica para tratar asuntos públicos o privados, con tal que no turben el orden público, así como el de petición individual o colectiva, ante todas y cada una de sus autoridades, sea para solicitar gracia o justicia, instruir a sus representantes o para pedir la reparación de agravios.', plainExplanation: 'El derecho de reunión no requiere autorización previa: basta con que sea pacífica y no altere el orden público. El derecho de petición es más amplio: cualquier persona, sola o en grupo, puede dirigirse a cualquier autoridad (intendente, legislador, gobernador, juez) para pedir una solución, una reparación o información. La autoridad tiene la obligación de responder.', practicalExample: 'Una asociación de padres puede presentar una nota al director de escuela, al supervisor, al ministro de educación y al propio gobernador reclamando la refacción del edificio escolar. Cada uno tiene obligación de responder o derivar correctamente la solicitud.', references: [], order: 0 },
        { id: 'cba-art-14-s2', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-14', articleNumber: '14', segmentType: 'PARAGRAPH', text: 'En ningún caso una reunión de personas podrá atribuirse la representación ni los derechos del pueblo, ni peticionar en su nombre, y los que lo hicieren cometer delito de sedición.', plainExplanation: 'Este párrafo establece el límite: ninguna multitud, por grande que sea, puede arrogarse la representación del "pueblo" ni actuar en su nombre. La soberanía popular se ejerce a través de las instituciones (voto, representantes electos), no por la vía de hecho. Quien lo intente comete sedición.', practicalExample: 'Un grupo que ocupa la sede del gobierno provincial proclamando gobernar "en nombre del pueblo" comete sedición: el artículo deja claro que ninguna reunión puede atribuirse la representación popular ni ejercer funciones del poder constituido.', references: [], order: 1 },
      ], amendments: [] },
  { id: 'const-buenos-aires-art-15', lawId: 'const-buenos-aires', number: '15', title: '', text: `La Provincia asegura la tutela judicial continua y efectiva, el acceso irrestricto a la justicia, la gratuidad de los trámites y la asistencia letrada a quienes carezcan de recursos suficientes y la inviolabilidad de la defensa de la persona y de los derechos en todo procedimiento administrativo o judicial. Las causas deberán decidirse en tiempo razonable. El retardo en dictar sentencia y las dilaciones indebidas cuando sean reiteradas, constituyen falta grave.`, plainLanguageExplanation: 'La Provincia garantiza tutela judicial efectiva, acceso irrestricto a la justicia, gratuidad de trámites para quienes no tienen recursos y asistencia letrada.', practicalEffects: ['Los ciudadanos sin recursos económicos tienen derecho a asistencia jurídica gratuita (defensa pública)', 'Ninguna traba formal puede impedir el acceso a la justicia'], examples: ['Una persona sin recursos que recibe una demanda de desalojo puede solicitar un defensor oficial gratuito: la Provincia está constitucionalmente obligada a proveerlo para garantizar la igualdad de armas en el proceso.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tutela judicial', 'acceso a la justicia', 'gratuidad', 'defensa pública'], order: 15, segments: [
        { id: 'cba-art-15-s1', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-15', articleNumber: '15', segmentType: 'PARAGRAPH', text: 'La Provincia asegura la tutela judicial continua y efectiva, el acceso irrestricto a la justicia, la gratuidad de los trámites y la asistencia letrada a quienes carezcan de recursos suficientes y la inviolabilidad de la defensa de la persona y de los derechos en todo procedimiento administrativo o judicial.', plainExplanation: 'Cuatro garantías se integran en un único mandato: (1) tutela judicial efectiva (no solo formal), (2) acceso irrestricto (ningún requisito puede volverlo de facto imposible para el ciudadano común), (3) gratuidad para quienes no pueden pagar (defensa pública, servicio de justicia sin aranceles para indigentes), y (4) inviolabilidad de la defensa en cualquier tipo de procedimiento, sea ante un juzgado o ante la administración pública.', practicalExample: 'Un trabajador despedido sin recursos puede acudir gratuitamente al fuero laboral con un abogado de oficio, sin pagar tasa de justicia, y el proceso debe resolverse en tiempo razonable. Si el juez demora años sin razón, incurre en falta grave.', references: [], order: 0 },
        { id: 'cba-art-15-s2', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-15', articleNumber: '15', segmentType: 'PARAGRAPH', text: 'Las causas deberán decidirse en tiempo razonable. El retardo en dictar sentencia y las dilaciones indebidas cuando sean reiteradas, constituyen falta grave.', plainExplanation: 'El "plazo razonable" no es solo un principio: su violación sistemática constituye una falta grave que habilita sanciones disciplinarias al juez o funcionario responsable. Esto crea un mecanismo de responsabilidad directa para combatir la mora judicial crónica.', practicalExample: 'Un juez de familia que tiene 300 causas sin resolver por más de 3 años puede ser sancionado disciplinariamente por la Suprema Corte de Justicia bonaerense sobre la base de este artículo, que califica el retardo reiterado como falta grave.', references: [], order: 1 },
      ], amendments: [] },
  { id: 'const-buenos-aires-art-16', lawId: 'const-buenos-aires', number: '16', title: '', text: `Nadie podrá ser detenido sin que preceda indagatoria sumaria que produzca semiplena prueba o indicio vehemente de un hecho que merezca pena corporal, salvo en caso flagrante, en que todo delincuente puede ser detenido por cualquiera persona y conducido inmediatamente a presencia de su juez; ni podrá ser constituido en prisión sin orden escrita de juez competente.`, plainLanguageExplanation: 'Nadie puede ser detenido sin orden escrita de juez competente, salvo en caso de flagrancia donde cualquier persona puede aprehender al delincuente y llevarlo ante el juez.', practicalEffects: ['La detención sin orden judicial solo procede en caso de flagrancia', 'La orden de detención debe ser escrita y emanar de juez competente'], examples: ['Si un agente policial detiene a alguien por "merodeo" sin flagrancia ni orden judicial, la persona puede exigir su libertad de inmediato mediante habeas corpus: la detención sin orden ni flagrancia viola este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['detención', 'orden judicial', 'flagrancia', 'libertad personal'], order: 16, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-17', lawId: 'const-buenos-aires', number: '17', title: '', text: `Toda orden de pesquisa, detención de una o más personas o embargo de propiedades, deberá especificar las personas u objetos de pesquisa o embargo, describiendo particularmente el lugar que debe ser registrado, y no se expedirá mandato de esta clase sino por hecho punible apoyado en juramento o afirmación, sin cuyos requisitos la orden o mandato no será exequible.`, plainLanguageExplanation: 'Toda orden de pesquisa, detención o embargo debe especificar las personas u objetos buscados y describir el lugar a registrar, fundada en juramento o afirmación.', practicalEffects: ['No pueden expedirse órdenes genéricas de registro o detención ("órdenes en blanco")', 'El requisito de especificidad protege contra los registros o detenciones arbitrarios'], examples: ['Una orden de allanamiento que diga "registro de todos los domicilios de la cuadra" es inválida: debe especificar la dirección exacta y los objetos buscados. Todo lo secuestrado bajo una orden genérica es nulo como prueba.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['allanamiento', 'orden judicial', 'especificidad', 'embargo'], order: 17, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-18', lawId: 'const-buenos-aires', number: '18', title: '', text: `No podrá juzgarse por comisiones ni tribunales especiales, cualquiera que sea la denominación que se les dé.`, plainLanguageExplanation: 'Ninguna persona puede ser juzgada por comisiones o tribunales especiales creados ad hoc: solo los tribunales ordinarios establecidos por ley tienen jurisdicción.', practicalEffects: ['La garantía del juez natural asegura que nadie sea juzgado por un tribunal creado para su caso', 'Los tribunales militares y similares no pueden juzgar a civiles'], examples: ['Una "comisión investigadora" creada por decreto del gobernador para juzgar a un funcionario acusado de corrupción sería inconstitucional: solo los jueces ordinarios preexistentes pueden juzgar, nunca comisiones o tribunales creados para el caso.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juez natural', 'tribunales especiales', 'garantías procesales', 'debido proceso'], order: 18, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-19', lawId: 'const-buenos-aires', number: '19', title: '', text: `Todo aprehendido será notificado de la causa de su detención dentro de las veinticuatro horas.`, plainLanguageExplanation: 'Todo detenido debe ser informado de los motivos de su detención dentro de las 24 horas de producida la aprehensión.', practicalEffects: ['El derecho a conocer la causa de la detención permite al detenido ejercer su defensa', 'Pasadas las 24 horas sin notificación, la detención puede ser impugnada judicialmente'], examples: ['Un detenido que lleva 30 horas sin que le informen por qué está preso puede interponer habeas corpus: la falta de notificación en las primeras 24 horas hace la detención ilegítima, independientemente de si existía una causa real.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho a la información', 'detención', '24 horas', 'causa de detención'], order: 19, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-20', lawId: 'const-buenos-aires', number: '20', title: '', text: `Se establecen las siguientes garantías de los derechos constitucionales: 1.- Toda persona que de modo actual o inminente, sufra en forma ilegal o arbitraria, cualquier tipo de restricción o amenaza en su libertad personal, podrá ejercer la garantía de Habeas Corpus recurriendo ante cualquier juez. Igualmente se procederá en caso de agravamiento arbitrario de las condiciones de su tención legal o en el de desaparición forzada de personas. La presentación no requerirá formalidad alguna y podrá realizarse por sí mismo o a través de terceros, aún sin mandato. El juez con conocimiento de los hechos y de resultar procedente, hará cesar inmediatamente y dentro de los veinticuatro horas, la restricción, amenaza o agravamiento, aun durante la vigencia del estado de sitio. Incurrirá en falta grave el juez o funcionario que no cumpliere con las disposiciones precedentes. 2.- La garantía de Amparo podrá ser ejercida por el Estado en sentido lato o por particulares, cuando por cualquier acto, hecho, decisión u omisión, proveniente de autoridad pública o de persona privada, se lesione o amenace, en forma actual o inminente con arbitrariedad o ilegalidad manifiesta, el ejercicio de los derechos constitucionales individuales y colectivos. El Amparo procederá ante cualquier juez siempre que no pudieren utilizarse, por la naturaleza del caso, los remedios ordinarios sin daño grave o irreparable y no procediese la garantía de Habeas Corpus. No procederá contra leyes o contra actos jurisdiccionales emanados del Poder Judicial. La ley regulará el Amparo estableciendo un procedimiento breve y de pronta resolución para el ejercicio de esta garantía, sin perjuicio de la facultad del juez para acelerar su trámite, mediante formas más sencillas que se adapten a la naturaleza de la cuestión planteada. En el caso, el juez podrá declarar la inconstitucionalidad de la norma en que se funde el acto u omisión lesivos. 3.- A través de la garantía de Habeas Data, que se regirá por el procedimiento que la ley determine, toda persona podrá conocer lo que conste de la misma en forma de registro, archivo o banco de datos de organismos públicos, o privados destinados a proveer informes, así como la finalidad a que se destine esa información, y a requerir su rectificación, actualización o cancelación. No podrá afectarse el secreto de las fuentes y el contenido de la información periodística. Ningún dato podrá registrarse con fines discriminatorios ni será proporcionado a terceros, salvo que tengan un interés legítimo. El uso de la informática no podrá vulnerar el honor, la intimidad personal y familiar y el pleno ejercicio de los derechos. Todas las garantías precedentes son operativas. En ausencia de reglamentación, los jueces resolverán sobre la procedencia de las acciones que se promuevan, en consideración a la naturaleza de los derechos que se pretendan tutelar.`, plainLanguageExplanation: 'Se establecen tres garantías constitucionales: Habeas Corpus contra detenciones ilegales, Amparo contra actos arbitrarios que lesionen derechos, y Habeas Data para controlar el uso de datos personales.', practicalEffects: ['El Habeas Corpus protege la libertad física de toda persona frente a detenciones ilegales o arbitrarias', 'El Amparo permite impugnar actos del Estado o privados que lesionen derechos constitucionales', 'El Habeas Data permite conocer, corregir o cancelar datos personales en registros públicos o privados'], examples: ['Una persona detenida sin orden judicial puede, por sí misma o a través de cualquier familiar, presentar un habeas corpus ante cualquier juez —incluso en fines de semana o feriados—: el juez tiene 24 horas para ordenar su libertad si la detención es ilegal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['habeas corpus', 'amparo', 'habeas data', 'garantías constitucionales'], order: 20, segments: [
        { id: 'cba-art-20-s1', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-20', articleNumber: '20', segmentType: 'INCISO', text: '1.- Toda persona que de modo actual o inminente, sufra en forma ilegal o arbitraria, cualquier tipo de restricción o amenaza en su libertad personal, podrá ejercer la garantía de Habeas Corpus recurriendo ante cualquier juez. Igualmente se procederá en caso de agravamiento arbitrario de las condiciones de su detención legal o en el de desaparición forzada de personas. La presentación no requerirá formalidad alguna y podrá realizarse por sí mismo o a través de terceros, aún sin mandato. El juez con conocimiento de los hechos y de resultar procedente, hará cesar inmediatamente y dentro de los veinticuatro horas, la restricción, amenaza o agravamiento, aun durante la vigencia del estado de sitio. Incurrirá en falta grave el juez o funcionario que no cumpliere con las disposiciones precedentes.', plainExplanation: 'El habeas corpus protege la libertad física ante detenciones ilegales o arbitrarias, pero también ante condiciones de detención inhumanas (habeas corpus correctivo) y ante desapariciones forzadas. No requiere abogado, no tiene formalidades: cualquier persona puede presentarlo por el detenido ante cualquier juez, que tiene 24 horas para actuar. Funciona incluso durante el estado de sitio. Un juez que no actúa incurre en falta grave.', practicalExample: 'La madre de un detenido al que no le informan dónde está puede presentar ella misma, a mano y sin abogado, un escrito ante cualquier juzgado de la Provincia diciendo "mi hijo fue detenido ayer y no sé dónde está ni por qué". El juez debe actuar de inmediato, ubicar al detenido y verificar la legalidad de su detención dentro de las 24 horas.', references: [], order: 0 },
        { id: 'cba-art-20-s2', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-20', articleNumber: '20', segmentType: 'INCISO', text: '2.- La garantía de Amparo podrá ser ejercida por el Estado en sentido lato o por particulares, cuando por cualquier acto, hecho, decisión u omisión, proveniente de autoridad pública o de persona privada, se lesione o amenace, en forma actual o inminente con arbitrariedad o ilegalidad manifiesta, el ejercicio de los derechos constitucionales individuales y colectivos. El Amparo procederá ante cualquier juez siempre que no pudieren utilizarse, por la naturaleza del caso, los remedios ordinarios sin daño grave o irreparable y no procediese la garantía de Habeas Corpus. No procederá contra leyes o contra actos jurisdiccionales emanados del Poder Judicial. La ley regulará el Amparo estableciendo un procedimiento breve y de pronta resolución para el ejercicio de esta garantía, sin perjuicio de la facultad del juez para acelerar su trámite, mediante formas más sencillas que se adapten a la naturaleza de la cuestión planteada. En el caso, el juez podrá declarar la inconstitucionalidad de la norma en que se funde el acto u omisión lesivos.', plainExplanation: 'El amparo es la garantía "comodín" para proteger cualquier derecho constitucional (salud, educación, medio ambiente, propiedad, privacidad) que no sea la libertad física (esa la cubre el habeas corpus) ante actos arbitrarios o ilegales tanto del Estado como de personas privadas. Es urgente, informal y breve. Notable: el amparo bonaerense también procede contra actos de particulares (empresas, obras sociales, etc.) y el juez puede declarar inconstitucional la norma en que se basa el acto lesivo.', practicalExample: 'Una obra social que niega cobertura para un medicamento oncológico puede ser demandada por amparo ante cualquier juez bonaerense. El proceso es urgente: el juez puede ordenar la cobertura en días y, si la negativa se basa en un reglamento interno de la obra social contrario a la Constitución, puede declararlo inconstitucional en ese mismo proceso.', references: [], order: 1 },
        { id: 'cba-art-20-s3', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-20', articleNumber: '20', segmentType: 'INCISO', text: '3.- A través de la garantía de Habeas Data, que se regirá por el procedimiento que la ley determine, toda persona podrá conocer lo que conste de la misma en forma de registro, archivo o banco de datos de organismos públicos, o privados destinados a proveer informes, así como la finalidad a que se destine esa información, y a requerir su rectificación, actualización o cancelación. No podrá afectarse el secreto de las fuentes y el contenido de la información periodística. Ningún dato podrá registrarse con fines discriminatorios ni será proporcionado a terceros, salvo que tengan un interés legítimo. El uso de la informática no podrá vulnerar el honor, la intimidad personal y familiar y el pleno ejercicio de los derechos. Todas las garantías precedentes son operativas. En ausencia de reglamentación, los jueces resolverán sobre la procedencia de las acciones que se promuevan, en consideración a la naturaleza de los derechos que se pretendan tutelar.', plainExplanation: 'El habeas data permite a toda persona: (a) saber qué información existe sobre ella en bases de datos públicas o privadas; (b) conocer para qué se usa esa información; (c) corregirla si es incorrecta; (d) actualizarla si está desactualizada; (e) cancelarla si se registró ilegalmente o para fines discriminatorios. Las fuentes periodísticas están protegidas (no pueden ser reveladas). Los datos no pueden venderse a terceros sin interés legítimo. Las tres garantías (habeas corpus, amparo y habeas data) son directamente operativas: funcionan aunque no haya ley reglamentaria.', practicalExample: 'Una persona que figure como "deudor" en el Veraz (buró de crédito) por una deuda ya pagada puede interponer habeas data contra esa empresa para exigir la rectificación o cancelación del dato. Si la empresa se niega, el juez puede ordenarla coactivamente en un proceso breve y sin formalidades.', references: [], order: 2 },
      ], amendments: [] },
  { id: 'const-buenos-aires-art-21', lawId: 'const-buenos-aires', number: '21', title: '', text: `Podrá ser excarcelada o eximida de prisión, la persona que diere caución o fianza suficiente. La ley determinará las condiciones y efectos de la fianza, atendiendo a la naturaleza del delito, su gravedad, peligrosidad del agente y demás circunstancias, y la forma y oportunidad de acordar la libertad provisional.`, plainLanguageExplanation: 'La excarcelación mediante caución o fianza es un derecho del imputado, sujeto a las condiciones que fije la ley según la gravedad del delito y peligrosidad del agente.', practicalEffects: ['La libertad provisional no es automática: depende de la gravedad del delito y peligrosidad del acusado', 'El juez puede fijar caución dineraria o personal según las circunstancias del caso'], examples: ['Un imputado por robo simple puede solicitar la excarcelación ofreciendo como caución el inmueble familiar o una suma de dinero. El juez evalúa la gravedad del hecho y la peligrosidad del acusado antes de concederla o denegarla.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['excarcelación', 'fianza', 'libertad provisional', 'proceso penal'], order: 21, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-22', lawId: 'const-buenos-aires', number: '22', title: '', text: `Todo habitante de la Provincia, tiene el derecho de entrar y salir del país, de ir y venir, llevando consigo sus bienes, salvo el derecho de tercero.`, plainLanguageExplanation: 'Todo habitante tiene derecho a entrar y salir del país y moverse libremente dentro del territorio provincial, llevando consigo sus bienes.', practicalEffects: ['La libertad de circulación es un derecho fundamental que no puede ser restringido sin causa legal', 'Solo una orden judicial fundada puede limitar la salida del país o el libre tránsito'], examples: ['Una persona con deuda de alimentos puede tener prohibida la salida del país por orden judicial, que es la única vía constitucionalmente válida para limitar este derecho. Un decreto del gobernador que lo impidiera sería inconstitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de circulación', 'libre tránsito', 'salida del país', 'derechos'], order: 22, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-23', lawId: 'const-buenos-aires', number: '23', title: '', text: `La correspondencia epistolar es inviolable.`, plainLanguageExplanation: 'La correspondencia epistolar y las comunicaciones privadas son inviolables: ninguna autoridad puede interceptarlas sin orden judicial.', practicalEffects: ['Ninguna autoridad puede interceptar cartas o comunicaciones sin orden judicial', 'La violación de la correspondencia constituye delito y las pruebas obtenidas son nulas'], examples: ['Un empleado de correo que abre cartas de los clientes comete delito y las pruebas obtenidas son nulas. Tampoco la policía puede requisar el correo de una persona sin autorización judicial expresa.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['correspondencia', 'privacidad', 'inviolabilidad', 'comunicaciones'], order: 23, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-24', lawId: 'const-buenos-aires', number: '24', title: '', text: `El domicilio de una persona no podrá ser allanado sino por orden escrita de juez o de las autoridades municipales encargadas de vigilar la ejecución de los reglamentos de salubridad pública y a este solo objeto.`, plainLanguageExplanation: 'El domicilio de toda persona es inviolable: solo puede ser allanado mediante orden escrita de juez competente o autoridad municipal en materia de salubridad pública.', practicalEffects: ['Sin orden judicial, la entrada forzada a un domicilio es ilegal y las pruebas obtenidas son nulas', 'La orden de allanamiento debe indicar el domicilio específico y el objeto de la diligencia'], examples: ['Un agente de inspección municipal que ingresa a un local sin orden del juez ni orden del área de salubridad realiza un allanamiento inconstitucional. Todo lo que encuentre durante esa inspresión ilegal no puede usarse como prueba.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inviolabilidad del domicilio', 'allanamiento', 'orden judicial', 'domicilio'], order: 24, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-25', lawId: 'const-buenos-aires', number: '25', title: '', text: `Ningún habitante de la Provincia estará obligado a hacer lo que la ley no manda, ni será privado de hacer lo que ella no prohíbe.`, plainLanguageExplanation: 'Ninguna persona puede ser obligada a hacer lo que la ley no manda ni impedida de hacer lo que la ley no prohíbe: principio de legalidad y libertad.', practicalEffects: ['El Estado no puede imponer obligaciones ni prohibiciones fuera de lo que establece la ley', 'Toda orden o restricción que no tenga respaldo legal expreso es inválida'], examples: ['Un decreto municipal que ordena a los comerciantes abrir sus locales un día específico bajo amenaza de multa, sin ley que lo respalde, viola este artículo: nadie puede ser obligado a hacer lo que la ley no manda.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['principio de legalidad', 'libertad', 'ley', 'obligaciones'], order: 25, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-26', lawId: 'const-buenos-aires', number: '26', title: '', text: `Las acciones privadas de los hombres, que de ningún modo ofendan al orden público ni perjudiquen a un tercero, están reservadas a Dios y exentas de la autoridad de los magistrados.`, plainLanguageExplanation: 'Las acciones privadas que no dañen a terceros ni al orden público están fuera del alcance del Estado y son solo responsabilidad del individuo ante su conciencia.', practicalEffects: ['El Estado no puede perseguir conductas privadas que no perjudiquen a terceros ni al orden público', 'La moral pública no puede imponerse coercitivamente si no hay daño concreto a terceros'], examples: ['El Estado provincial no puede sancionar a una persona por consumir alcohol en su domicilio o por tener relaciones consensuales entre adultos: son acciones privadas que no afectan a terceros ni al orden público y quedan fuera del alcance estatal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acciones privadas', 'autonomía personal', 'principio de privacidad', 'libertad'], order: 26, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-27', lawId: 'const-buenos-aires', number: '27', title: '', text: `La libertad de trabajo, industria y comercio, es un derecho asegurado a todo habitante de la Provincia, siempre que no ofenda o perjudique a la moral o a la salubridad pública, ni sea contrario a las leyes del país o a los derechos de tercero.`, plainLanguageExplanation: 'La libertad de trabajar, comerciar e industriar está garantizada siempre que no afecte la moral, la salud pública ni los derechos de terceros.', practicalEffects: ['El Estado puede regular el comercio y la industria pero no prohibirlos arbitrariamente', 'Las restricciones deben fundarse en razones de moral, salud pública o derechos de terceros'], examples: ['Un emprendedor que instala una panadería artesanal en su domicilio ejerce su libertad de trabajo garantizada por este artículo. El municipio puede regularla (habilitación, higiene) pero no prohibirla arbitrariamente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de trabajo', 'comercio', 'industria', 'regulación estatal'], order: 27, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-28', lawId: 'const-buenos-aires', number: '28', title: '', text: `Los habitantes de la Provincia tienen el derecho a gozar de un ambiente sano y el deber de conservarlo y protegerlo en su provecho y en el de las generaciones futuras. La Provincia ejerce el dominio eminente sobre el ambiente y los recursos naturales de su territorio incluyendo el subsuelo y el espacio aéreo correspondiente, el mar territorial y su lecho, la plataforma continental y los recursos naturales de la zona económica exclusiva, con el fin de asegurar una gestión, ambientalmente adecuada. En materia ecológica deberá preservar, recuperar y conservar los recursos naturales, renovables y no renovables del territorio de la Provincia, planificar el aprovechamiento racional de los mismos; controlar el impacto ambiental de todas las actividades que perjudiquen al ecosistema; promover acciones que eviten la contaminación del aire, agua y suelo; prohibir el ingreso en el territorio de residuos tóxicos o radiactivos; y garantizar el derecho a solicitar y recibir la adecuada información y a participar en la defensa del ambiente, de los recursos naturales y culturales. Asimismo, asegurará políticas de conservación y recuperación de la calidad del agua, aire y suelo compatible con la exigencia de mantener su integridad física y su capacidad productiva, y el resguardo de áreas de importancia ecológica, de la flora y la fauna. Toda persona física o jurídica cuya acción u omisión pueda degradar el ambiente está obligada a tomar todas las precauciones para evitarlo.`, plainLanguageExplanation: 'Los habitantes tienen derecho a un ambiente sano y el deber de protegerlo. La Provincia ejerce dominio sobre sus recursos naturales y debe prevenir y controlar la contaminación.', practicalEffects: ['Toda persona puede exigir al Estado medidas de protección ambiental', 'Las empresas que contaminen son responsables por los daños ambientales que causen'], examples: ['Los vecinos de una localidad que sufren contaminación de un arroyo por el vuelco industrial de una empresa pueden iniciar una acción colectiva de amparo ambiental invocando este artículo, exigiendo al Estado que controle y al contaminador que repare el daño.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medio ambiente', 'recursos naturales', 'derecho ambiental', 'contaminación'], order: 28, segments: [
        { id: 'cba-art-28-s1', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-28', articleNumber: '28', segmentType: 'PARAGRAPH', text: 'Los habitantes de la Provincia tienen el derecho a gozar de un ambiente sano y el deber de conservarlo y protegerlo en su provecho y en el de las generaciones futuras. La Provincia ejerce el dominio eminente sobre el ambiente y los recursos naturales de su territorio incluyendo el subsuelo y el espacio aéreo correspondiente, el mar territorial y su lecho, la plataforma continental y los recursos naturales de la zona económica exclusiva, con el fin de asegurar una gestión, ambientalmente adecuada.', plainExplanation: 'El derecho al ambiente sano es recíproco: los habitantes tienen el derecho y también el deber de cuidarlo —incluso para quienes todavía no nacieron. La Provincia tiene dominio eminente (soberanía) sobre todos sus recursos naturales: el suelo, el subsuelo, el espacio aéreo, el mar territorial y la plataforma continental. Ese dominio le da el fundamento para regular, controlar y cobrar regalías por la explotación de esos recursos.', practicalExample: 'Una empresa que extrae petróleo en territorio bonaerense lo hace bajo el dominio eminente provincial: debe pagar regalías a la Provincia, cumplir la normativa ambiental y someterse a los controles de impacto ambiental que la Provincia establezca.', references: [], order: 0 },
        { id: 'cba-art-28-s2', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-28', articleNumber: '28', segmentType: 'PARAGRAPH', text: 'En materia ecológica deberá preservar, recuperar y conservar los recursos naturales, renovables y no renovables del territorio de la Provincia, planificar el aprovechamiento racional de los mismos; controlar el impacto ambiental de todas las actividades que perjudiquen al ecosistema; promover acciones que eviten la contaminación del aire, agua y suelo; prohibir el ingreso en el territorio de residuos tóxicos o radiactivos; y garantizar el derecho a solicitar y recibir la adecuada información y a participar en la defensa del ambiente, de los recursos naturales y culturales.', plainExplanation: 'El Estado provincial tiene obligaciones concretas: planificar el uso racional de recursos, hacer evaluaciones de impacto ambiental antes de aprobar proyectos, evitar la contaminación de aire, agua y suelo, y prohibir el ingreso de residuos tóxicos o radiactivos. Además, los ciudadanos tienen derecho a participar en las decisiones ambientales y a recibir información veraz sobre el estado del ambiente.', practicalExample: 'Antes de aprobar la instalación de una industria química en el partido de La Matanza, la Provincia debe realizar un estudio de impacto ambiental, informar a la comunidad sobre los riesgos y brindar un espacio de participación ciudadana —todo obligatorio por este artículo.', references: [], order: 1 },
        { id: 'cba-art-28-s3', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-28', articleNumber: '28', segmentType: 'PARAGRAPH', text: 'Toda persona física o jurídica cuya acción u omisión pueda degradar el ambiente está obligada a tomar todas las precauciones para evitarlo.', plainExplanation: 'Principio de precaución: no hace falta que el daño ocurra —basta con que sea posible— para que nazca la obligación de prevenirlo. Esto aplica tanto a empresas como a personas físicas. La omisión también genera responsabilidad: quien no toma medidas preventivas cuando debía hacerlo es responsable del daño resultante.', practicalExample: 'Un frigorífico que vierte sus efluentes en un arroyo sin tratamiento puede ser sancionado y obligado a indemnizar a los vecinos afectados, incluso si aún no hay un daño irreversible comprobado: la posibilidad de degradación ya genera la obligación de actuar y responsabilidad por omisión.', references: [], order: 2 },
      ], amendments: [] },
  { id: 'const-buenos-aires-art-29', lawId: 'const-buenos-aires', number: '29', title: '', text: `A ningún acusado se le obligará a prestar juramento, ni a declarar contra sí mismo en materia criminal, ni será encausado dos veces por un mismo delito.`, plainLanguageExplanation: 'Ningún acusado puede ser obligado a declarar contra sí mismo en causa criminal, prestar juramento en esa materia, ni ser juzgado dos veces por el mismo delito.', practicalEffects: ['El derecho a no autoincriminarse impide que una confesión obtenida bajo presión sea válida en juicio', 'El principio non bis in idem prohíbe perseguir a alguien dos veces por el mismo hecho'], examples: ['Una persona absuelta en un juicio penal por robo no puede ser nuevamente procesada por los mismos hechos aunque aparezcan nuevas pruebas. La absolución firme tiene efecto de cosa juzgada, protegida por el principio non bis in idem.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['non bis in idem', 'derecho a no autoincriminarse', 'garantías procesales', 'juicio criminal'], order: 29, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-30', lawId: 'const-buenos-aires', number: '30', title: '', text: `Las prisiones son hechas para seguridad y no para mortificación de los detenidos. Las penitenciarías serán reglamentadas de manera que constituyan centros de trabajo y moralización. Todo rigor innecesario hace responsable a las autoridades que lo ejerzan.`, plainLanguageExplanation: 'Las prisiones tienen por fin la seguridad, no el castigo ni la mortificación. Las penitenciarías deben ser centros de trabajo y rehabilitación moral.', practicalEffects: ['Los detenidos no pueden ser sometidos a tratos degradantes o torturas', 'Las condiciones inhumanas de detención generan responsabilidad de las autoridades a cargo'], examples: ['Detenidos que denuncian superpoblación carcelaria extrema, falta de agua potable o violencia sistemática pueden iniciar habeas corpus correctivo invocando este artículo: las prisiones son para seguridad, no para mortificación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['condiciones de detención', 'rehabilitación', 'tratos inhumanos', 'penitenciaría'], order: 30, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-31', lawId: 'const-buenos-aires', number: '31', title: '', text: `La propiedad es inviolable, y ningún habitante de la Provincia puede ser privado de ella, sino en virtud de sentencia fundada en ley. La expropiación por causa de utilidad pública, debe ser calificada por ley y previamente indemnizada.`, plainLanguageExplanation: 'La propiedad es inviolable: nadie puede ser privado de ella sin sentencia fundada en ley. La expropiación por utilidad pública requiere calificación legal e indemnización previa.', practicalEffects: ['El Estado no puede tomar propiedad privada sin pagar indemnización justa y previa', 'La calificación de utilidad pública debe hacerse por ley, no por decreto ejecutivo'], examples: ['La Provincia quiere construir una autopista que atraviesa un campo privado. Para hacerlo debe declarar la utilidad pública por ley, pagar al dueño el valor real del inmueble antes de tomar posesión, y solo entonces puede expropiarlo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['propiedad', 'inviolabilidad', 'expropiación', 'indemnización'], order: 31, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-32', lawId: 'const-buenos-aires', number: '32', title: '', text: `Se ratifican para siempre las leyes de libertad de vientres y las que prohíben el tráfico de esclavos, la confiscación de bienes, el tormento, las penas crueles, infamia trascendental, mayorazgos y vinculaciones de toda especie, debiendo ser enajenable toda propiedad.`, plainLanguageExplanation: 'Se ratifican las leyes de abolición de la esclavitud y se prohíben para siempre la confiscación de bienes, el tormento, las penas crueles y los mayorazgos.', practicalEffects: ['La abolición de la esclavitud y del tormento tienen rango constitucional y no pueden revertirse por ley ordinaria', 'La confiscación de bienes como pena está absolutamente prohibida'], examples: ['Un juez no puede ordenar que se confisquen todos los bienes de un condenado como parte de la pena: la confiscación general de bienes está constitucionalmente prohibida desde 1853 y ratificada por este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['abolición esclavitud', 'tormento', 'confiscación', 'penas crueles'], order: 32, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-33', lawId: 'const-buenos-aires', number: '33', title: '', text: `Ninguna persona será encarcelada por deudas en causa civil, salvo los casos de fraude o culpa especificados por ley.`, plainLanguageExplanation: 'Nadie puede ser encarcelado por deudas civiles, salvo en casos de fraude o culpa expresamente tipificados por ley.', practicalEffects: ['Una deuda de dinero no justifica la prisión del deudor', 'Solo el fraude doloso puede dar lugar a sanciones privativas de la libertad en materia civil'], examples: ['Si un deudor no paga su hipoteca, el banco puede ejecutar la garantía y quedarse con el inmueble, pero no puede pedir que el deudor vaya preso por la deuda. La prisión por deudas civiles está prohibida constitucionalmente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deudas', 'prisión por deudas', 'fraude civil', 'garantías procesales'], order: 33, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-34', lawId: 'const-buenos-aires', number: '34', title: '', text: `Los extranjeros gozarán en el territorio de la Provincia de todos los derechos civiles del ciudadano y de los demás que esta Constitución les acuerda.`, plainLanguageExplanation: 'Los extranjeros radicados en la Provincia gozan de todos los derechos civiles del ciudadano argentino y los que la Constitución les reconoce expresamente.', practicalEffects: ['Los extranjeros pueden trabajar, contratar, adquirir propiedades y acceder a la justicia en igualdad con los ciudadanos', 'Solo los derechos políticos como votar o ser elegido quedan reservados a los ciudadanos'], examples: ['Un ciudadano boliviano residente en La Matanza puede abrir una empresa, firmar contratos, adquirir inmuebles y acceder a la justicia exactamente igual que un argentino. Lo que no puede es votar en elecciones provinciales ni ser elegido diputado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extranjeros', 'derechos civiles', 'igualdad', 'ciudadanía'], order: 34, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-35', lawId: 'const-buenos-aires', number: '35', title: '', text: `La libertad de enseñar y aprender no podrá ser coartada por medidas preventivas.`, plainLanguageExplanation: 'La libertad de enseñar y aprender no puede ser restringida por medidas preventivas del Estado; solo pueden establecerse requisitos razonables de calidad educativa.', practicalEffects: ['El Estado no puede prohibir preventivamente la actividad educativa privada', 'Cualquier restricción educativa requiere ley previa y fundamento razonable'], examples: ['Una escuela religiosa privada puede abrir e impartir su propuesta educativa sin que la Provincia la clausure preventivamente. Solo puede ser intervenida si incumple requisitos educativos establecidos por ley, no por razones ideológicas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de enseñanza', 'educación', 'medidas preventivas', 'libertad de aprendizaje'], order: 35, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-36', lawId: 'const-buenos-aires', number: '36', title: '', text: `La Provincia promoverá la eliminación de los obstáculos económicos, sociales o de cualquier otra naturaleza, que afecten o impidan el ejercicio de los derechos y garantías constitucionales: A tal fin reconoce los siguientes derechos: 1.- De la Familia. La familia es el núcleo primario y fundamental de la sociedad. La Provincia establecerá políticas que procuren su fortalecimiento y protección moral y material. 2.- De la Niñez. Todo niño tiene derecho a la protección y formación integral, al cuidado preventivo y supletorio del Estado en situaciones de desamparo y a la asistencia tutelar y jurídica en todos los casos. 3.- De la Juventud. Los jóvenes tienen derecho al desarrollo de sus aptitudes y a la plena participación e inserción laboral, cultural y comunitaria. 4.- De la Mujer. Toda mujer tiene derecho a no ser discriminada por su sexo, a la igualdad de oportunidades, a una protección especial durante los estados de embarazo y lactancia, y las condiciones laborales deben permitir el cumplimiento de su esencial función familiar. La Provincia promoverá políticas de asistencia a la madre sola sostén de hogar. 5.- De la Discapacidad. Toda persona discapacitada tiene derecho a la protección integral del Estado. La Provincia garantizará la rehabilitación, educación y capacitación en establecimientos especiales; tendiendo a la equiparación promoverá su inserción de solidaridad sobre discapacitados. 6.- De la Tercera Edad. Todas las personas de la tercera edad tienen derecho a la protección integral por parte de su familia. La Provincia promoverá políticas asistenciales y de revalorización de su rol activo. 7.- A la Vivienda, la Provincia promoverá el acceso a la vivienda única y la constitución del asiento del hogar como bien de familia; garantizará el acceso a la propiedad de un lote de terreno apto para erigir su vivienda familiar única y de ocupación permanente, a familias radicadas o que se radiquen en el interior de la Provincia, en municipios de hasta 50.000 habitantes, sus localidades o pueblos. Una ley especial reglamentará las condiciones de ejercicio de la garantía consagrada en esta norma. 8.- A la Salud. La Provincia garantiza a todos sus habitantes el acceso a la salud en los aspectos preventivos, asistenciales y terapéuticos; sostiene el hospital público y gratuito en general, con funciones de asistencia sanitaria, investigación y formación; promueve la educación para la salud; la rehabilitación y la reinserción de las personas tóxico-dependientes. El medicamento por su condición de bien social integra el derecho a la salud; la Provincia a los fines de su seguridad, eficacia y disponibilidad asegura, en el ámbito de sus atribuciones, la participación de profesionales competentes en su proceso de producción y comercialización. 9.- De los Indígenas. La Provincia reivindica la existencia de los pueblos indígenas en su territorio, garantizando el respeto a sus identidades étnicas, el desarrollo de sus culturas y la posesión familiar y comunitaria de las tierras que legítimamente ocupan. 10.- De los Veteranos de Guerra. La Provincia adoptará políticas orientadas a la asistencia y protección de los veteranos de guerra facilitando el acceso a la salud, al trabajo y a una vivienda digna.`, plainLanguageExplanation: 'La Provincia reconoce y promueve derechos sociales integrales: familia, niñez, juventud, mujer, discapacidad, tercera edad, vivienda, salud, pueblos indígenas y veteranos de guerra.', practicalEffects: ['Estos derechos obligan al Estado a dictar políticas activas de protección para grupos vulnerables', 'Las personas en situación de vulnerabilidad tienen derecho a la protección especial del Estado'], examples: ['Una madre soltera con hijos menores que pierde su vivienda puede exigir al Estado provincial medidas de asistencia urgente invocando los incisos 1 (familia), 4 (mujer) y 7 (vivienda) de este artículo: son derechos constitucionales exigibles.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos sociales', 'familia', 'salud', 'vivienda', 'inclusión'], order: 36, segments: [
        { id: 'cba-art-36-s1', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-36', articleNumber: '36', segmentType: 'INCISO', text: '1.- De la Familia. La familia es el núcleo primario y fundamental de la sociedad. La Provincia establecerá políticas que procuren su fortalecimiento y protección moral y material.', plainExplanation: 'La familia —en todas sus formas, no solo la nuclear tradicional— es el núcleo básico de la sociedad. El Estado tiene la obligación de dictar políticas activas de protección: programas sociales, servicios de mediación familiar, apoyo a familias en situación de vulnerabilidad.', practicalExample: 'Los centros de asistencia a la familia y los programas de acompañamiento a madres y padres en situación de vulnerabilidad tienen base constitucional en este inciso.', references: [], order: 0 },
        { id: 'cba-art-36-s2', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-36', articleNumber: '36', segmentType: 'INCISO', text: '2.- De la Niñez. Todo niño tiene derecho a la protección y formación integral, al cuidado preventivo y supletorio del Estado en situaciones de desamparo y a la asistencia tutelar y jurídica en todos los casos.', plainExplanation: 'Los niños tienen derechos propios y el Estado tiene una obligación de protección reforzada. Cuando un niño está en situación de desamparo (abandono, violencia, pobreza extrema), el Estado no puede ignorarlo: debe actuar de manera preventiva y, si la familia no puede protegerlo, suplirla mediante el sistema de protección de la infancia.', practicalExample: 'Un niño víctima de violencia intrafamiliar puede ser alojado en un hogar del Estado o familia de acogida, con representante legal y apoyo psicológico garantizado por este inciso —sin necesidad de que nadie lo solicite si el Estado lo detecta.', references: [], order: 1 },
        { id: 'cba-art-36-s3', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-36', articleNumber: '36', segmentType: 'INCISO', text: '3.- De la Juventud. Los jóvenes tienen derecho al desarrollo de sus aptitudes y a la plena participación e inserción laboral, cultural y comunitaria.', plainExplanation: 'La Constitución reconoce a los jóvenes como sujetos activos de derechos, no solo como destinatarios de protección. El Estado debe crear condiciones reales para que puedan desarrollarse: empleo joven, formación profesional, espacios culturales y participación en decisiones que los afectan.', practicalExample: 'Los programas provinciales de primer empleo para jóvenes, las becas educativas y los centros culturales barriales para adolescentes tienen fundamento en este inciso constitucional.', references: [], order: 2 },
        { id: 'cba-art-36-s4', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-36', articleNumber: '36', segmentType: 'INCISO', text: '4.- De la Mujer. Toda mujer tiene derecho a no ser discriminada por su sexo, a la igualdad de oportunidades, a una protección especial durante los estados de embarazo y lactancia, y las condiciones laborales deben permitir el cumplimiento de su esencial función familiar. La Provincia promoverá políticas de asistencia a la madre sola sostén de hogar.', plainExplanation: 'Se reconocen tres capas de derechos para las mujeres: no discriminación por sexo, protección especial durante el embarazo y lactancia (licencias, condiciones de trabajo), y asistencia especial para las madres que sostienen solas el hogar. Este inciso da base constitucional a los programas de asistencia a madres solas y a las licencias por maternidad en el empleo público provincial.', practicalExample: 'Una empleada pública bonaerense embarazada tiene derecho a licencia de maternidad, no puede ser transferida a tareas perjudiciales para su salud y no puede ser despedida por su estado: son garantías con fundamento directo en este inciso.', references: [], order: 3 },
        { id: 'cba-art-36-s5', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-36', articleNumber: '36', segmentType: 'INCISO', text: '5.- De la Discapacidad. Toda persona discapacitada tiene derecho a la protección integral del Estado. La Provincia garantizará la rehabilitación, educación y capacitación en establecimientos especiales; tendiendo a la equiparación promoverá su inserción de solidaridad sobre discapacitados.', plainExplanation: 'Las personas con discapacidad tienen derecho a protección integral: no solo atención médica sino educación, formación y la posibilidad real de insertarse en la sociedad. El Estado debe asegurar establecimientos educativos especiales y promover la inclusión laboral a través de cupos y programas específicos.', practicalExample: 'Una persona con discapacidad motriz puede exigir al Estado provincial que garantice accesibilidad en los edificios públicos y transporte. La omisión del Estado puede ser reclamada por amparo con base en este inciso.', references: [], order: 4 },
        { id: 'cba-art-36-s6', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-36', articleNumber: '36', segmentType: 'INCISO', text: '6.- De la Tercera Edad. Todas las personas de la tercera edad tienen derecho a la protección integral por parte de su familia. La Provincia promoverá políticas asistenciales y de revalorización de su rol activo.', plainExplanation: 'Los adultos mayores tienen derechos específicos: protección por parte de su familia y del Estado, y reconocimiento de su rol activo en la sociedad (no son pasivos). La Provincia debe garantizar servicios de salud, residencias para quienes no tienen contención familiar y programas que reconozcan la experiencia y aportes de los adultos mayores.', practicalExample: 'Un adulto mayor en situación de abandono familiar puede ser asistido por el sistema provincial de atención gerontológica, que tiene obligación constitucional de brindar protección integral en esos casos.', references: [], order: 5 },
        { id: 'cba-art-36-s7', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-36', articleNumber: '36', segmentType: 'INCISO', text: '7.- A la Vivienda. La Provincia promoverá el acceso a la vivienda única y la constitución del asiento del hogar como bien de familia; garantizará el acceso a la propiedad de un lote de terreno apto para erigir su vivienda familiar única y de ocupación permanente, a familias radicadas o que se radiquen en el interior de la Provincia, en municipios de hasta 50.000 habitantes, sus localidades o pueblos.', plainExplanation: 'El derecho a la vivienda tiene dos dimensiones concretas: (1) el Estado debe facilitar el acceso a la vivienda propia y protegerla como bien de familia (inembargable para ciertos acreedores); (2) en municipios del interior de hasta 50.000 habitantes, el Estado garantiza el acceso a un lote de terreno para construir la vivienda familiar permanente. Esto es una garantía exigible, no una mera declaración.', practicalExample: 'Una familia que se radica en un municipio del interior bonaerense de 30.000 habitantes puede solicitar al Estado provincial un lote para construir su vivienda permanente: es un derecho constitucional, no un programa discrecional del gobierno de turno.', references: [], order: 6 },
        { id: 'cba-art-36-s8', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-36', articleNumber: '36', segmentType: 'INCISO', text: '8.- A la Salud. La Provincia garantiza a todos sus habitantes el acceso a la salud en los aspectos preventivos, asistenciales y terapéuticos; sostiene el hospital público y gratuito en general, con funciones de asistencia sanitaria, investigación y formación; promueve la educación para la salud; la rehabilitación y la reinserción de las personas tóxico-dependientes. El medicamento por su condición de bien social integra el derecho a la salud.', plainExplanation: 'La salud es un derecho integral que abarca prevención, asistencia y tratamiento. El hospital público y gratuito tiene rango constitucional: no puede eliminarse. Los medicamentos son bienes sociales, no mercancías: el Estado debe garantizar su disponibilidad y accesibilidad. Las personas con adicciones tienen derecho a rehabilitación y reinserción social, no solo a sanción penal.', practicalExample: 'Un paciente sin cobertura de salud que necesita una cirugía urgente tiene derecho constitucional a ser atendido gratuitamente en un hospital público bonaerense. Si el hospital lo rechaza por falta de fondos, puede solicitar amparo invocando este inciso.', references: [], order: 7 },
        { id: 'cba-art-36-s9', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-36', articleNumber: '36', segmentType: 'INCISO', text: '9.- De los Indígenas. La Provincia reivindica la existencia de los pueblos indígenas en su territorio, garantizando el respeto a sus identidades étnicas, el desarrollo de sus culturas y la posesión familiar y comunitaria de las tierras que legítimamente ocupan.', plainExplanation: 'Los pueblos indígenas que habitan la Provincia tienen derechos colectivos reconocidos constitucionalmente: identidad cultural, desarrollo de sus costumbres y, fundamentalmente, derecho a la posesión de sus tierras ancestrales. Este reconocimiento es anterior a la tenencia registral: la posesión legítima y comunitaria tiene protección constitucional aunque no esté inscripta en el registro de la propiedad.', practicalExample: 'Una comunidad qom que posee ancestralmente tierras en el norte bonaerense puede oponerse judicialmente a un desalojo por parte de un particular que tiene título registral, invocando su posesión comunitaria reconocida por este inciso.', references: [], order: 8 },
        { id: 'cba-art-36-s10', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-36', articleNumber: '36', segmentType: 'INCISO', text: '10.- De los Veteranos de Guerra. La Provincia adoptará políticas orientadas a la asistencia y protección de los veteranos de guerra facilitando el acceso a la salud, al trabajo y a una vivienda digna.', plainExplanation: 'Los veteranos de las guerras en que participó Argentina —especialmente Malvinas— tienen reconocimiento constitucional específico. El Estado provincial debe actuar positivamente: crear políticas de salud, empleo preferencial y acceso a vivienda digna para este grupo. No es una gracia del gobierno de turno: es una obligación constitucional.', practicalExample: 'Un veterano de Malvinas que reside en la Provincia puede exigir acceso prioritario al sistema de salud provincial y a los programas de vivienda, con base en este inciso que crea una obligación concreta a cargo del Estado.', references: [], order: 9 },
      ], amendments: [] },
  { id: 'const-buenos-aires-art-37', lawId: 'const-buenos-aires', number: '37', title: '', text: `Todos los habitantes de la Provincia gozan del derecho a recibir, a través de políticas efectivas de acción social y salud, las utilidades producidas por los juegos de azar, debidamente creados y reglamentados por ley. La Provincia se reserva, como derecho no delegado al Estado Federal, la administración y explotación de todos los casinos y salas de juegos relativas a los mismos, existentes o a crearse; en tal sentido esta Constitución no admite la privatización o concesión de la banca estatal a través de ninguna forma jurídica. La ley que reglamente lo anteriormente consagrado podrá permitir la participación del capital privado en emprendimientos de desarrollo turístico, en tanto no implique la modificación del apartado anterior.`, plainLanguageExplanation: 'Las ganancias de los juegos de azar se destinan a políticas sociales y de salud. La Provincia mantiene el monopolio exclusivo de los casinos, que no pueden ser privatizados.', practicalEffects: ['Las ganancias de los juegos de azar no pueden ser apropiadas por privados: deben destinarse a salud y acción social', 'La Constitución prohíbe expresamente privatizar los casinos o conceder la banca estatal'], examples: ['Si una empresa privada intentara instalar un casino en Mar del Plata, el Estado bonaerense puede impedirlo: la Constitución prohíbe expresamente privatizar la explotación de casinos. Las ganancias del IOMA y la lotería provincial tienen mandato constitucional de destinarse a salud y acción social.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juegos de azar', 'casinos', 'monopolio provincial', 'acción social'], order: 37, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-38', lawId: 'const-buenos-aires', number: '38', title: '', text: `Los consumidores y usuarios tienen derecho, en la relación de consumo, a la protección frente a los riesgos para la salud y su seguridad, a la promoción y defensa de sus intereses económicos y a una información adecuada y veraz. La Provincia proveerá a la educación para el consumo, al establecimiento de procedimientos eficaces para la prevención y resolución de conflictos y promoverá la constitución de asociaciones de usuarios y consumidores.`, plainLanguageExplanation: 'Los consumidores y usuarios tienen derecho a protección frente a riesgos para su salud, a información veraz y a mecanismos de resolución de conflictos con proveedores.', practicalEffects: ['Las empresas tienen obligación de informar verazmente sobre sus productos y servicios', 'Los consumidores pueden organizarse en asociaciones para defender sus intereses colectivos'], examples: ['Una empresa de telefonía que cambia las condiciones del servicio sin informarlas claramente viola este artículo. El consumidor puede presentar denuncia ante el OMIC municipal y exigir la restitución al plan original, con base constitucional en el derecho a información veraz.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['consumidores', 'usuarios', 'información veraz', 'defensa del consumidor'], order: 38, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-39', lawId: 'const-buenos-aires', number: '39', title: '', text: `El trabajo es un derecho y un deber social. 1.- En especial se establece: derecho al trabajo, a una retribución justa, a condiciones dignas de trabajo, al bienestar, a la jornada limitada, al descanso semanal, a igual remuneración por igual tarea y al salario mínimo, vital y móvil. A tal fin, la Provincia deberá: fiscalizar el cumplimiento de las obligaciones del empleador y ejercer en forma indelegable el poder de policía en materia laboral; propiciar el pleno empleo, estimulando la creación de nuevas fuentes de trabajo; promover la capacitación y formación de los trabajadores; impulsar la colaboración entre empresarios y trabajadores, y la solución de los conflictos mediante la conciliación, y establecer tribunales especializados para solucionar los conflictos de trabajo. 2.- La Provincia reconoce los derechos de asociación y libertad sindical, los convenios colectivos, el derecho de huelga y las garantías al fuero sindical de los representantes gremiales. 3.- En materia laboral y de seguridad social regirán los principios de irrenunciabilidad, justicia social, gratuidad de las actuaciones en beneficio del trabajador, primacía de la realidad, indemnidad, progresividad y, en caso de duda, interpretación a favor del trabajador. 4.- Sin perjuicio de lo establecido en el artículo 103 inciso 12 de esta Constitución, la Provincia garantiza a los trabajadores estatales el derecho de negociación de sus condiciones de trabajo y la sustanciación de los conflictos colectivos entre el Estado Provincial y aquellos a través de un organismo imparcial que determine la ley. Todo acto o contrato que contravenga las garantías reconocidas en el presente inciso será nulo.`, plainLanguageExplanation: 'El trabajo es un derecho y deber social. Se garantizan salario justo, condiciones dignas, jornada limitada, igual remuneración, libertad sindical, derecho de huelga y principios protectorios a favor del trabajador.', practicalEffects: ['En caso de duda sobre una norma laboral, siempre debe interpretarse a favor del trabajador', 'Los convenios colectivos negociados por sindicatos son vinculantes para todos los trabajadores del sector'], examples: ['Un empleado que gana menos que una colega mujer por la misma tarea puede reclamar judicialmente igualdad salarial: el principio "igual remuneración por igual tarea" del inc. 1 de este artículo se aplica directamente como derecho exigible.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos laborales', 'salario mínimo', 'huelga', 'libertad sindical'], order: 39, segments: [
        { id: 'cba-art-39-s1', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-39', articleNumber: '39', segmentType: 'INCISO', text: '1.- En especial se establece: derecho al trabajo, a una retribución justa, a condiciones dignas de trabajo, al bienestar, a la jornada limitada, al descanso semanal, a igual remuneración por igual tarea y al salario mínimo, vital y móvil. A tal fin, la Provincia deberá: fiscalizar el cumplimiento de las obligaciones del empleador y ejercer en forma indelegable el poder de policía en materia laboral; propiciar el pleno empleo, estimulando la creación de nuevas fuentes de trabajo; promover la capacitación y formación de los trabajadores; impulsar la colaboración entre empresarios y trabajadores, y la solución de los conflictos mediante la conciliación, y establecer tribunales especializados para solucionar los conflictos de trabajo.', plainExplanation: 'El trabajo es a la vez un derecho (toda persona tiene derecho a obtenerlo) y una fuente de derechos concretos: retribución justa, condiciones dignas, jornada limitada, descanso, igual salario sin discriminación de género, y salario mínimo. El Estado provincial tiene obligaciones activas: controlar a los empleadores, crear empleo, capacitar trabajadores, facilitar la conciliación y sostener la justicia laboral especializada.', practicalExample: 'Un trabajador al que le pagan $500.000 mensuales cuando el salario mínimo vital y móvil nacional es de $800.000 puede reclamar ante el Ministerio de Trabajo bonaerense la diferencia: la Provincia tiene obligación constitucional de fiscalizar el cumplimiento del salario mínimo.', references: [], order: 0 },
        { id: 'cba-art-39-s2', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-39', articleNumber: '39', segmentType: 'INCISO', text: '2.- La Provincia reconoce los derechos de asociación y libertad sindical, los convenios colectivos, el derecho de huelga y las garantías al fuero sindical de los representantes gremiales.', plainExplanation: 'Los trabajadores tienen constitucionalmente reconocidos cuatro derechos colectivos: (1) libertad sindical (afiliarse o no, crear sindicatos), (2) negociación colectiva (los convenios colectivos son vinculantes para todo el sector), (3) derecho de huelga (parar el trabajo para presionar en conflictos laborales), y (4) fuero sindical para los delegados (no pueden ser despedidos por su actividad gremial sin autorización judicial previa).', practicalExample: 'Un delegado gremial de una empresa bonaerense que es despedido por organizar una huelga puede solicitar la reinstalación inmediata vía medida cautelar, ya que el fuero sindical le impide ser removido sin autorización del juez laboral: es una garantía constitucional, no solo legal.', references: [], order: 1 },
        { id: 'cba-art-39-s3', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-39', articleNumber: '39', segmentType: 'INCISO', text: '3.- En materia laboral y de seguridad social regirán los principios de irrenunciabilidad, justicia social, gratuidad de las actuaciones en beneficio del trabajador, primacía de la realidad, indemnidad, progresividad y, en caso de duda, interpretación a favor del trabajador.', plainExplanation: 'Siete principios de aplicación obligatoria: (1) irrenunciabilidad (el trabajador no puede renunciar a derechos aunque firme que lo hace); (2) justicia social (el resultado debe ser socialmente justo); (3) gratuidad del proceso laboral para el trabajador; (4) primacía de la realidad (lo que sucede en los hechos prevalece sobre los papeles: si alguien trabaja en relación de dependencia aunque le hagan facturar como monotributista, es empleado); (5) indemnidad (no puede sufrir represalias por ejercer derechos); (6) progresividad (los derechos laborales no pueden retroceder); y (7) in dubio pro operario (en caso de duda, se interpreta a favor del trabajador).', practicalExample: 'Una empresa que contrata "pasantes" para tareas habituales de producción durante 3 años, haciéndoles firmar contratos de pasantía, no puede oponer esos documentos: la primacía de la realidad muestra una relación laboral real, y el trabajador tiene derecho a todos los beneficios del empleado en relación de dependencia.', references: [], order: 2 },
        { id: 'cba-art-39-s4', lawId: 'const-buenos-aires', articleId: 'const-buenos-aires-art-39', articleNumber: '39', segmentType: 'INCISO', text: '4.- Sin perjuicio de lo establecido en el artículo 103 inciso 12 de esta Constitución, la Provincia garantiza a los trabajadores estatales el derecho de negociación de sus condiciones de trabajo y la sustanciación de los conflictos colectivos entre el Estado Provincial y aquellos a través de un organismo imparcial que determine la ley. Todo acto o contrato que contravenga las garantías reconocidas en el presente inciso será nulo.', plainExplanation: 'Los empleados públicos bonaerenses también tienen derecho a negociar colectivamente sus condiciones de trabajo con el Estado como empleador. Los conflictos entre el Estado Provincial y sus empleados deben resolverse ante un organismo imparcial previsto por ley. Cualquier cláusula contractual o acto que vulnere estas garantías es automáticamente nulo —el empleado público no puede renunciar a estos derechos aunque lo haga por escrito.', practicalExample: 'El gobierno provincial no puede unilateralmente bajar el sueldo o cambiar las condiciones de trabajo de los empleados públicos sin pasar por la instancia de negociación colectiva prevista en este inciso: hacerlo es inconstitucional y los actos que lo consagren son nulos.', references: [], order: 3 },
      ], amendments: [] },
  { id: 'const-buenos-aires-art-40', lawId: 'const-buenos-aires', number: '40', title: '', text: `La Provincia ampara los regímenes de seguridad social emergentes de la relación de empleo público provincial. El sistema de seguridad social para los agentes públicos estará a cargo de entidades con autonomía económica y financiera administradas por la Provincia con participación en las mismas de representantes de los afiliados conforme lo establezca la ley. La Provincia reconoce la existencia de cajas y sistemas de seguridad social de profesionales.`, plainLanguageExplanation: 'La Provincia protege la seguridad social de sus empleados públicos a través de entidades con autonomía económica y financiera en las que participan representantes de los afiliados.', practicalEffects: ['Las cajas previsionales de empleados públicos tienen autonomía y no pueden ser intervenidas arbitrariamente', 'Los afiliados tienen representantes en la conducción de las entidades de seguridad social'], examples: ['Los empleados del Estado bonaerense aportan al IOMA (salud) y al IOMA de jubilaciones, que son entidades con autonomía financiera. El gobierno no puede, por decreto, unificarlas con el sistema nacional sin ley y sin respetar esta autonomía constitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['seguridad social', 'empleo público', 'cajas previsionales', 'autonomía financiera'], order: 40, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-41', lawId: 'const-buenos-aires', number: '41', title: '', text: `La Provincia reconoce a las entidades intermedias expresivas de las actividades culturales, gremiales, sociales y económicas y garantiza el derecho a la constitución y desenvolvimiento de colegios o consejos profesionales. Asimismo fomenta la organización y desarrollo de cooperativas y mutuales, otorgándoles un tratamiento tributario y financiamiento acorde con su naturaleza.`, plainLanguageExplanation: 'La Provincia reconoce a los gremios, colegios profesionales, cooperativas y mutuales como entidades intermedias de la sociedad, fomentándolas con beneficios tributarios y financieros.', practicalEffects: ['Los colegios profesionales tienen respaldo constitucional y pueden regular el ejercicio de las profesiones', 'Las cooperativas y mutuales reciben un trato fiscal diferenciado por su naturaleza social'], examples: ['El Colegio de Abogados de San Isidro tiene respaldo constitucional para matricular abogados y suspender a quienes cometan faltas éticas. Sus resoluciones son revisables judicialmente pero no pueden ser ignoradas por quien quiera ejercer la profesión.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['colegios profesionales', 'cooperativas', 'mutuales', 'entidades intermedias'], order: 41, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-42', lawId: 'const-buenos-aires', number: '42', title: '', text: `Las universidades y facultades científicas erigidas legalmente, expedirán los títulos y grados de su competencia, sin más condición que la de exigir exámenes suficientes en el tiempo en que el candidato lo solicite, de acuerdo con los reglamentos de las facultades respectivas quedando a la Legislatura la facultad de determinar lo concerniente al ejercicio de las profesiones liberales.`, plainLanguageExplanation: 'Las universidades habilitadas por ley expiden títulos y grados a quienes aprueben los exámenes requeridos. La Legislatura provincial regula el ejercicio de las profesiones liberales.', practicalEffects: ['Las universidades habilitadas pueden otorgar títulos que habilitan para ejercer profesiones reguladas', 'El Poder Legislativo fija las condiciones para el ejercicio de profesiones como medicina, abogacía o ingeniería'], examples: ['Un egresado de la UNLP con título de médico puede ejercer la medicina en la Provincia sin más trámite que la inscripción en el colegio profesional. Nadie puede exigirle exámenes adicionales más allá de los que superó en la facultad.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['títulos universitarios', 'profesiones liberales', 'universidades', 'habilitación profesional'], order: 42, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-43', lawId: 'const-buenos-aires', number: '43', title: '', text: `La Provincia fomenta la investigación científica y tecnológica, la transferencia de sus resultados a los habitantes cuando se efectúe con recursos del Estado y la difusión de los conocimientos y datos culturales mediante la implementación de sistemas adecuados de información, a fin de lograr un sostenido desarrollo económico y social que atienda a una mejor calidad de vida de la población.`, plainLanguageExplanation: 'La Provincia fomenta la investigación científica y tecnológica y ordena que sus resultados sean transferidos a la sociedad cuando se financien con recursos públicos.', practicalEffects: ['Los resultados de investigaciones financiadas con fondos públicos deben beneficiar a la comunidad', 'La difusión del conocimiento científico es una obligación del Estado provincial'], examples: ['Una investigación sobre agua subterránea financiada por el CONICET con fondos provinciales debe tener sus resultados disponibles para el público bonaerense: la Constitución ordena que el conocimiento generado con dinero público se transfiera a la sociedad.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['investigación científica', 'tecnología', 'desarrollo', 'calidad de vida'], order: 43, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-44', lawId: 'const-buenos-aires', number: '44', title: '', text: `La Provincia preserva, enriquece y difunde su patrimonio cultural, histórico, arquitectónico, arqueológico y urbanístico, y protege sus instituciones. La Provincia desarrollará políticas orientadas a rescatar, investigar y difundir las manifestaciones culturales, individuales o colectivas, y las realizaciones del pueblo que afirmen su identidad regional, provincial y nacional, generando ámbitos de participación comunitaria.`, plainLanguageExplanation: 'La Provincia protege y difunde su patrimonio cultural, histórico, arquitectónico y arqueológico, y promueve las manifestaciones culturales que afirman la identidad regional y provincial.', practicalEffects: ['El patrimonio histórico y arqueológico es de dominio público y no puede ser destruido ni privatizado', 'El Estado debe financiar políticas para rescatar y difundir la cultura popular y las tradiciones regionales'], examples: ['Un constructor que demoliera un edificio histórico declarado patrimonio cultural sin autorización cometería una infracción grave. La Provincia tiene obligación constitucional de preservar ese patrimonio y puede exigir la restauración a cargo del responsable.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['patrimonio cultural', 'identidad regional', 'arqueología', 'protección cultural'], order: 44, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-45', lawId: 'const-buenos-aires', number: '45', title: '', text: `Los poderes públicos no podrán delegar las facultades que les han sido conferidas por esta Constitución, ni atribuir al Poder Ejecutivo otras que las que expresamente le están acordadas por ella.`, plainLanguageExplanation: 'Los poderes públicos no pueden delegar las facultades constitucionales que les fueron conferidas ni atribuir al Poder Ejecutivo atribuciones que la Constitución no le concede.', practicalEffects: ['La Legislatura no puede traspasar al Ejecutivo su facultad de dictar leyes (delegación legislativa prohibida)', 'Todo acto que implique delegación de facultades constitucionales es inconstitucional'], examples: ['Si la Legislatura aprueba una ley que dice "el gobernador fijará las alícuotas del impuesto inmobiliario", esa delegación es inconstitucional: la potestad tributaria es legislativa y no puede transferirse al Ejecutivo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['indelegabilidad', 'separación de poderes', 'facultades constitucionales', 'Poder Ejecutivo'], order: 45, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-46', lawId: 'const-buenos-aires', number: '46', title: '', text: `No podrá acordarse remuneración extraordinaria a ninguno de los miembros de los poderes públicos y ministros secretarios, por servicios hechos o que se les encargaren en el ejercicio de sus funciones, o por comisiones especiales o extraordinarias.`, plainLanguageExplanation: 'Ningún miembro de los poderes públicos ni ministro puede recibir remuneración extraordinaria por servicios prestados en el ejercicio de sus funciones o por comisiones especiales.', practicalEffects: ['Los funcionarios solo pueden cobrar el sueldo que fija la ley, sin extras por comisiones adicionales', 'Esta prohibición previene el enriquecimiento indebido a través de honorarios por tareas ya remuneradas'], examples: ['Un diputado provincial que integra una comisión especial de investigación no puede cobrar honorarios adicionales por esa tarea: ya cobra su dieta parlamentaria y este artículo prohíbe toda remuneración extraordinaria sobre las funciones regulares.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneración', 'funcionarios públicos', 'prohibición', 'ética pública'], order: 46, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-47', lawId: 'const-buenos-aires', number: '47', title: '', text: `No podrá autorizarse empréstito alguno sobre el crédito general de la Provincia, ni emisión de fondos públicos, sino por ley sancionada por dos tercios de votos de los miembros presentes de cada Cámara.`, plainLanguageExplanation: 'Todo empréstito o emisión de fondos públicos debe ser autorizado por ley aprobada con dos tercios de los votos de los miembros presentes de cada Cámara legislativa.', practicalEffects: ['El endeudamiento provincial requiere mayoría calificada para garantizar el consenso legislativo', 'El Estado provincial no puede endeudarse por decisión del Ejecutivo solo, sin ley parlamentaria'], examples: ['Si el gobernador quisiera tomar un préstamo internacional de 500 millones de dólares para financiar obras públicas, necesita que ambas cámaras de la Legislatura lo autoricen por dos tercios de los votos de los miembros presentes. No puede hacerlo por decreto.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['empréstito', 'deuda pública', 'dos tercios', 'fondos públicos'], order: 47, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-48', lawId: 'const-buenos-aires', number: '48', title: '', text: `Toda ley que sancione empréstito deberá especificar los recursos especiales con que deba hacerse el servicio de la deuda y su amortización.`, plainLanguageExplanation: 'Toda ley que autorice un empréstito debe especificar los recursos con que se pagarán la deuda y su amortización; el endeudamiento sin plan de repago está prohibido.', practicalEffects: ['El empréstito no puede votarse sin indicar cómo se va a pagar', 'Esta norma protege la sustentabilidad fiscal de la Provincia evitando deuda sin respaldo'], examples: ['La ley que autorice un préstamo del BID para construir cloacas debe especificar: "se pagarán con la recaudación del impuesto inmobiliario urbano, en cuotas de X durante 20 años". Sin ese detalle, la ley no puede sancionarse.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['empréstito', 'amortización', 'recursos', 'sustentabilidad fiscal'], order: 48, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-49', lawId: 'const-buenos-aires', number: '49', title: '', text: `No podrán aplicarse los recursos que se obtengan por empréstito sino a los objetos determinados, que debe especificar la ley que lo autorice, bajo responsabilidad de la autoridad que los invierta o destine a otros objetos.`, plainLanguageExplanation: 'Los fondos obtenidos por empréstito solo pueden aplicarse a los objetos específicamente determinados en la ley que lo autorizó; los funcionarios que los desvíen son responsables.', practicalEffects: ['No puede desviarse dinero de un préstamo para un fin distinto al indicado en la ley', 'Los funcionarios que desvíen fondos de empréstitos incurren en responsabilidad personal'], examples: ['Si la Provincia toma un préstamo autorizado por ley para construir hospitales y el ministro de hacienda desvía esos fondos para pagar sueldos atrasados, incurre en responsabilidad personal. El desvío es inconstitucional aunque no haya ley penal específica.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fondos de empréstito', 'afectación específica', 'responsabilidad fiscal', 'deuda'], order: 49, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-50', lawId: 'const-buenos-aires', number: '50', title: '', text: `La Legislatura no podrá disponer de suma alguna del capital del Banco de la Provincia.`, plainLanguageExplanation: 'La Legislatura no puede disponer de ninguna suma del capital del Banco de la Provincia, cuya integridad patrimonial tiene protección constitucional.', practicalEffects: ['El capital del Banco de la Provincia está protegido de la disposición legislativa discrecional', 'Esta norma garantiza la solidez patrimonial del Banco Provincia frente al uso político de sus fondos'], examples: ['La Legislatura bonaerense no puede votar una ley ordenando al Banco Provincia transferir su capital al Fisco para cubrir el déficit: el capital del banco tiene protección constitucional y es inaccesible para el uso político discrecional del poder legislativo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Banco Provincia', 'capital bancario', 'protección constitucional', 'legislatura'], order: 50, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-51', lawId: 'const-buenos-aires', number: '51', title: '', text: `Ningún impuesto establecido o aumentado para sufragar la construcción de obras especiales, podrá ser aplicado interina o definitivamente a objetos distintos de los determinados en la ley de su creación, ni durará por más tiempo que el que se emplee en redimir la deuda que se contraiga.`, plainLanguageExplanation: 'Los impuestos creados para financiar obras especiales no pueden redirigirse a otros objetos ni prolongarse más allá del tiempo necesario para saldar la deuda de la obra.', practicalEffects: ['Un impuesto creado para financiar una obra pública debe extinguirse cuando la deuda se cancela', 'Redirigir esos fondos a otro fin requeriría una nueva ley y sería inconstitucional'], examples: ['Si la Provincia creó un impuesto en 2010 para construir un gasoducto y lo terminó en 2015, ese impuesto debe eliminarse: ya no existe la deuda que justificaba su cobro. Extenderlo para otros fines sería inconstitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['impuestos afectados', 'obras públicas', 'afectación tributaria', 'temporalidad'], order: 51, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-52', lawId: 'const-buenos-aires', number: '52', title: '', text: `Los empleados públicos a cuya elección o nombramiento no provea esta Constitución, serán nombrados por el Poder Ejecutivo.`, plainLanguageExplanation: 'Los empleados públicos cuya designación no está prevista en la Constitución son nombrados por el Poder Ejecutivo provincial como atribución residual.', practicalEffects: ['El Ejecutivo tiene la facultad residual de nombrar al personal de la administración provincial', 'Esta potestad permite al Ejecutivo dotar de personal a los organismos que lo requieran'], examples: ['El director de un hospital público bonaerense es designado por el Ejecutivo mediante decreto, ya que la Constitución no prevé otro mecanismo para ese cargo. El gobernador también puede removerlo en ejercicio de esa misma atribución residual.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['empleados públicos', 'nombramiento', 'Poder Ejecutivo', 'administración'], order: 52, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-53', lawId: 'const-buenos-aires', number: '53', title: '', text: `No podrá acumularse dos o más empleos a sueldo en una misma persona, aunque sea el uno provincial y el otro nacional, con excepción de los del magisterio en ejercicio. En cuanto a los empleos gratuitos y comisiones eventuales, la ley determinará los que sean incompatibles.`, plainLanguageExplanation: 'Ninguna persona puede acumular dos o más empleos remunerados del Estado. La única excepción son los docentes en ejercicio. La ley regula las incompatibilidades en empleos gratuitos.', practicalEffects: ['La prohibición de acumular cargos evita la concentración del gasto público en pocas personas', 'Los docentes en ejercicio son la única excepción constitucional a la regla de incompatibilidad'], examples: ['Un médico del hospital provincial no puede ser también empleado de una entidad nacional de salud percibiendo dos sueldos estatales. La única excepción es si es docente en ejercicio: puede combinar su cargo hospitalario con la docencia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incompatibilidad', 'acumulación de cargos', 'empleos públicos', 'excepción docentes'], order: 53, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-54', lawId: 'const-buenos-aires', number: '54', title: '', text: `Todo funcionario y empleado de la Provincia, cuya residencia no esté regida por esta Constitución, deberá tener su domicilio real en el partido donde ejerza sus funciones. La ley determinará las penas que deban aplicarse a los infractores y los casos en que pueda acordarse, licencias temporales.`, plainLanguageExplanation: 'Todo funcionario o empleado provincial debe tener su domicilio real en el partido donde ejerce sus funciones, salvo las excepciones que prevea la ley mediante licencias temporales.', practicalEffects: ['El requisito de domicilio garantiza que el funcionario esté presente y disponible en su área de actuación', 'El incumplimiento está sancionado por ley y puede dar lugar a medidas disciplinarias'], examples: ['Un juez de primera instancia de San Nicolás que vive en Buenos Aires y viaja todos los días viola este artículo: debe fijar su domicilio real en el partido donde ejerce sus funciones.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['domicilio', 'funcionarios', 'residencia', 'jurisdicción'], order: 54, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-55', lawId: 'const-buenos-aires', number: '55', title: '', text: `El Defensor del Pueblo tiene a su cargo la defensa de los derechos individuales y colectivos de los habitantes. Ejerce su misión frente a los hechos u omisiones de la administración pública, fuerzas de seguridad, entes descentralizados o empresas del Estado que impliquen el ejercicio ilegítimo, defectuoso, irregular, abusivo, arbitrario o negligente de sus funciones. Supervisa la eficacia de los servicios públicos que tenga a su cargo la Provincia o sus empresas concesionarias. Tendrá plena autonomía funcional y política. Durará cinco años en el cargo pudiendo ser designado por un segundo período. Será nombrado y removido por la Legislatura con el voto de las dos terceras partes de los miembros de cada Cámara. Una ley especial regulará su organización y funcionamiento.`, plainLanguageExplanation: 'El Defensor del Pueblo defiende los derechos individuales y colectivos frente a actos u omisiones de la administración pública y supervisa los servicios públicos con plena autonomía funcional.', practicalEffects: ['Cualquier ciudadano puede recurrir al Defensor del Pueblo ante abusos de la administración sin costo', 'El Defensor puede iniciar investigaciones y formular recomendaciones sin necesidad de mandato judicial'], examples: ['Un ciudadano que no recibe respuesta de la Provincia a su solicitud de habilitación laboral por más de seis meses puede recurrir gratuitamente al Defensor del Pueblo bonaerense, que tiene autonomía para investigar la demora e intimar al organismo responsable.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Defensor del Pueblo', 'ombudsman', 'derechos ciudadanos', 'administración pública'], order: 55, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-56', lawId: 'const-buenos-aires', number: '56', title: '', text: `Las declaraciones, derechos y garantías enumerados en esta Constitución, no serán interpretados como negación o mengua de otros derechos y garantías no enumerados o virtualmente retenidos por el pueblo, que nacen del principio de la soberanía popular y que corresponden al hombre en su calidad de tal.`, plainLanguageExplanation: 'La enumeración de derechos en la Constitución no excluye otros derechos no enumerados que corresponden a las personas por su dignidad humana o por el principio de soberanía popular.', practicalEffects: ['Los jueces pueden reconocer derechos que no figuran expresamente en la Constitución si surgen de la dignidad humana', 'Esta cláusula protege frente a interpretaciones restrictivas que solo admiten derechos enumerados'], examples: ['El derecho a la identidad de género no está expresamente mencionado en la Constitución de 1994, pero los jueces pueden reconocerlo invocando este artículo: los derechos nacidos de la dignidad humana no necesitan estar enumerados para ser exigibles.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos no enumerados', 'soberanía popular', 'dignidad humana', 'cláusula residual'], order: 56, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-57', lawId: 'const-buenos-aires', number: '57', title: '', text: `Toda ley, decreto u orden contrarios a los artículos precedentes o que impongan al ejercicio de las libertades y derechos reconocidos en ellos, otras restricciones que las que los mismos artículos permiten, o priven a los ciudadanos de las garantías que aseguran, serán inconstitucionales y no podrán ser aplicados por los jueces. Los individuos que sufran los efectos de toda orden que viole o menoscabe estos derechos, libertades y garantías, tienen acción civil para pedir las indemnizaciones por los perjuicios que tal violación o menoscabo les cause, contra el empleado o funcionario que la haya autorizado o ejecutado.`, plainLanguageExplanation: 'Toda ley, decreto u orden contrarios a los derechos y garantías constitucionales es inconstitucional y no puede aplicarse. Los afectados tienen acción civil contra los funcionarios responsables.', practicalEffects: ['Los jueces deben declarar inconstitucional cualquier norma que viole los derechos constitucionales', 'Los ciudadanos perjudicados por actos inconstitucionales pueden demandar civilmente a los funcionarios responsables'], examples: ['Un policía que detiene ilegalmente a una persona puede ser demandado civilmente en forma personal —además del Estado— por los daños ocasionados. Este artículo habilita la acción directa contra el funcionario que ejecutó la orden inconstitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inconstitucionalidad', 'acción civil', 'derechos', 'responsabilidad del Estado'], order: 57, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-58', lawId: 'const-buenos-aires', number: '58', title: '', text: `La representación política tiene por base la población y con arreglo a ella se ejercerá el derecho electoral.`, plainLanguageExplanation: 'La representación política tiene como base la población: a mayor número de habitantes, mayor representación en los cuerpos colegiados provinciales.', practicalEffects: ['Los distritos con más habitantes tienen más representantes en la Legislatura provincial', 'Este principio garantiza que el voto de todos los ciudadanos tenga el mismo peso relativo'], examples: ['El Gran Buenos Aires, con millones de habitantes, tiene muchos más diputados provinciales que la Patagonia bonaerense: la base poblacional garantiza que cada voto tenga el mismo peso relativo en la elección de representantes.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['representación proporcional', 'base poblacional', 'derecho electoral', 'demografía'], order: 58, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-59', lawId: 'const-buenos-aires', number: '59', title: '', text: `1.- Esta Constitución garantiza el pleno ejercicio de los derechos políticos, con arreglo al principio de la soberanía popular y las leyes que se dicten en consecuencia. La atribución del sufragio popular es un derecho inherente a la condición de ciudadano argentino y del extranjero en las condiciones que determine la ley, y un deber que se desempeña con arreglo a las prescripciones de esta Constitución y a la ley de la materia. El sufragio será universal, igual, secreto y obligatorio. 2.- Los partidos políticos son instituciones fundamentales del sistema democrático. Su creación y el ejercicio de sus actividades son libres dentro del respeto a la Constitución Nacional, a esta Constitución y a la ley que en su consecuencia se dicte, garantizándose su organización y funcionamiento democrático, la representación de las minorías, la competencia exclusiva para la postulación de los candidatos a cargos públicos electivos, el acceso a la información pública y a la difusión de sus ideas. La Provincia contribuye al sostenimiento económico de los partidos políticos, los que deberán dar publicidad del origen y destino de sus fondos y patrimonios.`, plainLanguageExplanation: 'El sufragio es universal, igual, secreto y obligatorio. Los partidos políticos son instituciones fundamentales del sistema democrático y tienen el monopolio de la postulación de candidatos.', practicalEffects: ['Solo los partidos políticos reconocidos pueden presentar candidatos a cargos electivos', 'Los partidos reciben financiamiento público y deben publicar el origen y destino de sus fondos'], examples: ['Un candidato independiente sin partido no puede presentarse a elecciones para diputado provincial: la Constitución otorga el monopolio de postulación a los partidos políticos. Solo los partidos reconocidos pueden postular candidatos a cargos electivos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sufragio', 'partidos políticos', 'democracia', 'financiamiento político'], order: 59, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-60', lawId: 'const-buenos-aires', number: '60', title: '', text: `La proporcionalidad de la representación será la regla en todas las elecciones populares para integrar cuerpos colegiados, a fin de dar a cada opinión un número de representantes proporcional al número de sus adherentes, según el sistema que para la aplicación de este principio determine la ley. A los efectos de mantener la regla establecida en este artículo, la Legislatura determinará la forma y oportunidad del reemplazo por suplentes, de legisladores, municipales y consejeros escolares, en los casos de vacante. Con el mismo objeto, no se convocará a elecciones por menos de tres vacantes.`, plainLanguageExplanation: 'La proporcionalidad es la regla en todas las elecciones populares para cuerpos colegiados: cada fuerza política obtiene representantes en proporción a los votos recibidos.', practicalEffects: ['Los partidos minoritarios tienen derecho a representación proporcional a sus votos', 'La ley regula el sistema proporcional aplicable y la cobertura de vacantes mediante suplentes'], examples: ['Si un partido obtiene el 15% de los votos en la Sección Electoral Capital, tiene derecho a aproximadamente el 15% de las bancas en disputa. No puede hacerse un sistema "todo o nada" (winner-takes-all) que excluya a las minorías.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['representación proporcional', 'elecciones', 'cuerpos colegiados', 'sistema electoral'], order: 60, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-61', lawId: 'const-buenos-aires', number: '61', title: '', text: `La Legislatura dictará la ley electoral; ésta será uniforme para toda la Provincia y se sujetará a las disposiciones precedentes y a las que se expresan a continuación: 1° Cada uno de los partidos en que se divida la Provincia, constituirá un distrito electoral; los distritos electorales serán agrupados en secciones electorales. No se formará ninguna sección electoral a la que le corresponda elegir menos de tres senadores y seis diputados. La capital de la Provincia formará una sección electoral. 2° Se votará personalmente y por boletas en que se consten los nombres de los candidatos. 3° Los electores votarán en el distrito electoral de su residencia. 4° Los electores estarán obligados a desempeñar las funciones electorales que les encomienden las autoridades creadas por esta Constitución y la ley electoral; se determinarán sanciones para los infractores.`, plainLanguageExplanation: 'La Legislatura dicta la ley electoral uniforme para toda la Provincia. El voto es personal, en boleta, en el distrito de residencia del elector, que tiene obligación de participar en las funciones electorales.', practicalEffects: ['Cada partido judicial constituye un distrito electoral; las secciones deben elegir al menos tres senadores y seis diputados', 'Los electores están obligados a participar en los comicios y pueden ser sancionados si se niegan'], examples: ['Un ciudadano empadronado en Mar del Plata (Partido de General Pueyrredón) vota en ese distrito y solo puede votar para los cargos de esa sección electoral. No puede votar en el distrito de donde es oriundo si ya cambió su domicilio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ley electoral', 'distritos electorales', 'voto', 'uniformidad electoral'], order: 61, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-62', lawId: 'const-buenos-aires', number: '62', title: '', text: `Habrá una Junta Electoral permanente, integrada por los presidente de la Suprema Corte de Justicia, del Tribunal de Cuentas y de tres Cámaras de Apelación del departamento de la Capital, que funcionará en el local de la Legislatura, bajo la presidencia del primero. En caso de impedimento serán reemplazados por sus substitutos legales.`, plainLanguageExplanation: 'La Junta Electoral permanente es el órgano que supervisa el proceso electoral. Se integra por presidentes de la Suprema Corte, del Tribunal de Cuentas y de Cámaras de Apelación.', practicalEffects: ['La Junta Electoral garantiza la imparcialidad del proceso al estar integrada por magistrados judiciales', 'Su carácter permanente permite funcionar antes, durante y después de cada comicio'], examples: ['Tras cada elección provincial, es la Junta Electoral —no el gobierno— quien verifica los resultados, resuelve impugnaciones y otorga diplomas a los electos. Su composición judicial garantiza imparcialidad frente al poder político.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Junta Electoral', 'proceso electoral', 'control electoral', 'magistrados'], order: 62, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-63', lawId: 'const-buenos-aires', number: '63', title: '', text: `Corresponderá a la Junta Electoral: 1° Formar y depurar el registro de electores; 2° Designar y remover los electores encargados de recibir los sufragios; 3° Realizar los escrutinios, sin perjuicio de lo que disponga la Legislatura en el caso de resolver la simultaneidad de las elecciones nacionales y provinciales; 4° Juzgar de la validez de las elecciones; 5° Diplomar a los legisladores, municipales y consejeros escolares, quienes con esa credencial, quedarán habilitados para ejercer sus respectivos mandatos. Estas atribuciones y las demás que le acuerde la Legislatura, serán ejercida con sujeción al procedimiento que determine la ley.`, plainLanguageExplanation: 'La Junta Electoral tiene atribuciones exclusivas: forma el padrón, designa autoridades de mesa, hace el escrutinio, juzga la validez de elecciones y otorga diplomas a los electos.', practicalEffects: ['La validez de toda elección es decidida por la Junta Electoral, con carácter definitivo', 'Los legisladores y concejales solo pueden ejercer su mandato tras recibir el diploma de la Junta'], examples: ['Si hay denuncia de fraude en una mesa electoral de La Matanza, es la Junta Electoral quien investiga, puede anular esa mesa y, si lo considera, toda la elección del distrito. Su resolución habilitará o denegará el diploma al candidato.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Junta Electoral', 'escrutinio', 'validez de elecciones', 'diplomas'], order: 63, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-64', lawId: 'const-buenos-aires', number: '64', title: '', text: `A los efectos del escrutinio, los miembros del Ministerio Público y los secretarios de la Suprema Corte de Justicia y de las Cámaras de Apelación, serán auxiliares de la Junta Electoral.`, plainLanguageExplanation: 'Los miembros del Ministerio Público y secretarios de la Suprema Corte y las Cámaras de Apelación son auxiliares de la Junta Electoral durante el escrutinio.', practicalEffects: ['El escrutinio cuenta con el apoyo técnico y jurídico del Poder Judicial', 'La participación del Ministerio Público garantiza transparencia en el conteo de votos'], examples: ['Durante el escrutinio provincial, los fiscales del Ministerio Público asisten a la Junta Electoral verificando que el cómputo sea correcto. Su presencia, ordenada constitucionalmente, refuerza la transparencia del proceso.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Junta Electoral', 'escrutinio', 'auxiliares', 'Ministerio Público'], order: 64, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-65', lawId: 'const-buenos-aires', number: '65', title: '', text: `Toda elección deberá terminarse en un solo día, sin que las autoridades puedan suspenderla por ningún motivo.`, plainLanguageExplanation: 'Toda elección debe terminarse en un solo día y ninguna autoridad puede suspenderla por ningún motivo.', practicalEffects: ['La prohibición de suspender elecciones protege el proceso democrático de interferencias del poder político', 'No puede invocarse ningún pretexto, ni emergencia ni desorden, para interrumpir el acto electoral'], examples: ['Si durante una elección hay disturbios en algunos partidos, las autoridades no pueden ordenar suspender la votación en esas mesas: la Constitución prohíbe la suspensión del acto electoral por cualquier motivo. Deben garantizarse las condiciones para votar.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acto electoral', 'continuidad', 'un solo día', 'garantía electoral'], order: 65, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-66', lawId: 'const-buenos-aires', number: '66', title: '', text: `Los electores encargados de recibir los sufragios, tendrán a su cargo el orden inmediato en el comicio durante el ejercicio de sus funciones y para conservarlo o restablecerlo, podrán requerir el auxilio de la fuerza pública.`, plainLanguageExplanation: 'Las autoridades de mesa tienen a su cargo el orden del comicio durante su funcionamiento y pueden requerir la fuerza pública para mantenerlo o restablecerlo.', practicalEffects: ['Las autoridades de mesa tienen poder de policía en el recinto del comicio', 'La fuerza pública está subordinada a las autoridades electorales durante el acto comicial'], examples: ['Las autoridades de mesa tienen, durante el comicio, las mismas atribuciones que un agente policial para mantener el orden. Si un ciudadano perturba la votación, la autoridad puede hacerlo retirar sin necesidad de llamar a la policía.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['autoridades de mesa', 'orden comicial', 'fuerza pública','elecciones'], order: 66, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-67', lawId: 'const-buenos-aires', number: '67', title: '', text: `1. Los electores tienen el derecho de iniciativa para la presentación de proyectos de ley, con excepción de los referidos a reforma constitucional, aprobación de tratados y convenios, presupuesto, recursos, creación de municipios y de órganos jurisdiccionales, debiendo la Legislatura darle expreso tratamiento dentro del término de doce meses. La ley determinará las condiciones, requisitos y porcentaje de electores que deberán suscribir la iniciativa. 2. Todo asunto de especial trascendencia para la Provincia, podrá ser sometido a consulta popular por la Legislatura o por el Poder Ejecutivo, dentro de las respectivas competencias. La consulta podrá ser obligatoria y vinculante por el voto de la mayoría absoluta el total de los miembros de cada Cámara. 3. Todo proyecto de ley podrá ser sometido a consulta popular, para su ratificación o rechazo, por el voto de la mayoría absoluta del total de los miembros de cada Cámara. Ratificado el proyecto se promulgará como ley en forma automática. 4. La ley reglamentaria establecerá las condiciones, requisitos, materias y procedimientos que regirán para las diferentes formas de consulta popular. 5. La Legislatura por dos tercios de votos del total de los miembros de cada Cámara, podrá establecer otras formas de participación popular.`, plainLanguageExplanation: 'Los ciudadanos tienen derecho de iniciativa popular para presentar proyectos de ley. También existe la consulta popular vinculante o no vinculante y el referéndum legislativo.', practicalEffects: ['Los ciudadanos pueden forzar a la Legislatura a tratar un proyecto de ley si reúnen las firmas requeridas', 'En un referéndum, si la mayoría vota a favor de un proyecto este se promulga como ley automáticamente'], examples: ['10.000 electores bonaerenses pueden presentar ante la Legislatura un proyecto de ley para crear un seguro de desempleo provincial. La Cámara tiene la obligación de tratarlo, aunque puede modificarlo o rechazarlo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['iniciativa popular', 'consulta popular', 'referéndum', 'democracia directa'], order: 67, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-68', lawId: 'const-buenos-aires', number: '68', title: '', text: `El Poder Legislativo de la Provincia será ejercido por dos Cámaras, una de diputados y otra de senadores, elegidos directamente por los electores, con arreglo a las prescripciones de esta Constitución y a la ley de la materia.`, plainLanguageExplanation: 'El Poder Legislativo de la Provincia es bicameral: se ejerce por una Cámara de Diputados y un Senado, cuyos miembros son elegidos directamente por los ciudadanos.', practicalEffects: ['Toda ley requiere la aprobación de ambas Cámaras antes de ser promulgada por el Ejecutivo', 'El bicameralismo garantiza que cada proyecto sea revisado dos veces antes de convertirse en ley'], examples: ['Una ley provincial necesita aprobarse en ambas cámaras. Si Diputados aprueba una reforma educativa pero el Senado la rechaza, la ley no puede promulgarse: el bicameralismo exige el acuerdo de los dos cuerpos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Poder Legislativo', 'bicameralismo', 'Cámara de Diputados', 'Senado'], order: 68, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-69', lawId: 'const-buenos-aires', number: '69', title: '', text: `Esta Cámara se compondrá de ochenta y cuatro diputados. La Legislatura, por dos tercios de votos del total de los miembros de cada Cámara, podrá elevar esta cantidad hasta cien como máximo. Se determinará con arreglo a cada censo nacional o provincial, debidamente aprobado, el número de habitantes que ha de representar cada diputado.`, plainLanguageExplanation: 'La Cámara de Diputados se compone de 84 miembros, ampliables hasta 100 por ley especial. El número de habitantes por diputado se determina con cada censo nacional o provincial.', practicalEffects: ['La composición de la Cámara refleja la distribución poblacional del último censo aprobado', 'Puede ampliarse la Cámara hasta 100 diputados si la Legislatura lo decide por dos tercios'], examples: ['Cada distrito electoral (partido) elige diputados en proporción a su población: el Partido de La Matanza, con más de 2 millones de habitantes, elige más diputados que Patagones con sus 40.000 habitantes.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Cámara de Diputados', 'composición', 'censo', 'representación'], order: 69, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-70', lawId: 'const-buenos-aires', number: '70', title: '', text: `El cargo de diputado durará cuatro años, pero la Cámara se renovará por mitad cada dos años.`, plainLanguageExplanation: 'Los diputados duran cuatro años en su cargo. La Cámara se renueva por mitades cada dos años, lo que garantiza continuidad institucional y renovación periódica.', practicalEffects: ['Cada dos años se elige la mitad de la Cámara, evitando un recambio total que podría desestabilizar la legislatura', 'La renovación parcial permite que siempre haya legisladores con experiencia en el cuerpo'], examples: ['Cada dos años se renuevan aproximadamente 42 de los 84 bancas en Diputados. Esto genera continuidad institucional: nunca se renueva la cámara completa de una vez, lo que evita rupturas abruptas en la representación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandato diputados', 'renovación parcial', 'cuatro años', 'Cámara de Diputados'], order: 70, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-71', lawId: 'const-buenos-aires', number: '71', title: '', text: `Para ser diputado se requieren las cualidades siguientes: 1° Ciudadanía natural en ejercicio, o legal después de cinco años de obtenida, y residencia inmediata de un año para los que no sean hijos de la Provincia. 2° Veintidós años de edad.`, plainLanguageExplanation: 'Para ser diputado se requiere ciudadanía argentina (natural o legal con cinco años), residencia de un año en la Provincia si no es nativo de ella, y tener 22 años de edad.', practicalEffects: ['Un extranjero naturalizado puede ser diputado recién cinco años después de obtener la ciudadanía', 'La edad mínima de 22 años establece un umbral bajo para favorecer la participación de jóvenes'], examples: ['Un ciudadano naturalizado argentino con 2 años de residencia en el partido bonaerense donde quiere candidatearse y al menos 22 años cumple los requisitos para ser diputado provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos diputado', 'ciudadanía', 'edad mínima', 'residencia'], order: 71, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-72', lawId: 'const-buenos-aires', number: '72', title: '', text: `Es incompatible el cargo de diputado con el de empleado a sueldo de la Provincia o de la Nación, y de miembro de los directorios de los establecimientos públicos de la Provincia. Exceptúanse los del magisterio en ejercicio y las comisiones eventuales. Todo ciudadano que siendo diputado aceptase cualquier empleo de los expresados en el primer párrafo de este artículo, cesará por ese hecho de ser miembro de la Cámara.`, plainLanguageExplanation: 'El cargo de diputado es incompatible con cualquier empleo remunerado de la Provincia o la Nación. Aceptar uno de esos empleos implica la renuncia automática a la banca.', practicalEffects: ['Un diputado que acepta un cargo ejecutivo pierde su banca sin necesidad de renuncia expresa', 'Los docentes en ejercicio y las comisiones eventuales son las únicas excepciones a esta incompatibilidad'], examples: ['Si un ministro del Ejecutivo provincial es elegido diputado, debe renunciar al ministerio antes de asumir la banca: el cargo legislativo es incompatible con cualquier empleo remunerado de la Provincia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incompatibilidad diputados', 'banca', 'empleo público', 'renuncia automática'], order: 72, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-73', lawId: 'const-buenos-aires', number: '73', title: '', text: `Es de competencia exclusiva de la Cámara de Diputados: 1° Prestar su acuerdo al Poder Ejecutivo para el nombramiento de los miembros del Consejo General de Cultura y Educación; 2° Acusar ante el Senado al Gobernador de la Provincia y sus ministros, al Vicegobernador, a los miembros de la Suprema Corte de Justicia, al Procurador y Subprocurador General de la misma, y al Fiscal de Estado por delitos en el desempeño de sus funciones o falta de cumplimiento a los deberes de su cargo. Para usar de esta atribución, deberá preceder una sanción de la Cámara por dos tercios de votos de sus miembros presentes, que declare que hay lugar a formación de causa. Cualquier habitante de la Provincia tiene acción para denunciar ante la Cámara de Diputados el delito o falta, a efecto de que se promueva la acusación. La ley determinará el procedimiento de estos juicios.`, plainLanguageExplanation: 'La Cámara de Diputados tiene competencia exclusiva para acusar ante el Senado al Gobernador, ministros, vicegobernador, miembros de la Suprema Corte y Fiscal de Estado por delitos en sus funciones.', practicalEffects: ['Cualquier habitante puede denunciar ante Diputados un delito de estos funcionarios para iniciar el juicio político', 'Se requieren dos tercios de los miembros presentes para declarar que hay lugar a formación de causa'], examples: ['Si la Cámara de Diputados inicia juicio político al gobernador por mal desempeño, necesita mayoría absoluta para acusar. Si prospera, el Senado actúa como tribunal y puede destituirlo con dos tercios de votos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'acusación', 'Cámara de Diputados', 'funcionarios'], order: 73, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-74', lawId: 'const-buenos-aires', number: '74', title: '', text: `Cuando se deduzca acusación por delitos comunes contra los funcionarios acusables por la Cámara de Diputados, no podrá procederse contra sus personas, sin que previamente el tribunal competente solicite el juicio político y la Legislatura haga lugar a la acusación y al allanamiento de la inmunidad del acusado.`, plainLanguageExplanation: 'Los altos funcionarios pasibles de juicio político no pueden ser procesados por delitos comunes sin que previamente la Legislatura levante su inmunidad mediante el procedimiento de desafuero.', practicalEffects: ['La inmunidad protege el ejercicio del cargo pero no es absoluta: puede levantarse por mayoría legislativa', 'Sin desafuero, un juez penal no puede detener ni procesar a un diputado, senador o gobernador'], examples: ['Un diputado detenido por robo puede ser procesado penalmente por la justicia ordinaria, pero primero la Cámara de Diputados debe votar su desafuero por mayoría absoluta para suspenderle la inmunidad.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['desafuero', 'inmunidad', 'juicio político', 'delitos comunes'], order: 74, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-75', lawId: 'const-buenos-aires', number: '75', title: '', text: `Esta Cámara se compondrá de cuarenta y dos senadores. La Legislatura, por dos tercios de votos del total de los miembros de cada Cámara, podrá elevar esta cantidad hasta cincuenta, como máximo, estableciendo el número de habitantes que ha de representar cada senador, de acuerdo con lo prescripto en el artículo 69.`, plainLanguageExplanation: 'El Senado provincial se compone de 42 miembros, ampliables hasta 50 por ley especial. La cantidad de habitantes por senador se fija con cada censo, al igual que para diputados.', practicalEffects: ['El Senado tiene el doble de habitantes representados por cada miembro que la Cámara de Diputados', 'Puede ampliarse hasta 50 senadores si la Legislatura lo decide por dos tercios de votos'], examples: ['El Senado bonaerense tiene 42 miembros. Cada sección electoral elige senadores en proporción a su población, lo que da más bancas al Gran Buenos Aires que al interior rural.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Senado', 'composición', 'senadores', 'representación'], order: 75, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-76', lawId: 'const-buenos-aires', number: '76', title: '', text: `Son requisitos para ser senador: 1° - Ciudadanía natural en ejercicio, o legal después de cinco años de obtenida y residencia inmediata de un año para los que no sean hijos de la Provincia. 2° - Tener treinta años de edad.`, plainLanguageExplanation: 'Para ser senador se requiere ciudadanía argentina (natural o legal con cinco años), residencia de un año si no es nativo de la Provincia, y 30 años de edad cumplidos.', practicalEffects: ['Los requisitos para senador son más exigentes que para diputado, especialmente la edad mínima (30 vs 22)', 'La diferencia etaria refleja la función deliberativa y de revisión que tiene el Senado'], examples: ['Para ser senador se requiere tener al menos 26 años, ser ciudadano argentino y residir en la sección electoral que se pretende representar. Un candidato de 25 años sería inelegible.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos senador', 'ciudadanía', 'edad mínima', 'residencia'], order: 76, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-77', lawId: 'const-buenos-aires', number: '77', title: '', text: `Son también aplicables al cargo de senador las incompatibilidades establecidas en el artículo 72 para los diputados, en los términos allí prescriptos.`, plainLanguageExplanation: 'Los senadores tienen las mismas incompatibilidades que los diputados: no pueden acumular el cargo con empleos remunerados del Estado ni integrar directorios de organismos públicos.', practicalEffects: ['Un senador que acepta un empleo público incompatible pierde su banca automáticamente', 'Los docentes en ejercicio son la única excepción a la regla de incompatibilidad en ambas Cámaras'], examples: ['Un secretario de juzgado que es electo senador debe renunciar a su cargo judicial antes de asumir: la banca senatorial es incompatible con el empleo remunerado del Estado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incompatibilidad senadores', 'empleo público', 'banca', 'Senado'], order: 77, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-78', lawId: 'const-buenos-aires', number: '78', title: '', text: `El cargo de senador durará cuatro años, pero la Cámara se renovará por mitad cada dos años.`, plainLanguageExplanation: 'Los senadores duran cuatro años en su cargo. El Senado se renueva por mitades cada dos años, igual que la Cámara de Diputados.', practicalEffects: ['Cada dos años se elige la mitad del Senado, garantizando continuidad institucional', 'La renovación parcial impide que un partido que ganó una elección controle totalmente el cuerpo'], examples: ['Los senadores duran 4 años y el Senado se renueva por mitades cada 2 años. Esto significa que en cada elección se disputa aproximadamente la mitad de las bancas del Senado, garantizando continuidad institucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandato senadores', 'renovación parcial', 'cuatro años', 'Senado'], order: 78, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-79', lawId: 'const-buenos-aires', number: '79', title: '', text: `Es atribución exclusiva del Senado juzgar en juicio público a los acusados por la Cámara de Diputados, constituyéndose al efecto en tribunal y prestando sus miembros juramento o afirmación para estos casos. Cuando el acusado fuese el Gobernador o el Vicegobernador de la Provincia, deberá presidir el Senado el Presidente de la Suprema Corte de Justicia, pero no tendrá voto.`, plainLanguageExplanation: 'El Senado es el tribunal del juicio político: juzga en juicio público a los funcionarios acusados por Diputados. Si el acusado es el Gobernador, preside la Suprema Corte pero sin votar.', practicalEffects: ['El juicio político en el Senado es público: los ciudadanos pueden seguirlo', 'La presidencia de la Suprema Corte cuando se juzga al Gobernador garantiza imparcialidad en el tribunal'], examples: ['Si la Cámara de Diputados acusa al gobernador de mal desempeño y delitos en el ejercicio de sus funciones, el Senado se constituye en tribunal de enjuiciamiento y falla con dos tercios de votos. El gobernador puede ser destituido e inhabilitado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'Senado tribunal', 'Gobernador', 'Suprema Corte'], order: 79, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-80', lawId: 'const-buenos-aires', number: '80', title: '', text: `El fallo del Senado en estos casos no tendrá más efecto que destituir al acusado y aún declararlo incapaz de ocupar ningún puesto de honor o a sueldo de la Provincia. Ningún acusado podrá ser declarado culpable, sin una mayoría de dos tercios de votos de los miembros presentes. Deberá votarse en estos casos nominalmente y registrarse en el "Diario de Sesiones" el voto de cada senador.`, plainLanguageExplanation: 'El Senado solo puede destituir al acusado e inhabilitarlo para cargos públicos; no puede aplicar penas. La condena requiere dos tercios de votos y se registra nominalmente.', practicalEffects: ['El juicio político solo produce la destitución e inhabilitación, no penas de prisión', 'La votación nominal con registro garantiza transparencia y responsabilidad de cada senador'], examples: ['El Senado destituye a un ministro por juicio político: el efecto es que pierde el cargo y queda inhabilitado para ejercer funciones públicas provinciales. No puede ordenar su prisión: para eso debe intervenir la justicia penal ordinaria.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fallo Senado', 'destitución', 'inhabilitación', 'juicio político'], order: 80, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-81', lawId: 'const-buenos-aires', number: '81', title: '', text: `El que fuese condenado en esta forma queda, sin embargo, sujeto a acusación y juicio ante los tribunales ordinarios.`, plainLanguageExplanation: 'El funcionario destituido por juicio político queda sometido a la justicia ordinaria para que se le apliquen las penas criminales correspondientes a su conducta.', practicalEffects: ['La destitución no lo exime de la responsabilidad penal por los mismos hechos', 'La justicia ordinaria puede condenar a prisión al ex funcionario independientemente del juicio político'], examples: ['El exgobernador destituido por el Senado puede luego ser procesado penalmente por el mismo hecho ante la justicia ordinaria. La destitución política no lo exime de ir a juicio penal ni de pagar daños civiles.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['post-destitución', 'responsabilidad penal', 'justicia ordinaria', 'juicio político'], order: 81, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-82', lawId: 'const-buenos-aires', number: '82', title: '', text: `Presta su acuerdo a los nombramientos que debe hacer el Poder Ejecutivo con este requisito y le presenta una terna alternativa para el nombramiento de Tesorero y Subtesorero, Contador y Subcontador de la Provincia.`, plainLanguageExplanation: 'El Senado presta acuerdo a los nombramientos del Poder Ejecutivo y propone ternas para el nombramiento de Tesorero, Subtesorero, Contador y Subcontador de la Provincia.', practicalEffects: ['El Senado actúa como cuerpo de control en las designaciones de funcionarios clave del erario público', 'La terna impide que el Ejecutivo nombre libremente a los responsables de los fondos provinciales'], examples: ['El gobernador nombra al Fiscal de Estado, pero necesita el acuerdo del Senado: sin esa aprobación, el nombramiento no es válido. Esto evita que el Ejecutivo monopolice los cargos de control.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acuerdo Senado', 'nombramientos', 'tesorería', 'control legislativo'], order: 82, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-83', lawId: 'const-buenos-aires', number: '83', title: '', text: `Las elecciones para diputados y senadores tendrán lugar cada dos años, en la fecha que la ley establezca.`, plainLanguageExplanation: 'Las elecciones legislativas para renovar la mitad de cada Cámara se celebran cada dos años, en la fecha que fija la ley electoral.', practicalEffects: ['Los ciudadanos eligen diputados y senadores cada dos años, siguiendo el ritmo de renovación parcial de las Cámaras', 'La ley electoral determina la fecha exacta de cada comicio legislativo'], examples: ['En 2025 se renovó la mitad de la Legislatura bonaerense. En 2027 se renueva la otra mitad. Este ciclo bienal garantiza que nunca haya un corte total en la representación: siempre hay legisladores con experiencia en ejercicio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['elecciones legislativas', 'cada dos años', 'renovación parcial', 'calendario electoral'], order: 83, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-84', lawId: 'const-buenos-aires', number: '84', title: '', text: `Las Cámaras abrirán automáticamente sus sesiones ordinarias, el primer día hábil del mes de marzo de cada año y las cerrarán el treinta de noviembre. Funcionarán en la Capital de la Provincia pero podrán hacerlo por causas extraordinarias en otro punto, precediendo una disposición de ambas Cámaras que así lo autorice.`, plainLanguageExplanation: 'Las sesiones ordinarias de la Legislatura comienzan automáticamente el primer día hábil de marzo y finalizan el 30 de noviembre. Funcionan en La Plata, salvo causa extraordinaria.', practicalEffects: ['La apertura automática impide que el Ejecutivo bloquee el funcionamiento legislativo negándose a convocar las sesiones', 'Las sesiones fuera de la Capital requieren acuerdo de ambas Cámaras'], examples: ['El primer día hábil de marzo, la Legislatura bonaerense abre sus sesiones ordinarias automáticamente, sin necesidad de que el gobernador las convoque: es un mecanismo constitucional de independencia del Poder Legislativo frente al Ejecutivo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sesiones ordinarias', 'Legislatura', 'La Plata', 'período legislativo'], order: 84, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-85', lawId: 'const-buenos-aires', number: '85', title: '', text: `Los senadores y diputados residirán en la Provincia mientras dure el ejercicio de sus funciones.`, plainLanguageExplanation: 'Los senadores y diputados deben residir en la Provincia durante el ejercicio de su mandato, como condición de continuidad en el cargo.', practicalEffects: ['El legislador que deja de residir en la Provincia durante su mandato podría perder su banca', 'El requisito garantiza que los representantes estén presentes en el territorio que representan'], examples: ['Un diputado bonaerense que se muda a vivir en Montevideo pierde el requisito de residencia y puede ser desafectado de su banca. Los legisladores deben mantener su domicilio real en la Provincia durante todo su mandato.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['residencia legisladores', 'mandato', 'Provincia', 'requisito'], order: 85, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-86', lawId: 'const-buenos-aires', number: '86', title: '', text: `Las Cámaras podrán ser convocadas por el Poder Ejecutivo a sesiones extraordinarias, siempre que un asunto de interés público y urgente lo exija o convocarse por sí mismas cuando, por la misma razón, lo soliciten doce senadores y veinticuatro diputados. En estos casos, sólo se ocuparán del asunto o asuntos de la convocatoria, empezando por declarar si ha llegado el caso de urgencia e interés público para hacer lugar al requerimiento.`, plainLanguageExplanation: 'Las sesiones extraordinarias pueden ser convocadas por el Ejecutivo o por los propios legisladores (12 senadores y 24 diputados) ante asuntos urgentes de interés público.', practicalEffects: ['Los legisladores pueden auto-convocarse sin necesidad de que el Ejecutivo los cite', 'En sesiones extraordinarias solo pueden tratar los asuntos que motivaron la convocatoria'], examples: ['En enero, fuera del período ordinario, el gobernador puede convocar a sesiones extraordinarias para tratar un presupuesto de emergencia. La Legislatura solo puede tratar el asunto específico convocado, no cualquier tema.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sesiones extraordinarias', 'convocatoria', 'urgencia', 'interés público'], order: 86, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-87', lawId: 'const-buenos-aires', number: '87', title: '', text: `Para funcionar necesitan mayoría absoluta del total de sus miembros, pero en número menor podrán reunirse al solo efecto de acordar las medidas que estimen convenientes para compeler a los inasistentes.`, plainLanguageExplanation: 'Cada Cámara necesita mayoría absoluta de sus miembros para sesionar válidamente. Con menos quórum puede reunirse solo para adoptar medidas que obliguen a concurrir a los ausentes.', practicalEffects: ['Sin quórum la Cámara no puede aprobar leyes ni tomar decisiones válidas', 'Puede forzar la presencia de legisladores ausentes mediante las medidas que la ley autorice'], examples: ['Si hay 84 diputados totales, se necesitan al menos 43 presentes para sesionar. Si en la sesión hay menos, el presidente de la cámara no puede someter a votación ninguna ley: no hay quórum y la sesión no puede avanzar.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['quórum', 'mayoría absoluta', 'sesiones', 'asistencia'], order: 87, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-88', lawId: 'const-buenos-aires', number: '88', title: '', text: `Ninguna de las Cámaras podrá suspender sus sesiones más de tres días sin acuerdo de la otra.`, plainLanguageExplanation: 'Ninguna de las dos Cámaras puede suspender sus sesiones por más de tres días sin el acuerdo de la otra, garantizando la continuidad del trabajo legislativo.', practicalEffects: ['Ninguna Cámara puede paralizarse unilateralmente por un período largo sin el aval de la otra', 'Esto previene que una Cámara sabotee la actividad legislativa negándose a sesionar'], examples: ['Diputados no puede resolver en solitario suspender las sesiones por 30 días: necesita el acuerdo del Senado. Esto evita que una cámara paralice unilateralmente el trabajo legislativo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['suspensión sesiones', 'acuerdo bicameral', 'continuidad legislativa', 'tres días'], order: 88, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-89', lawId: 'const-buenos-aires', number: '89', title: '', text: `Ningún miembro del Poder Legislativo, durante su mandato, ni aún renunciando su cargo, podrá ser nombrado para desempeñar empleo alguno rentado que haya sido creado o cuyos emolumentos se hayan aumentado durante el período legal de la Legislatura en que haya actuado, ni ser parte en contrato alguno que resulte de una ley sancionada durante su período.`, plainLanguageExplanation: 'Ningún legislador puede beneficiarse de los cargos o contratos creados por las leyes que él mismo votó durante su mandato, ni aún renunciando a su banca.', practicalEffects: ['Un diputado no puede votar una ley que crea un cargo y luego renunciar para ocuparlo', 'Esto impide que los legisladores legiferen en beneficio propio'], examples: ['Un diputado que es dueño de una empresa constructora no puede votar una ley de obras públicas que beneficiaría directamente a su empresa: tiene conflicto de interés y debe excusarse o inhibirse de votar ese proyecto.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conflicto de interés', 'incompatibilidad legislativa', 'beneficio propio', 'ética pública'], order: 89, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-90', lawId: 'const-buenos-aires', number: '90', title: '', text: `Cada Cámara podrá nombrar comisiones de su seno para examinar el estado del tesoro y para el mejor desempeño de las atribuciones que le concierna, y podrá pedir a los jefes de departamentos de la Administración y por su conducto a sus subalternos, los informes que crea convenientes.`, plainLanguageExplanation: 'Cada Cámara puede crear comisiones internas para examinar el tesoro y cumplir sus funciones, y puede solicitar informes a los organismos de la administración provincial.', practicalEffects: ['Las comisiones legislativas tienen poder de solicitar información a cualquier repartición del Ejecutivo', 'La negativa injustificada a brindar información podría configurar un conflicto institucional'], examples: ['La Comisión de Presupuesto de la Cámara de Diputados puede convocar al Ministro de Economía para que explique una partida del presupuesto, y este tiene obligación constitucional de comparecer y dar los informes requeridos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['comisiones legislativas', 'control parlamentario', 'informes', 'control del tesoro'], order: 90, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-91', lawId: 'const-buenos-aires', number: '91', title: '', text: `Podrán también expresar la opinión de su mayoría por medio de resoluciones o declaraciones sin fuerza de ley, sobre cualquier asunto político o administrativo que afecte los intereses generales de la Provincia o de la Nación.`, plainLanguageExplanation: 'Las Cámaras pueden emitir resoluciones o declaraciones sin fuerza de ley para expresar su postura sobre asuntos políticos o administrativos que afecten los intereses de la Provincia o la Nación.', practicalEffects: ['Las resoluciones legislativas no obligan al Ejecutivo pero tienen valor político e institucional', 'Son el mecanismo para que la Legislatura se pronuncie sobre temas de gobierno sin dictar una ley'], examples: ['La Legislatura puede emitir una resolución declarando de interés provincial un festival cultural sin que eso tenga fuerza de ley. Las declaraciones expresan la posición política del cuerpo pero no crean obligaciones jurídicas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['resoluciones legislativas', 'declaraciones', 'función política', 'Legislatura'], order: 91, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-92', lawId: 'const-buenos-aires', number: '92', title: '', text: `Cada Cámara podrá hacer venir a su sala a los ministros del Poder Ejecutivo, para pedirles los informes que estime convenientes.`, plainLanguageExplanation: 'Cada Cámara puede citar a los ministros del Poder Ejecutivo para que concurran y brinden los informes que la Cámara considere necesarios.', practicalEffects: ['Los ministros tienen obligación de concurrir a la sala cuando son citados por la Cámara', 'La negativa a comparecer puede dar lugar a conflictos institucionales y medidas de la Cámara'], examples: ['El Senado puede interpelar al Ministro de Seguridad para que explique un operativo policial controvertido. El ministro debe concurrir y responder. Si la cámara considera que su gestión fue negligente, puede votar una moción de censura.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['interpelación', 'ministros', 'control legislativo', 'informes'], order: 92, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-93', lawId: 'const-buenos-aires', number: '93', title: '', text: `Cada Cámara se regirá por un reglamento especial y nombrará su Presidente y Vicepresidentes, a excepción del Presidente del Senado, que lo será el Vicegobernador, quien no tendrá voto sino en caso de empate. Los funcionarios y empleados de ambas Cámaras, serán designados en la forma que determinen sus respectivos reglamentos.`, plainLanguageExplanation: 'Cada Cámara se rige por su propio reglamento. La Cámara de Diputados elige su presidente; el Senado es presidido por el Vicegobernador, que solo vota en caso de empate.', practicalEffects: ['El Vicegobernador preside el Senado pero solo vota para desempatar', 'Cada Cámara tiene autonomía para dictar sus normas internas de funcionamiento'], examples: ['Cada cámara dicta su propio reglamento interno. Si el reglamento del Senado establece que los proyectos ingresan por mesa de entradas antes de las 17h, eso es una norma interna vinculante que el Ejecutivo no puede cuestionar.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglamento', 'Vicegobernador', 'presidente del Senado', 'autonomía legislativa'], order: 93, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-94', lawId: 'const-buenos-aires', number: '94', title: '', text: `La Legislatura sancionará su presupuesto, acordando el número de empleados que necesite, su dotación y la forma en que deben proveerse. Esta ley no podrá ser vetada por el Poder Ejecutivo.`, plainLanguageExplanation: 'La Legislatura aprueba su propio presupuesto de gastos y personal. El Poder Ejecutivo no puede vetarlo, garantizando así la independencia financiera del Poder Legislativo.', practicalEffects: ['El Ejecutivo no puede condicionar financieramente al Legislativo vetando su presupuesto', 'La autonomía financiera de la Legislatura es una garantía de la separación de poderes'], examples: ['La Legislatura aprueba su propio presupuesto de gastos operativos y el gobernador no puede vetarlo: la autonomía financiera del Legislativo es una garantía de separación de poderes.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presupuesto legislativo', 'autonomía financiera', 'veto', 'separación de poderes'], order: 94, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-95', lawId: 'const-buenos-aires', number: '95', title: '', text: `Las sesiones de ambas Cámaras serán públicas, y sólo podrán ser secretas por acuerdo de la mayoría.`, plainLanguageExplanation: 'Las sesiones de las Cámaras son públicas por defecto; solo pueden ser secretas si la mayoría de los miembros así lo decide expresamente.', practicalEffects: ['El carácter público de las sesiones garantiza la transparencia en la formación de las leyes', 'Las sesiones secretas son la excepción y requieren una decisión expresa de la mayoría'], examples: ['Los ciudadanos tienen derecho a presenciar o ver en vivo las sesiones del Senado y Diputados: son públicas por mandato constitucional. Solo por mayoría especial pueden declararse secretas, lo que es excepcional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sesiones públicas', 'transparencia', 'sesiones secretas', 'Legislatura'], order: 95, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-96', lawId: 'const-buenos-aires', number: '96', title: '', text: `Los miembros de ambas Cámaras son inviolables por las opiniones que manifiesten y votos que emitan en el desempeño de su cargo. No hay autoridad alguna que pueda procesarlos y reconvenirlos en ningún tiempo por tales causas.`, plainLanguageExplanation: 'Los legisladores son inviolables por las opiniones y votos emitidos en ejercicio de su mandato: ninguna autoridad puede procesarlos ni reconvenirlos por esas causas.', practicalEffects: ['Un legislador no puede ser demandado civil ni penalmente por lo que dijo o votó en la Cámara', 'La inviolabilidad es perpetua respecto de esos actos y no puede ser levantada ni siquiera por la propia Cámara'], examples: ['Un diputado que en sesión acusa a un funcionario de corrupción no puede ser demandado civilmente por difamación: sus palabras en el recinto están protegidas por la inmunidad de opinión, aunque luego no se pruebe el hecho.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inviolabilidad', 'inmunidad de opinión', 'legisladores', 'libertad de expresión parlamentaria'], order: 96, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-97', lawId: 'const-buenos-aires', number: '97', title: '', text: `Los senadores y diputados gozarán de completa inmunidad en su persona desde el día de su elección hasta el día en que cese su mandato, y no podrán ser detenidos por ninguna autoridad sino en caso de ser sorprendidos en la ejecución flagrante de algún crimen, dándose inmediatamente cuenta a la Cámara respectiva, con la información sumaria del hecho, para que resuelva lo que corresponda, según el caso, sobre la inmunidad personal.`, plainLanguageExplanation: 'Los legisladores gozan de inmunidad de arresto desde su elección hasta el fin del mandato. Solo pueden ser detenidos si son sorprendidos en flagrante delito; la Cámara decide sobre su situación.', practicalEffects: ['Ninguna autoridad puede detener a un legislador sin la intervención de su Cámara, salvo flagrancia', 'La Cámara decide si mantiene o levanta la inmunidad personal del legislador detenido en flagrancia'], examples: ['Un diputado bonaerense es detenido por la policía provincial de camino a una sesión. Como no se trata de flagrante delito, la detención viola su inmunidad de arresto: debe ser liberado y la Cámara debe intervenir para resolver si corresponde el desafuero.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inmunidad de arresto', 'legisladores', 'flagrancia', 'desafuero'], order: 97, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-98', lawId: 'const-buenos-aires', number: '98', title: '', text: `Cuando se deduzca acusación ante la justicia contra cualquier senador o diputado, examinado el mérito del sumario, de la acusación o información traída, podrá la Cámara respectiva, con dos tercios de votos, suspender en sus funciones al acusado, dejándolo a disposición del juez competente para su juzgamiento.`, plainLanguageExplanation: 'Cuando un legislador es procesado penalmente, la Cámara puede suspenderlo en sus funciones por dos tercios de votos, dejándolo a disposición del juez para su juzgamiento.', practicalEffects: ['La suspensión legislativa no equivale a condena: el legislador sigue siendo inocente hasta sentencia firme', 'El proceso requiere dos tercios de votos, protegiendo a los legisladores de suspensiones por motivos políticos'], examples: ['Un senador bonaerense es imputado por defraudación. La Cámara de Senadores, con dos tercios de votos, resuelve suspenderlo en sus funciones y remitirlo al juez penal competente para que continúe el proceso sin el escudo de la inmunidad.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['suspensión legislativa', 'proceso penal', 'desafuero', 'dos tercios'], order: 98, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-99', lawId: 'const-buenos-aires', number: '99', title: '', text: `Cada Cámara podrá corregir a cualquiera de sus miembros por desorden de conducta en el ejercicio de sus funciones, por dos tercios de votos; y en caso de reincidencia, podrá expulsarlo por el mismo número de votos. Por inasistencia notable podrá también declararlo cesante en la misma forma.`, plainLanguageExplanation: 'Cada Cámara puede corregir a sus miembros por desorden de conducta (con dos tercios de votos) y hasta expulsarlos en caso de reincidencia. La inasistencia grave también puede llevar a la cesantía.', practicalEffects: ['La expulsión requiere dos tercios, protegiendo a los legisladores de sanciones por motivos políticos', 'La inasistencia reiterada puede llevar a la declaración de vacante de la banca'], examples: ['Un diputado acumula quince inasistencias injustificadas durante el año legislativo. La Cámara, con dos tercios de votos, lo declara cesante en su cargo por inasistencia notable, dejando la banca disponible para que asuma el suplente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disciplina legislativa', 'expulsión', 'conducta', 'inasistencia'], order: 99, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-100', lawId: 'const-buenos-aires', number: '100', title: '', text: `Cada Cámara tendrá jurisdicción para corregir los actos que atenten contra su autoridad, dignidad e independencia y contra las inmunidades de sus miembros. La ley definirá los casos y las penas para la aplicación de este artículo.`, plainLanguageExplanation: 'Cada Cámara tiene poder de policía para sancionar los actos que atenten contra su autoridad, dignidad e independencia. La ley define los casos y las penas aplicables.', practicalEffects: ['La Cámara puede sancionar a quienes impidan su funcionamiento o atenten contra sus miembros', 'El poder disciplinario protege la independencia del Legislativo frente a presiones externas'], examples: ['Un funcionario del Ejecutivo ingresa a fuerza al recinto de la Cámara de Diputados e interrumpe una sesión. La propia Cámara, sin recurrir al Poder Judicial, puede sancionarlo con multa o arresto en ejercicio de su poder disciplinario para proteger su independencia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['poder disciplinario', 'autoridad legislativa', 'independencia parlamentaria', 'sanciones'], order: 100, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-101', lawId: 'const-buenos-aires', number: '101', title: '', text: `Al aceptar el cargo los diputados y senadores, jurarán por Dios y por la Patria, o por la Patria, desempeñarlo fielmente.`, plainLanguageExplanation: 'Al asumir el cargo, los legisladores prestan juramento de desempeñarlo fielmente, con o sin invocación religiosa según la conciencia de cada uno.', practicalEffects: ['El juramento formaliza la asunción del cargo y el compromiso con la Constitución', 'La opción de jurar solo por la Patria garantiza que el juramento sea accesible a personas de cualquier creencia'], examples: ['Una diputada de convicciones laicas asume su banca jurando "por la Patria y la Constitución" sin invocar a Dios. El juramento tiene la misma validez jurídica que el de un colega que jura "por Dios y por la Patria": ambas formas son constitucionalmente equivalentes.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juramento', 'legisladores', 'toma de posesión', 'asunción del cargo'], order: 101, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-102', lawId: 'const-buenos-aires', number: '102', title: '', text: `Los senadores y diputados gozarán de una remuneración determinada por la Legislatura.`, plainLanguageExplanation: 'Los senadores y diputados perciben una remuneración cuyo monto fija la propia Legislatura en ejercicio de su autonomía financiera.', practicalEffects: ['La Legislatura determina sus propios sueldos, lo que puede generar tensiones con la opinión pública', 'La remuneración garantiza que el ejercicio del mandato no quede limitado a personas de alto poder adquisitivo'], examples: ['La Legislatura bonaerense aprueba una ley que actualiza las dietas legislativas conforme al Índice de Precios al Consumidor. Al ser la propia Legislatura quien fija sus sueldos, el aumento tiene vigencia directa sin necesidad de aprobación del Ejecutivo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneración legisladores', 'dietas', 'Legislatura', 'autonomía financiera'], order: 102, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-103', lawId: 'const-buenos-aires', number: '103', title: '', text: `Corresponde al Poder Legislativo: 1° Establecer los impuestos y contribuciones necesarios para los gastos de servicio público, debiendo estas cargas ser uniformes en toda la Provincia. 2° Fijar anualmente el cálculo de recursos y el presupuesto de gastos. Con relación a nuevos gastos, dentro de la ley de presupuesto, la iniciativa corresponderá exclusivamente al Poder Ejecutivo; pero la Legislatura podrá disminuir o suprimir los que le fuesen propuestos. La ley de presupuesto será la base a que debe sujetarse todo gasto en la administración general de la Provincia. Si el Poder Ejecutivo no remitiera los proyectos de presupuesto y leyes de recursos para el ejercicio siguientes antes del 31 de agosto, la Legislatura podrá iniciar su estudio y sancionarlos, tomando por base las leyes vigentes. Vencido el ejercicio administrativo sin que la Legislatura hubiese sancionado una nueva ley de gastos y recursos, se tendrán por prorrogadas las que hasta ese momento se encontraban en vigor. 3° Crear y suprimir empleos para la mejor administración de la Provincia, determinando sus atribuciones, responsabilidades y dotación, con la limitación a que se refiere el primer párrafo del inciso anterior. 4° Fijar las divisiones territoriales para la mejor administración. 5° Conceder indultos y acordar amnistías por delitos de sedición en la Provincia. 6° Conceder privilegios por un tiempo limitado a los autores o inventores, perfeccionadores y primeros introductores de perjuicio de las atribuciones del Gobierno General. 7° Dictar leyes estableciendo los medios de hacer efectivas las responsabilidades de todos los recaudadores de rentas y tesoreros de la Provincia y sus municipios. 8° Dictar leyes estableciendo los medios de hacer efectivas las responsabilidades civiles de los funcionarios públicos 9° Aprobar o desechar los tratados que el Poder Ejecutivo celebrase con otras provincias. 10° Discernir honores y recompensas pecuniarias por una sola vez, y con dos tercios de votos del número total de los miembros de cada Cámara, por servicios distinguidos prestados a la Provincia. 11.- Dictar la Ley Orgánica del Montepío Civil. 12.- Organizar la carrera administrativa con las siguientes bases: acceso por idoneidad; escalafón; estabilidad; uniformidad de sueldos en cada categoría e incompatibilidades. 13.- Dictar todas aquellas leyes necesarias para el mejor desempeño de las anteriores atribuciones y para todo asunto de interés público y general de la Provincia, cuya naturaleza y objeto no corresponda privativamente a los poderes nacionales.`, plainLanguageExplanation: 'El Poder Legislativo tiene amplias atribuciones: fijar impuestos, aprobar el presupuesto, crear organismos, acordar amnistías, proteger inventores, organizar la carrera administrativa y dictar toda ley de interés público provincial.', practicalEffects: ['Solo la Legislatura puede crear o modificar impuestos provinciales', 'Si el Ejecutivo no envía el presupuesto antes del 31 de agosto, la Legislatura puede elaborarlo con la ley vigente como base'], examples: ['El Ejecutivo no envía el proyecto de presupuesto antes del 31 de agosto. La Legislatura toma el presupuesto vigente como base, lo estudia y lo sanciona sin necesidad de esperar al Ejecutivo. Al cerrar el año sin una nueva ley aprobada, el presupuesto anterior se prorroga automáticamente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribuciones legislativas', 'impuestos', 'presupuesto', 'amnistía'], order: 103, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-104', lawId: 'const-buenos-aires', number: '104', title: '', text: `Toda ley puede tener principio en cualquiera de las Cámaras y se propondrá en forma de proyecto por cualquiera de los miembros de cada Cámara y también por el Poder Ejecutivo. Toda ley especial que autorice gastos, necesitará para su aprobación, el voto de los dos tercios de los miembros presentes de cada Cámara.`, plainLanguageExplanation: 'Todo proyecto de ley puede iniciarse en cualquiera de las Cámaras, presentado por cualquier legislador o por el Ejecutivo. Las leyes que autorizan gastos requieren dos tercios de los presentes.', practicalEffects: ['El Ejecutivo puede presentar proyectos de ley en cualquiera de las Cámaras', 'Una ley de gasto especial no puede aprobarse por simple mayoría: requiere dos tercios'], examples: ['Una diputada presenta un proyecto de ley de reforma procesal civil, que puede originarse en la Cámara de Diputados. En cambio, un proyecto que crea un fondo especial con erogaciones millonarias requiere dos tercios de los presentes en ambas Cámaras para ser aprobado, dado que autoriza gastos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['iniciativa legislativa', 'proyectos de ley', 'dos tercios', 'leyes de gasto'], order: 104, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-105', lawId: 'const-buenos-aires', number: '105', title: '', text: `Aprobado un proyecto por la Cámara de su origen, pasará para su revisión a la otra y si ésta también lo aprobase, se comunicará al Poder Ejecutivo para su promulgación.`, plainLanguageExplanation: 'El proyecto aprobado por la Cámara de origen pasa a la otra Cámara para su revisión. Si ambas lo aprueban, se comunica al Ejecutivo para su promulgación como ley.', practicalEffects: ['Ninguna ley puede sancionarse sin la aprobación de ambas Cámaras', 'El paso por la Cámara revisora garantiza un segundo análisis del proyecto antes de convertirse en ley'], examples: ['La Cámara de Diputados aprueba un proyecto de reforma del Código de Faltas. El proyecto pasa al Senado que lo aprueba sin modificaciones. La Legislatura comunica la sanción al Poder Ejecutivo, quien lo promulga y publica en el Boletín Oficial como ley vigente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['proceso legislativo', 'Cámara revisora', 'promulgación', 'bicameralismo'], order: 105, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-106', lawId: 'const-buenos-aires', number: '106', title: '', text: `Si la Cámara revisora modifica el proyecto que se le ha remitido, volverá a la iniciadora y si ésta aprueba las modificaciones, pasará al Poder Ejecutivo. Si las modificaciones fuesen rechazadas, volverá por segunda vez el proyecto a la Cámara revisora y si ella no tuviese dos tercios para insistir, prevalecerá la sanción de la iniciadora. Pero si concurriesen dos tercios de votos para sostener las modificaciones, el proyecto pasará de nuevo a la Cámara de su origen, la que necesitará igualmente el voto de las dos terceras partes de sus miembros presentes, para que su sanción se comunique al Poder Ejecutivo.`, plainLanguageExplanation: 'Si la Cámara revisora introduce modificaciones, el proyecto va y viene entre las Cámaras. Si la revisora insiste en sus cambios con dos tercios, la iniciadora también necesita dos tercios para imponer su versión.', practicalEffects: ['El desacuerdo entre Cámaras no paraliza el proceso: se resuelve mediante el mecanismo de insistencia con dos tercios', 'Una Cámara no puede imponer su versión sobre la otra sin el respaldo de dos tercios de sus miembros'], examples: ['El Senado modifica tres artículos de un proyecto de Diputados. Diputados rechaza los cambios. El Senado vuelve a insistir con sus modificaciones, pero solo reúne 51 votos de 64 (menos de dos tercios). En ese caso, prevalece la versión original de Diputados y el proyecto va al Ejecutivo sin las modificaciones del Senado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modificaciones legislativas', 'insistencia', 'dos tercios', 'proceso bicameral'], order: 106, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-107', lawId: 'const-buenos-aires', number: '107', title: '', text: `Ningún proyecto de leyes rechazado totalmente por una de las Cámaras, podrá repetirse en las sesiones de aquel año. Un proyecto sancionado por una de las Cámaras y no votado por la otra en ese año o en el siguiente, se considerará rechazado.`, plainLanguageExplanation: 'El proyecto rechazado totalmente por una Cámara no puede volver a presentarse ese año. El aprobado por una Cámara y no tratado por la otra en ese año ni el siguiente se considera rechazado.', practicalEffects: ['Los proyectos "cajoneados" quedan rechazados si pasan dos períodos legislativos sin ser tratados', 'Esto evita que proyectos rechazados sean presentados repetidamente en la misma sesión'], examples: ['Un proyecto de ley de ordenamiento territorial es rechazado por el Senado. Su autor no puede volver a presentarlo en las sesiones ordinarias de ese mismo año; debe esperar al período siguiente para reintroducirlo o redirigirlo a la otra Cámara como proyecto alternativo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rechazo legislativo', 'caducidad', 'proceso legislativo', 'proyectos cajoneados'], order: 107, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-108', lawId: 'const-buenos-aires', number: '108', title: '', text: `El Poder Ejecutivo deberá promulgar los proyectos de ley sancionados dentro de diez días de haberle sido remitidos por la Legislatura; pero podrá devolverlos con observaciones durante dicho plazo, y si una vez transcurrido no ha hecho la promulgación, ni los ha devuelto con sus objeciones, serán ley de la Provincia y deberán promulgarse y publicarse en el día inmediato por el Poder Ejecutivo, o en su defecto, se publicarán por el Presidente de la Cámara que hubiese prestado la sanción definitiva. En cuanto a la ley general de presupuesto, que fuese observada por el Poder Ejecutivo, sólo será reconsiderada en la parte objetada, quedando en vigencia lo demás de ella.`, plainLanguageExplanation: 'El Ejecutivo tiene 10 días para promulgar o vetar una ley. Si no hace nada, la ley se promulga automáticamente. El veto parcial del presupuesto no afecta las partes no vetadas.', practicalEffects: ['El silencio del Ejecutivo durante 10 días equivale a promulgar la ley tácitamente', 'Si la Legislatura se cierra antes de los 10 días, el Ejecutivo puede enviar el veto a la secretaría de la Cámara'], examples: ['La Legislatura sanciona una ley de acceso a la información pública y la remite al Ejecutivo. El Gobernador no la promulga ni la veta dentro de los 10 días hábiles. Transcurrido ese plazo, la ley queda promulgada en forma tácita y el Poder Ejecutivo debe publicarla en el Boletín Oficial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['promulgación', 'veto', '10 días', 'promulgación tácita'], order: 108, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-109', lawId: 'const-buenos-aires', number: '109', title: '', text: `Si antes del vencimiento de los diez días, hubiese tenido lugar la clausura de las Cámaras, el Poder Ejecutivo deberá, dentro de dicho término, remitir el proyecto vetado a la Secretaría de la Cámara de su origen, sin cuyo requisito no tendrá efecto el veto.`, plainLanguageExplanation: 'Si la Legislatura cierra sus sesiones antes de que venza el plazo de veto, el Ejecutivo debe remitir el veto a la secretaría de la Cámara de origen dentro del plazo de 10 días, o el veto caduca.', practicalEffects: ['El cierre de sesiones no extiende el plazo del Ejecutivo para vetar', 'Si el veto no se comunica formalmente a la secretaría, el proyecto se promulga automáticamente'], examples: ['La Legislatura sanciona una ley el último día de sesiones ordinarias y la remite al Ejecutivo. El Gobernador no puede promulgarla ni vetarla durante el receso. Al reanudarse las sesiones, el plazo de 10 días hábiles comienza a correr desde ese momento; si no actúa, la ley queda promulgada tácitamente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['veto', 'cierre de sesiones', 'plazo', 'caducidad del veto'], order: 109, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-110', lawId: 'const-buenos-aires', number: '110', title: '', text: `Devuelto un proyecto por el Poder Ejecutivo, será reconsiderado primero en la Cámara de su origen, pasando luego a la revisora; y si ambas insisten en su sanción por el voto de los dos tercios de sus miembros presentes, el proyecto será ley y el Poder Ejecutivo se hallará obligado a promulgarlo. En caso contrario, no podrá repetirse en las sesiones de aquel año.`, plainLanguageExplanation: 'Si ambas Cámaras insisten en el proyecto vetado por dos tercios de sus miembros presentes, el Ejecutivo está obligado a promulgar la ley sin posibilidad de nuevo veto.', practicalEffects: ['El veto presidencial puede ser superado si ambas Cámaras insisten con dos tercios', 'Si alguna Cámara no alcanza dos tercios para insistir, el proyecto no puede tratarse en las sesiones de ese año'], examples: ['El Gobernador veta una ley de reforma educativa. Diputados y el Senado votan insistir con el texto original: ambas Cámaras reúnen más de dos tercios de sus miembros presentes. La ley queda sancionada sin modificaciones y el Ejecutivo está obligado a promulgarla y publicarla.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['insistencia legislativa', 'superación del veto', 'dos tercios', 'veto'], order: 110, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-111', lawId: 'const-buenos-aires', number: '111', title: '', text: `Si un proyecto de ley observado volviere a ser sancionado en uno de los dos períodos legislativos subsiguientes, el Poder Ejecutivo no podrá observarlo de nuevo, estando obligado a promulgarlo como ley.`, plainLanguageExplanation: 'Si un proyecto vetado es sancionado nuevamente en alguno de los dos períodos legislativos siguientes, el Ejecutivo ya no puede vetarlo y está obligado a promulgarlo.', practicalEffects: ['La insistencia legislativa en dos períodos futuros elimina definitivamente la posibilidad de veto', 'Esta regla evita que el Ejecutivo bloquee indefinidamente leyes con apoyo legislativo sostenido'], examples: ['El Gobernador veta parcialmente una ley y devuelve observaciones. Una Cámara insiste con dos tercios pero la otra no alcanza ese número. En ese caso, el veto prevalece y la parte observada no entra en vigor; solo las partes no vetadas, si son separables, pueden ser promulgadas parcialmente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['doble insistencia', 'veto', 'promulgación obligatoria', 'proceso legislativo'], order: 111, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-112', lawId: 'const-buenos-aires', number: '112', title: '', text: `En la sanción de las leyes se usará la siguiente fórmula: "El Senado y Cámara de Diputados de la Provincia de Buenos Aires, sancionan con fuerza de ley, etcétera"`, plainLanguageExplanation: 'Las leyes provinciales llevan la fórmula oficial "El Senado y Cámara de Diputados de la Provincia de Buenos Aires, sancionan con fuerza de ley..." que les da autenticidad formal.', practicalEffects: ['La fórmula de sanción identifica el origen constitucional de la ley y le da validez formal', 'Una ley sin la fórmula correcta podría ser cuestionada en su validez formal'], examples: ['Una ley de la Provincia que no incluye la fórmula "El Senado y la Cámara de Diputados de la Provincia de Buenos Aires, sancionan con fuerza de Ley" puede ser cuestionada en su validez formal. La fórmula autentica el acto legislativo y distingue una ley de cualquier otro acto de gobierno.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fórmula de sanción', 'leyes', 'validez formal', 'autenticidad'], order: 112, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-113', lawId: 'const-buenos-aires', number: '113', title: '', text: `Ambas Cámaras sólo se reunirán para el desempeño de las funciones siguientes: 1° Apertura y clausura de las sesiones; 2° Para recibir el juramento de ley al Gobernador y Vicegobernador de la Provincia; 3° Para tomar en consideración y admitir o desechar las renuncias que hicieren de su cargo los mismos funcionarios; 4° Para verificar la elección de senadores al Congreso Nacional; 5° Para tomar conocimiento del resultado del escrutinio de la elección de Gobernador y Vicegobernador y proclamar a los electos; 6° Para considerar la renuncia de los senadores electos al Congreso de la Nación, antes de que el Senado tome conocimiento de su elección.`, plainLanguageExplanation: 'La Asamblea Legislativa (ambas Cámaras reunidas) solo sesiona para funciones específicas: apertura y clausura, juramento del Gobernador y Vicegobernador, aceptar renuncias, proclamar electos y elegir senadores nacionales.', practicalEffects: ['La Asamblea no es un órgano legislativo ordinario sino un foro para actos institucionales solemnes', 'El Gobernador no puede asumir sin prestar juramento ante la Asamblea Legislativa'], examples: ['El nuevo Gobernador electo debe prestar juramento de asumir el cargo. Para ello, Diputados y Senadores se reúnen en Asamblea Legislativa —sesión conjunta— en el recinto de la Legislatura, y en ese acto el Gobernador jura ante los legisladores reunidos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Asamblea Legislativa', 'sesión conjunta', 'juramento', 'actos institucionales'], order: 113, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-114', lawId: 'const-buenos-aires', number: '114', title: '', text: `Todos los nombramientos que se defieren a la Asamblea General deberán hacerse a mayoría absoluta de los miembros presentes.`, plainLanguageExplanation: 'Los nombramientos que realiza la Asamblea Legislativa requieren mayoría absoluta de los miembros presentes de la sesión conjunta.', practicalEffects: ['La mayoría simple de la Asamblea (más de la mitad de los presentes) es suficiente para los nombramientos', 'Este umbral garantiza que los nombramientos tengan un respaldo real de la mayoría legislativa'], examples: ['La Asamblea Legislativa debe designar al Presidente de la Suprema Corte. Reunidos diputados y senadores, la designación requiere mayoría absoluta del total de los presentes —no solo mayoría simple—, lo que exige mayor consenso que en una votación ordinaria.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mayoría absoluta', 'Asamblea Legislativa', 'nombramientos', 'quórum'], order: 114, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-115', lawId: 'const-buenos-aires', number: '115', title: '', text: `Si hecho el escrutinio no resultare candidato con mayoría absoluta, deberá repetirse la votación, contrayéndose a los dos candidatos que hubiesen obtenido más votos en la anterior; y en caso de empate, decidirá el presidente.`, plainLanguageExplanation: 'Si ningún candidato alcanza mayoría absoluta en la Asamblea, se repite la votación entre los dos más votados. En caso de empate, decide el presidente de la Asamblea.', practicalEffects: ['El sistema de dos vueltas entre los más votados garantiza que siempre se llegue a una decisión', 'El presidente de la Asamblea tiene voto de desempate, lo que le confiere poder en situaciones disputadas'], examples: ['La Asamblea Legislativa vota para cubrir un cargo y ningún candidato obtiene mayoría absoluta. Se realiza una segunda vuelta entre los dos más votados; el que obtenga más votos en esa instancia resulta designado, rompiendo el empate y garantizando que el cargo quede cubierto.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['segunda vuelta', 'desempate', 'Asamblea Legislativa', 'votación'], order: 115, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-116', lawId: 'const-buenos-aires', number: '116', title: '', text: `De las excusaciones que se presenten de nombramientos hechos por la Asamblea, conocerá ella misma, procediendo según fuese su resultado.`, plainLanguageExplanation: 'La Asamblea Legislativa resuelve las excusaciones de los nombramientos que ella misma realiza, determinando si acepta o no la justificación presentada.', practicalEffects: ['La Asamblea tiene control completo sobre los nombramientos que le corresponden, incluyendo la evaluación de excusas', 'Una excusación aceptada implica que la Asamblea debe proceder a otro nombramiento'], examples: ['Un legislador que es primo del candidato a un cargo que debe resolver la Asamblea Legislativa debe excusarse de votar para evitar conflicto de intereses. La Asamblea sesiona y vota válidamente con los miembros que no se han excusado, siempre que se mantenga el quórum.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['excusaciones', 'Asamblea Legislativa', 'nombramientos', 'autarquía'], order: 116, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-117', lawId: 'const-buenos-aires', number: '117', title: '', text: `Las reuniones de la Asamblea General serán presididas por el Vicegobernador, en su defecto, por el Vicepresidente del Senado, y a falta de éste, por el Presidente de la Cámara de Diputados.`, plainLanguageExplanation: 'La Asamblea Legislativa es presidida por el Vicegobernador, o en su defecto por el Vicepresidente del Senado, y en último término por el Presidente de la Cámara de Diputados.', practicalEffects: ['El Vicegobernador tiene un rol protocolario central en la Asamblea por ser su presidente nato', 'La cadena de sustitución garantiza que siempre haya alguien habilitado para presidir la Asamblea'], examples: ['El Vicegobernador, en su rol de presidente nato del Senado, preside también la Asamblea Legislativa cuando esta se reúne para el juramento del Gobernador o la designación de funcionarios. Si el Vicegobernador está ausente, el Presidente Provisional del Senado toma la presidencia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Asamblea Legislativa', 'presidencia', 'Vicegobernador', 'sustitución'], order: 117, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-118', lawId: 'const-buenos-aires', number: '118', title: '', text: `No podrá funcionar la Asamblea sin la mayoría absoluta de los miembros de cada Cámara.`, plainLanguageExplanation: 'La Asamblea Legislativa no puede funcionar sin la mayoría absoluta de los miembros de cada Cámara, garantizando representatividad suficiente en los actos institucionales solemnes.', practicalEffects: ['Si no hay quórum de ambas Cámaras, la Asamblea no puede sesionar ni realizar los actos que le competen', 'El quórum de la Asamblea es más exigente que el de cada Cámara por separado'], examples: ['Se convoca a la Asamblea Legislativa para elegir al Defensor del Pueblo. Si no se reúne la mayoría absoluta del total de sus miembros, la sesión no puede iniciarse. Los legisladores ausentes pueden ser compelidos a concurrir para garantizar el quórum necesario.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['quórum', 'Asamblea Legislativa', 'mayoría absoluta', 'sesión conjunta'], order: 118, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-119', lawId: 'const-buenos-aires', number: '119', title: '', text: `El Poder Ejecutivo de la Provincia será desempeñado por un ciudadano, con el título de Gobernador de la Provincia de Buenos Aires.`, plainLanguageExplanation: 'El Poder Ejecutivo de la Provincia es unipersonal y está a cargo del Gobernador, quien tiene el título de "Gobernador de la Provincia de Buenos Aires".', practicalEffects: ['El Gobernador concentra en su persona toda la jefatura del Ejecutivo provincial', 'El título constitucional es el de "Gobernador", no "Presidente" ni ningún otro'], examples: ['Cuando el Gobernador dicta un decreto sin refrendo ministerial, el acto puede ser impugnado: el poder ejecutivo es unipersonal y reside en el Gobernador, pero los ministros coparticipan en los actos de gobierno con su firma, que distribuye responsabilidades.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Gobernador', 'Poder Ejecutivo', 'unipersonal', 'jefatura ejecutiva'], order: 119, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-120', lawId: 'const-buenos-aires', number: '120', title: '', text: `Al mismo tiempo y por el mismo período que se elija Gobernador, será elegido un Vicegobernador.`, plainLanguageExplanation: 'El Vicegobernador es elegido simultáneamente con el Gobernador y por el mismo período, formando una fórmula única ante el electorado.', practicalEffects: ['El Vicegobernador y el Gobernador son inseparables en la elección: el pueblo vota la fórmula completa', 'El Vicegobernador sucede al Gobernador en caso de acefalía y preside el Senado'], examples: ['En las elecciones provinciales, los ciudadanos votan una fórmula única: el candidato a Gobernador y el candidato a Vicegobernador forman una sola boleta. No es posible votar a uno sin el otro, ya que la Constitución los liga como fórmula para un período de cuatro años.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Vicegobernador', 'fórmula electoral', 'Gobernador', 'período'], order: 120, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-121', lawId: 'const-buenos-aires', number: '121', title: '', text: `Para ser elegido Gobernador o Vicegobernador, se requiere: 1° Haber nacido en territorio argentino o ser hijo de ciudadano nativo, si hubiese nacido en país extranjero. 2° Tener treinta años de edad. 3° Cinco años de domicilio en la Provincia con ejercicio de ciudadanía no interrumpida, si no hubiese nacido en ella.`, plainLanguageExplanation: 'Para ser Gobernador o Vicegobernador se requiere ser argentino nativo o hijo de nativo, tener al menos 30 años de edad y cinco años de domicilio continuado en la Provincia.', practicalEffects: ['Un extranjero naturalizado no puede acceder al cargo de Gobernador', 'El domicilio en la Provincia debe ser continuo e ininterrumpido durante los cinco años previos a la elección'], examples: ['Un ciudadano naturalizado que vive hace 12 años en la Provincia y tiene 37 años de edad cumple los requisitos para ser candidato a Gobernador: es argentino nativo o naturalizado, mayor de 30 años y con domicilio en la Provincia. Un candidato recién llegado o menor de 30 no puede postularse.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos Gobernador', 'ciudadanía', 'domicilio', 'Vicegobernador'], order: 121, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-122', lawId: 'const-buenos-aires', number: '122', title: '', text: `El Gobernador y el Vicegobernador durarán cuatro años en el ejercicio de sus funciones, y cesarán en ellas en el mismo día en que expire el período legal, sin que evento alguno pueda motivar su prorrogación por un día más, ni tampoco que se les complete más tarde.`, plainLanguageExplanation: 'El Gobernador y el Vicegobernador ejercen sus funciones durante cuatro años exactos, finalizando el mismo día que vence el período legal sin posibilidad de prórroga ni retraso.', practicalEffects: ['El mandato es de duración fija: no puede extenderse ni un día por ningún motivo', 'La fecha de cese es objetiva e improrrogable, garantizando la renovación periódica del poder ejecutivo'], examples: ['El Gobernador asume el 10 de diciembre y ejerce el mandato durante exactamente cuatro años. No puede prorrogar su mandato ni un día más allá del plazo constitucional, aunque haya obras públicas en curso o emergencias sin resolver: el 10 de diciembre del cuarto año, su sucesor asume.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['período de gobierno', 'mandato ejecutivo', 'cuatro años', 'renovación'], order: 122, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-123', lawId: 'const-buenos-aires', number: '123', title: '', text: `El Gobernador y el Vicegobernador pueden ser reelectos o sucederse recíprocamente, por un nuevo período. Si han sido reelectos o se han sucedido recíprocamente, no pueden ser elegidos para ninguno de ambos cargos, sino con intervalo de un período.`, plainLanguageExplanation: 'El Gobernador y el Vicegobernador pueden ser reelectos o sucederse recíprocamente por un período más. Tras dos períodos consecutivos, deben esperar un período completo antes de poder postularse nuevamente.', practicalEffects: ['El Gobernador puede ser reelecto una sola vez de forma inmediata', 'Después de dos mandatos consecutivos (propios o por sucesión), debe existir un período de intervalo obligatorio'], examples: ['Un Gobernador que cumplió dos mandatos consecutivos no puede presentarse a un tercer período aunque haya pasado tiempo desde el último. Solo podría volver a postularse si dejó pasar un período completo sin ejercer el cargo, ya que la Constitución limita a dos mandatos consecutivos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reelección', 'mandato ejecutivo', 'Gobernador', 'límite mandatos'], order: 123, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-124', lawId: 'const-buenos-aires', number: '124', title: '', text: `En caso de muerte, destitución, renuncia, enfermedad, suspensión o ausencia del Gobernador, las funciones del Poder Ejecutivo serán desempeñadas por el Vicegobernador, por todo el resto del período legal, en los tres primeros casos, o hasta que haya cesado la inhabilidad temporaria, en los tres últimos.`, plainLanguageExplanation: 'Si el Gobernador muere, renuncia, es destituido, está enfermo, suspendido o ausente, el Vicegobernador asume sus funciones: de forma definitiva en los tres primeros casos o provisionalmente en los restantes.', practicalEffects: ['La acefalía del Ejecutivo tiene solución institucional automática: el Vicegobernador asume sin trámites adicionales', 'La distinción entre causal definitiva y temporal determina si el reemplazo es permanente o transitorio'], examples: ['El Gobernador sufre una enfermedad grave y debe ausentarse por 60 días. Durante ese período el Vicegobernador ejerce el Poder Ejecutivo con todas las atribuciones. Al recuperarse, el Gobernador retoma automáticamente el cargo sin necesidad de nuevas elecciones.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acefalía', 'Vicegobernador', 'reemplazo', 'Poder Ejecutivo'], order: 124, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-125', lawId: 'const-buenos-aires', number: '125', title: '', text: `Si la inhabilidad temporaria afectase simultáneamente al Gobernador y al Vicegobernador, el Vicepresidente primero del Senado se hará cargo del Poder Ejecutivo, hasta que aquélla cese en uno de ellos. Dicho funcionario también se hará cargo del Poder Ejecutivo, cuando en el momento de producirse la enfermedad, suspensión o ausencia del Gobernador, no exista Vicegobernador, o cuando al producirse la muerte, destitución o renuncia del Gobernador, el Vicegobernador estuviera afectado de inhabilidad temporaria, o cuando la inhabilidad temporaria, afectase al Vicegobernador en ejercicio definitivo de las funciones de Gobernador.`, plainLanguageExplanation: 'Cuando tanto el Gobernador como el Vicegobernador estén impedidos simultáneamente, asume provisoriamente el Vicepresidente primero del Senado hasta que uno de ellos pueda reincorporarse.', practicalEffects: ['La cadena de sucesión garantiza continuidad del Poder Ejecutivo incluso ante acefalía simultánea del titular y su sucesor', 'El Vicepresidente del Senado actúa como tercer escalón de la línea sucesoria del Ejecutivo provincial'], examples: ['Tanto el Gobernador como el Vicegobernador renuncian simultáneamente. La cadena de suplencia activa al Vicepresidente Primero del Senado para cubrir la acefalía y garantizar que el Poder Ejecutivo no quede sin titular, mientras se convoca a la Asamblea Legislativa para resolver la situación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acefalía simultánea', 'Vicepresidente del Senado', 'continuidad institucional', 'reemplazo ejecutivo'], order: 125, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-126', lawId: 'const-buenos-aires', number: '126', title: '', text: `En el caso de muerte, destitución o renuncia del Gobernador, cuando no exista Vicegobernador o del Vicegobernador que hubiese asumido definitivamente las funciones de Gobernador, el Poder Ejecutivo, será desempeñado por el vicepresidente primero del Senado, pero dentro de los treinta días de producida la vacante se reunirá la Asamblea Legislativa y designará de su seno un Gobernador interino, quien se hará cargo inmediatamente del Poder Ejecutivo. El Gobernador interino deberá reunir las condiciones establecidas en el artículo 121 y durará en sus funciones hasta que asuma el nuevo Gobernador. Si la vacante tuviere lugar en la primera mitad del período en ejercicio se procederá a elegir Gobernador y Vicegobernador en la primera elección de renovación de la Legislatura que se realice, quienes completarán el período constitucional correspondiente a los mandatarios reemplazados. El Gobernador y el Vicegobernador electos tomarán posesión de sus cargos el primer día hábil posterior a la integración de las Cámaras con la incorporación de los legisladores electos en la misma elección.`, plainLanguageExplanation: 'Ante acefalía total sin Vicegobernador, el Vicepresidente del Senado asume provisionalmente y la Asamblea Legislativa debe designar un Gobernador interino dentro de los 30 días. Si la vacante ocurre en la primera mitad del período, se convoca a elecciones.', practicalEffects: ['La Asamblea Legislativa actúa como elector de Gobernador interino ante vacante total del Ejecutivo', 'Si queda más de la mitad del mandato por cumplir, el pueblo elige un nuevo Gobernador en la próxima elección legislativa'], examples: ['Ante la renuncia del Gobernador y del Vicegobernador, la Asamblea Legislativa se reúne para designar un Gobernador interino que conduzca el Poder Ejecutivo hasta que se realicen nuevas elecciones. El interino no puede presentarse como candidato en esa elección.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acefalía total', 'Gobernador interino', 'Asamblea Legislativa', 'elecciones'], order: 126, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-127', lawId: 'const-buenos-aires', number: '127', title: '', text: `Si la acefalía se produjese por muerte, destitución o renuncia del Gobernador interino, se procederá como ha sido previsto en el artículo anterior.`, plainLanguageExplanation: 'Si el Gobernador interino también muere, es destituido o renuncia, se aplica nuevamente el procedimiento del artículo anterior para cubrir la vacante.', practicalEffects: ['El mecanismo de acefalía se reitera cuantas veces sea necesario para garantizar que siempre haya titular del Ejecutivo', 'La cadena de sucesión no tiene un límite predefinido: la Constitución la cierra mediante la elección popular'], examples: ['El Gobernador interino designado por la Asamblea Legislativa también renuncia antes de que se realicen las nuevas elecciones. La cadena sucesoria continúa: el siguiente en la línea de suplencia asume con carácter interino hasta que los comicios definan al nuevo Gobernador electo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Gobernador interino', 'acefalía reiterada', 'sucesión ejecutiva', 'vacante'], order: 127, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-128', lawId: 'const-buenos-aires', number: '128', title: '', text: `En los mismos casos en que el Vicegobernador reemplaza al Gobernador, el Vicepresidente del Senado reemplaza al Vicegobernador.`, plainLanguageExplanation: 'El mismo mecanismo que regula el reemplazo del Gobernador por el Vicegobernador se aplica simétricamente al reemplazo del Vicegobernador por el Vicepresidente del Senado.', practicalEffects: ['La regla de sustitución es idéntica tanto para el primer como para el segundo cargo del Ejecutivo', 'Si el Vicegobernador está ejerciendo las funciones de Gobernador y queda impedido, el Vicepresidente del Senado asume'], examples: ['El Vicegobernador fallece en el tercer año de mandato. El Gobernador continúa al frente del Ejecutivo y el Vicepresidente del Senado asume la presidencia del cuerpo. La vacante del Vicegobernador se cubre según las reglas de suplencia para que la cadena de sucesión no quede interrumpida.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reemplazo Vicegobernador', 'Vicepresidente del Senado', 'simetría sucesoria', 'Ejecutivo provincial'], order: 128, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-129', lawId: 'const-buenos-aires', number: '129', title: '', text: `La Legislatura dictará una ley que determine el funcionario que deberá desempeñar el cargo provisoriamente para los casos en que el Gobernador, Vicegobernador y Vicepresidente del Senado no pudiesen desempeñar las funciones del Poder Ejecutivo.`, plainLanguageExplanation: 'La ley determinará qué funcionario asumirá provisionalmente el Poder Ejecutivo cuando Gobernador, Vicegobernador y Vicepresidente del Senado estén simultáneamente impedidos.', practicalEffects: ['El cuarto escalón de la cadena sucesoria es determinado por ley ordinaria, no por la Constitución', 'Esta norma cierra el sistema de acefalía cubriendo los casos más extremos de vacancia múltiple'], examples: ['Si la cadena de suplencia constitucional se agota sin que ningún titular pueda ejercer el Poder Ejecutivo, la ley especial de acefalía provincial establece quién asume y bajo qué condiciones, garantizando que el Ejecutivo nunca quede sin conducción, aun en las situaciones más extremas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acefalía máxima', 'cadena sucesoria', 'Poder Ejecutivo', 'ley de acefalía'], order: 129, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-130', lawId: 'const-buenos-aires', number: '130', title: '', text: `El Gobernador y el Vicegobernador en ejercicio de sus funciones, residirán en la Capital de la Provincia y no podrán ausentarse del territorio provincial por más de treinta días sin autorización legislativa.`, plainLanguageExplanation: 'El Gobernador y el Vicegobernador deben residir en la Capital provincial (La Plata) durante el ejercicio de sus funciones y no pueden ausentarse del territorio provincial por más de 30 días sin autorización legislativa.', practicalEffects: ['El Gobernador necesita autorización de la Legislatura para viajes oficiales prolongados al exterior o a otras provincias', 'La residencia obligatoria en La Plata asegura la presencia física del Ejecutivo en la sede del gobierno'], examples: ['El Gobernador desea viajar al exterior por una semana para firmar acuerdos interprovinciales. Necesita autorización de la Legislatura para ausentarse de la Provincia. Si viaja sin autorización, el acto puede ser cuestionado y el Vicegobernador quedaría a cargo de manera automática.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['residencia Gobernador', 'ausencia provincial', 'autorización legislativa', 'sede gobierno'], order: 130, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-131', lawId: 'const-buenos-aires', number: '131', title: '', text: `En el receso de las Cámaras sólo podrán ausentarse por un motivo urgente de interés público y por el tiempo indispensable, dando cuenta a aquéllas oportunamente.`, plainLanguageExplanation: 'Durante el receso legislativo, el Gobernador solo puede ausentarse de la Provincia por motivo urgente de interés público y por el tiempo estrictamente necesario, debiendo informar a las Cámaras en la primera oportunidad.', practicalEffects: ['El Gobernador no puede ausentarse libremente en período de receso: debe justificar urgencia e interés público', 'La obligación de dar cuenta a las Cámaras preserva el control parlamentario sobre el Ejecutivo'], examples: ['Durante el receso legislativo, el Gobernador necesita ausentarse por razones de salud. Puede hacerlo sin autorización previa de la Legislatura, pero debe notificarla; si la Legislatura considera que la ausencia afecta al interés público, puede convocar a sesión para evaluar la situación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['receso legislativo', 'ausencia Gobernador', 'interés público', 'control parlamentario'], order: 131, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-132', lawId: 'const-buenos-aires', number: '132', title: '', text: `Al tomar posesión del cargo, el Gobernador y el Vicegobernador prestarán juramento ante el Presidente de la Asamblea Legislativa en los términos siguientes: "Juro por Dios y por la Patria y sobre estos Santos Evangelios, observar y hacer observar la Constitución de la Provincia, desempeñando con lealtad y honradez el cargo de Gobernador (o Vicegobernador). Si así no lo hiciere, Dios y la Patria me lo demanden".`, plainLanguageExplanation: 'El Gobernador y el Vicegobernador juran ante el Presidente de la Asamblea Legislativa al asumir el cargo, comprometiendo su lealtad, honradez y fiel observancia de la Constitución provincial.', practicalEffects: ['El juramento es condición para el ejercicio válido del cargo: sin él, la asunción no es constitucional', 'La fórmula constitucionalizada del juramento no puede ser modificada por ley ordinaria'], examples: ['El Gobernador electo asume el cargo en el Salón de la Asamblea Legislativa, ante los legisladores reunidos en sesión conjunta. Presta juramento de desempeñar fielmente el cargo y cumplir y hacer cumplir la Constitución: desde ese momento ejerce el Poder Ejecutivo con todas sus atribuciones.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juramento', 'asunción del cargo', 'Gobernador', 'Asamblea Legislativa'], order: 132, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-133', lawId: 'const-buenos-aires', number: '133', title: '', text: `El Gobernador y el Vicegobernador gozan del sueldo que la ley determine, no pudiendo ser alterado en el período de sus nombramientos. Durante éste no podrán ejercer otro empleo ni recibir otro emolumento de la Nación o de la Provincia.`, plainLanguageExplanation: 'El Gobernador y el Vicegobernador perciben el sueldo que fija la ley, el cual no puede ser modificado durante su mandato. Mientras ejercen el cargo no pueden ocupar ningún otro empleo ni cobrar remuneración de la Nación o la Provincia.', practicalEffects: ['La inamovilidad del sueldo protege la independencia del Gobernador frente a presiones del poder legislativo', 'La incompatibilidad absoluta impide que el Gobernador tenga intereses económicos paralelos durante su mandato'], examples: ['La Legislatura no puede reducir el sueldo del Gobernador en ejercicio como medio de presión política: la Constitución fija su remuneración e impide que sea disminuida durante el mandato. Tampoco puede el Gobernador ejercer otra actividad rentada mientras ocupa el cargo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sueldo Gobernador', 'incompatibilidad', 'inamovilidad salarial', 'mandato ejecutivo'], order: 133, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-134', lawId: 'const-buenos-aires', number: '134', title: '', text: `La elección de Gobernador y Vicegobernador será hecha directamente por el pueblo, por simple mayoría de votos; cada elector votará el nombre de un ciudadano para Gobernador y el de otro ciudadano para Vicegobernador.`, plainLanguageExplanation: 'El Gobernador y el Vicegobernador son elegidos por voto directo del pueblo mediante simple mayoría: cada elector vota un nombre para Gobernador y otro para Vicegobernador.', practicalEffects: ['El sistema de elección directa elimina intermediarios electorales como el Colegio Electoral', 'La mayoría simple significa que gana quien obtiene más votos, sin necesidad de ballotage'], examples: ['En las elecciones de 2023, tres fórmulas compiten por la gobernación. La que obtiene más votos —aunque no supere el 50%— gana la elección: en la Provincia de Buenos Aires el Gobernador se elige por mayoría simple en primera vuelta, sin segunda ronda.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['elección directa', 'Gobernador', 'mayoría simple', 'voto popular'], order: 134, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-135', lawId: 'const-buenos-aires', number: '135', title: '', text: `La elección tendrá lugar conjuntamente con la de senadores y diputados del año que corresponda.`, plainLanguageExplanation: 'La elección de Gobernador y Vicegobernador se celebra el mismo día que las elecciones legislativas del año correspondiente, unificando los comicios en una sola jornada electoral.', practicalEffects: ['La coincidencia con las elecciones legislativas reduce los costos electorales y la fatiga cívica', 'El calendario electoral está coordinado para que cada cuatro años se renueve simultáneamente el Ejecutivo y parte del Legislativo'], examples: ['Las elecciones para Gobernador y Vicegobernador se realizan el mismo día que las elecciones legislativas provinciales, simplificando el calendario electoral y reduciendo costos. El ciudadano vota en un único acto por todas las autoridades provinciales que se renuevan ese año.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['elecciones simultáneas', 'calendario electoral', 'Gobernador', 'Vicegobernador'], order: 135, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-136', lawId: 'const-buenos-aires', number: '136', title: '', text: `La Junta Electoral practicará el escrutinio y remitirá constancia del mismo al Gobernador de la Provincia y al Presidente de la Asamblea Legislativa.`, plainLanguageExplanation: 'La Junta Electoral realiza el escrutinio de los votos y comunica el resultado al Gobernador en ejercicio y al Presidente de la Asamblea Legislativa para que ésta proceda a la proclamación.', practicalEffects: ['La Junta Electoral tiene competencia exclusiva para el escrutinio definitivo de las elecciones ejecutivas', 'El Presidente de la Asamblea y el Gobernador son los destinatarios institucionales del resultado electoral'], examples: ['Finalizado el escrutinio de la elección de Gobernador, la Junta Electoral bonaerense verifica los cómputos, resuelve las impugnaciones y proclama a la fórmula ganadora. Solo tras esa proclamación oficial el candidato puede ser reconocido como Gobernador electo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Junta Electoral', 'escrutinio', 'proclamación', 'elección Gobernador'], order: 136, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-137', lawId: 'const-buenos-aires', number: '137', title: '', text: `Una vez que el presidente de la Asamblea Legislativa haya recibido comunicación del escrutinio, convocará a la Asamblea con tres días de anticipación, a fin de que este Cuerpo tome conocimiento del resultado y proclame y diplome a los ciudadanos que hayan sido elegidos Gobernador y Vicegobernador. En caso de empate, la Asamblea resolverá por mayoría absoluta de votos cuál de los ciudadanos que hayan empatado debe desempeñar el cargo. Esta sesión de Asamblea no podrá levantarse hasta no haber terminado su cometido.`, plainLanguageExplanation: 'La Asamblea Legislativa convocada con tres días de anticipación proclama y diplomas al Gobernador y Vicegobernador electos. En caso de empate, la Asamblea elige por mayoría absoluta. La sesión no puede levantarse hasta cumplir su cometido.', practicalEffects: ['La Asamblea actúa como colegio electoral en caso de empate entre candidatos', 'La prohibición de levantar sesión garantiza que la proclamación siempre se resuelve en esa jornada'], examples: ['Dos fórmulas empatan en votos. La Asamblea Legislativa se reúne para resolver el empate: los diputados y senadores votan entre las dos fórmulas empatadas. La que obtenga mayoría en la Asamblea es proclamada Gobernadora y Vicegobernadora electas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Asamblea Legislativa', 'proclamación', 'empate electoral', 'diploma'], order: 137, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-138', lawId: 'const-buenos-aires', number: '138', title: '', text: `El Presidente de la Asamblea Legislativa comunicará el resultado de la sesión a que se refiere el artículo anterior, a los ciudadanos electos y al Gobernador de la Provincia.`, plainLanguageExplanation: 'El Presidente de la Asamblea Legislativa notifica a los electos y al Gobernador en ejercicio el resultado de la sesión de proclamación, cerrando el ciclo de la transmisión electoral.', practicalEffects: ['La notificación a los ciudadanos electos habilita el plazo para aceptar el cargo', 'El Gobernador en ejercicio recibe la comunicación formal para preparar la transmisión del mando'], examples: ['Una vez proclamado el Gobernador electo, el Presidente de la Asamblea Legislativa le notifica oficialmente el resultado. Esta comunicación marca el inicio formal del período preposesorio: el electo comienza a organizar su gabinete y preparar la transición del gobierno.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['notificación electoral', 'transmisión del mando', 'Presidente de la Asamblea', 'Gobernador electo'], order: 138, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-139', lawId: 'const-buenos-aires', number: '139', title: '', text: `Los ciudadanos que resulten electos Gobernador y Vicegobernador, deberán comunicar al Presidente de la Asamblea Legislativa y al Gobernador de la Provincia, la aceptación del cargo dentro de los cinco días siguientes a aquél en que les fue comunicado su nombramiento.`, plainLanguageExplanation: 'Los ciudadanos electos Gobernador y Vicegobernador deben comunicar su aceptación del cargo al Presidente de la Asamblea y al Gobernador en ejercicio dentro de los cinco días de notificada su elección.', practicalEffects: ['El plazo de cinco días para aceptar es perentorio: su vencimiento sin respuesta puede interpretarse como renuncia tácita', 'La aceptación expresa es el acto que abre el proceso formal de asunción del cargo'], examples: ['El Gobernador electo recibe la notificación de su triunfo. Tiene un plazo constitucional para manifestar que acepta el cargo. Si no lo hace en término, se entiende que renuncia y la Asamblea Legislativa debe resolver la situación convocando a quien corresponda según la cadena de suplencia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aceptación del cargo', 'Gobernador electo', 'plazo constitucional', 'transmisión del mando'], order: 139, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-140', lawId: 'const-buenos-aires', number: '140', title: '', text: `Aceptado que sea el cargo de Gobernador y Vicegobernador por los ciudadanos que hayan resultado electos, el Presidente de la Asamblea Legislativa fijará y les comunicará la hora en que habrán de presentarse a prestar juramento el primer día hábil posterior a la integración de las Cámaras. Igual comunicación se hará al Gobernador de la Provincia.`, plainLanguageExplanation: 'Tras la aceptación, el Presidente de la Asamblea Legislativa notifica a los electos la hora del juramento, que tendrá lugar el primer día hábil posterior a la integración de las Cámaras con los nuevos legisladores.', practicalEffects: ['La asunción se sincroniza con la integración de las nuevas Cámaras para que la transición política sea completa', 'El Presidente de la Asamblea coordina la logística institucional del acto de jura'], examples: ['El día de la asunción, los nuevos legisladores electos también prestan juramento ante la Asamblea Legislativa reunida. De ese modo, el nuevo Gobernador asume ante un cuerpo legislativo ya renovado, garantizando la continuidad institucional entre Ejecutivo y Legislativo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juramento', 'integración de Cámaras', 'asunción de cargo', 'Presidente de la Asamblea'], order: 140, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-141', lawId: 'const-buenos-aires', number: '141', title: '', text: `Corresponde a la Asamblea Legislativa conocer en las renuncias del Gobernador y Vicegobernador electos.`, plainLanguageExplanation: 'La Asamblea Legislativa es el órgano competente para conocer y resolver sobre las renuncias presentadas por el Gobernador y el Vicegobernador electos antes de asumir sus cargos.', practicalEffects: ['La Asamblea puede aceptar o rechazar la renuncia de los electos antes de la asunción', 'Este mecanismo preserva la continuidad institucional ante una renuncia sorpresiva en el período preposesorio'], examples: ['El Gobernador electo, antes de asumir, renuncia por razones personales. La Asamblea Legislativa debe resolver quién asume la gobernación: generalmente el Vicegobernador electo toma la titularidad del Ejecutivo, y si este también renuncia, se activa la cadena de suplencia constitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['renuncia Gobernador electo', 'Asamblea Legislativa', 'período preposesorio', 'acefalía'], order: 141, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-142', lawId: 'const-buenos-aires', number: '142', title: '', text: `Aceptadas que sean las renuncias del Gobernador y Vicegobernador electos, se reunirá la Asamblea Legislativa y designará Gobernador interino en las condiciones y por el tiempo establecido en el artículo 126. Pero si sólo hubiese sido aceptada la renuncia del Gobernador electo o del Vicegobernador electo, aquél de los dos que no hubiese renunciado, o cuya renuncia no hubiese sido aceptada, prestará juramento y se hará cargo del Poder Ejecutivo, sin que se proceda a realizar una nueva elección.`, plainLanguageExplanation: 'Si ambos electos renuncian, la Asamblea designa un Gobernador interino. Si solo renuncia uno, el otro asume solo, sin nueva elección. Se aplican las reglas del art. 126 para la designación interina.', practicalEffects: ['Si solo renuncia el Gobernador electo, el Vicegobernador electo asume como Gobernador sin necesidad de nueva elección', 'La Asamblea actúa como garante de continuidad cuando ambos cargos quedan vacantes antes de la asunción'], examples: ['Tanto el Gobernador electo como el Vicegobernador electo renuncian antes de asumir el cargo. La Asamblea Legislativa interviene de urgencia y designa un Gobernador interino que conduce la Provincia hasta que nuevas elecciones elijan a las autoridades definitivas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['renuncia antes de asumir', 'Gobernador interino', 'Asamblea Legislativa', 'vacante doble'], order: 142, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-143', lawId: 'const-buenos-aires', number: '143', title: '', text: `Una vez aceptado el cargo, el Gobernador y Vicegobernador electos gozarán de las mismas inmunidades personales de los senadores y diputados.`, plainLanguageExplanation: 'Desde que aceptan el cargo, el Gobernador y el Vicegobernador electos gozan de las mismas inmunidades personales que los senadores y diputados provinciales.', practicalEffects: ['Los electos quedan protegidos por inmunidad de arresto e inviolabilidad de opiniones desde la aceptación del cargo', 'Esta protección evita maniobras para impedir la asunción mediante causas penales o detenciones'], examples: ['Desde el día en que es proclamado, el Gobernador electo goza de fuero personal: no puede ser detenido ni sometido a proceso penal sin desafuero. Si hay una causa judicial en curso contra él, esta queda suspendida hasta que asuma y luego se resuelva el desafuero, si correspondiera.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inmunidades', 'Gobernador electo', 'inviolabilidad', 'fuero personal'], order: 143, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-144', lawId: 'const-buenos-aires', number: '144', title: '', text: `El Gobernador es el jefe de la administración de la Provincia, y tiene las siguientes atribuciones: 1°Nombrar y remover los ministros secretarios del despacho. 2° Promulgar y hacer ejecutar las leyes de la Provincia, facilitando su ejecución por reglamentos y disposiciones especiales que no alteren su espíritu. 3° Concurrir a la formación de las leyes, con arreglo a la Constitución, teniendo el derecho de iniciarlas por proyectos presentados a las Cámaras, y de tomar parte en su discusión por medio de los ministros. 4° El Gobernador podrá conmutar las penas impuestas por delitos sujetos a la jurisdicción provincial, previo informe motivado de la Suprema Corte de Justicia, sobre la oportunidad y conveniencia dela conmutación y con arreglo a la ley reglamentaria que determinará los casos y la forma en que pueda solicitarse, debiendo ponerse en conocimiento de la Asamblea Legislativa, las razones que hayan motivado en cada caso la conmutación de la pena. El Gobernador no podrá ejercer esta atribución cuando se trate de delitos en que el Senado conoce como juez, y de aquéllos cometidos por funcionarios públicos en el ejercicio de sus funciones. 5° Ejercerá los derechos de patronato como vicepatrono, hasta que el Congreso Nacional, en uso de la atribución que le confiere el artículo 67, inciso 19 de la Constitución de la República, dicte la ley de la materia. 6° A la apertura de la Legislatura la informará del estado genera de la administración. 7° Convocar al pueblo de la Provincia a todas las elecciones en la oportunidad debida, sin que por ningún motivo pueda diferirlas. 8° Convocar a sesiones extraordinarias a la Legislatura o a cualquiera de las Cámaras, cuando lo exija un grande interés público, salvo el derecho del cuerpo convocado para apreciar y decidir después de reunido, sobre los fundamentos de la convocatoria. 9° Hacer recaudar las rentas de la Provincia y decretar su inversión con arreglo a las leyes, debiendo hacer publicar mensualmente el estado de la Tesorería. 10° Celebrar y firmar tratados parciales con otras provincias para fines de la administración de justicia, de intereses económicos y trabajos de utilidad común, con aprobación de la Legislatura y dando conocimiento al Congreso Nacional. 11° Es el comandante en jefe de las fuerzas militares de la Provincia, con excepción de aquéllas que hayan sido movilizadas para objetos nacionales. 12° Movilizar la milicia provincial en caso de conmoción interior que ponga en peligro la seguridad de la Provincia, el receso, dando cuenta en las próximas sesiones, sin perjuicio de hacerlo inmediatamente a la autoridad nacional. 13° Decretar también la movilización de las milicias, en los casos previstos por el inciso vigésimo cuarto, artículo sesenta y siete dela Constitución Nacional. 14° Expedir despachos a los oficiales que nombre para organizar la milicia de la Provincia y para poner en ejercicio las facultades acordadas en los dos incisos que preceden. En cuanto a los jefes, expide también despachos hasta teniente coronel. Para dar el de coronel se requiere el acuerdo del Senado. 15° Es agente inmediato y directo del Gobierno Nacional para hacer cumplir en la Provincia la Constitución y las leyes de la Nación. 16° Da cuenta a las Cámaras Legislativas del estado de la hacienda y de la inversión de los fondos votados para el ejercicio precedente y remite antes del 31 de agosto los proyectos de presupuesto de la administración y las leyes de recursos. 17° No podrá acordar goce de sueldo o pensión sino por alguno de los títulos que las leyes expresamente determinan. 18° Nombra, con acuerdo del Senado: 1° El Fiscal del Estado; 2° El Director General de Cultura y Educación; 3° El Presidente y los vocales del Tribunal de Cuentas; 4° El Presidente y los directores del Banco de la Provincia que le corresponda designar. Y con acuerdo de la Cámara de Diputados, los miembros del Consejo General de Cultura y Educación. La ley determinará en los casos no previstos por esta Constitución, la duración de estos funcionarios, debiendo empezar el 1° de junio sus respectivos períodos.`, plainLanguageExplanation: 'El Gobernador dirige la administración provincial con amplias atribuciones: nombra ministros, promulga y reglamenta leyes, convoca elecciones, conduce las fuerzas militares, administra la hacienda, y actúa como agente del gobierno federal en la Provincia.', practicalEffects: ['El Gobernador puede conmutar penas provinciales previo informe de la Suprema Corte', 'Los nombramientos de los funcionarios más importantes (Fiscal del Estado, vocales del Tribunal de Cuentas) requieren acuerdo del Senado'], examples: ['El Gobernador recibe la ley de presupuesto aprobada, la promulga y dicta el decreto reglamentario que especifica los procedimientos de ejecución del gasto. Simultáneamente, convoca a la Legislatura a sesiones extraordinarias por una crisis fiscal y conmuta la pena de un condenado previo informe de la Suprema Corte: todo ello son atribuciones que este artículo le asigna expresamente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribuciones Gobernador', 'administración provincial', 'jefe del Ejecutivo', 'conmutación de penas'], order: 144, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-145', lawId: 'const-buenos-aires', number: '145', title: '', text: `No puede expedir órdenes y decretos sin la firma del ministro respectivo. Podrá no obstante, expedirlos en caso de acefalía de ministros y mientras se provea a su nombramiento, autorizando a los oficiales mayores de los ministerios por un decreto especial. Los oficiales mayores en estos casos, quedan sujetos a las responsabilidades de los ministros.`, plainLanguageExplanation: 'El Gobernador no puede expedir órdenes ni decretos sin la firma del ministro del ramo correspondiente. En caso de acefalía ministerial puede autorizar al oficial mayor del ministerio para firmar por decreto especial.', practicalEffects: ['El refrendo ministerial es requisito de validez de los actos del Ejecutivo: sin firma de ministro no tienen efecto', 'El oficial mayor que refrenda queda sujeto a la misma responsabilidad que el ministro titular'], examples: ['El Gobernador dicta un decreto que reorganiza el organigrama de la Dirección de Vialidad. El decreto debe ser firmado también por el Ministro de Infraestructura: sin ese refrendo, el acto carece de validez formal y puede ser impugnado judicialmente por cualquier afectado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['refrendo ministerial', 'decretos ejecutivos', 'co-firma', 'acefalía ministerial'], order: 145, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-146', lawId: 'const-buenos-aires', number: '146', title: '', text: `Estando las Cámaras reunidas, la propuesta de funcionarios que requieren para su nombramiento el acuerdo del Senado o de la Cámara de Diputados, se hará dentro de los quince días de ocurrida la vacante, no pudiendo el Poder Ejecutivo insistir sobre un candidato rechazado por el Senado o la Cámara de Diputados en su caso, durante ese año. En el receso, la propuesta se hará dentro del mismo término, convocándose extraordinariamente, al efecto, a la Cámara respectiva. Ninguno de los funcionarios para cuyo nombramiento se requiere el acuerdo o propuesta por terna de alguna de las Cámaras, podrá ser removido sin el mismo requisito. Exceptúanse los funcionarios para cuya remoción esta Constitución establece un procedimiento especial.`, plainLanguageExplanation: 'El Ejecutivo debe proponer los funcionarios que requieren acuerdo legislativo dentro de los quince días de producida la vacante. El Poder Ejecutivo no puede insistir con un candidato rechazado por el Senado durante ese año. Los funcionarios con acuerdo no pueden ser removidos sin el mismo trámite.', practicalEffects: ['El Senado actúa como contrapeso en los nombramientos clave del Ejecutivo', 'La prohibición de insistir protege la autoridad del Senado como cámara de revisión de designaciones'], examples: ['El Gobernador quiere designar al nuevo Fiscal de Estado. Eleva la propuesta al Senado, que tiene 15 días para dar acuerdo. Si el Senado no se expide en ese plazo, el Gobernador puede dar por concedido el acuerdo tácitamente y proceder a la designación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acuerdo del Senado', 'designaciones ejecutivas', 'remoción', 'plazo quince días'], order: 146, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-147', lawId: 'const-buenos-aires', number: '147', title: '', text: `El despacho de los negocios administrativos de la Provincia estará a cargo de dos o más ministros secretarios, y una ley especial deslindará los ramos y las funciones adscriptas al despacho de cada uno de los ministerios.`, plainLanguageExplanation: 'Los negocios administrativos de la Provincia son conducidos por al menos dos ministros secretarios, y la ley determina los ramos y funciones de cada ministerio.', practicalEffects: ['La ley puede crear, fusionar o suprimir ministerios sin necesidad de reforma constitucional', 'La Constitución garantiza como mínimo dos ministerios, evitando la concentración unipersonal del despacho'], examples: ['La Legislatura sanciona una ley que reorganiza los ministerios: divide el Ministerio de Salud en dos secretarías autónomas. El Gobernador debe adaptar su gabinete a esa estructura; no puede mantener un ministerio que la ley suprimió ni crear uno nuevo sin autorización legislativa.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ministerios', 'despacho administrativo', 'estructura ejecutiva', 'secretarios de Estado'], order: 147, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-148', lawId: 'const-buenos-aires', number: '148', title: '', text: `Para ser nombrado ministro se requieren las mismas condiciones que esta Constitución determina para ser elegido diputado.`, plainLanguageExplanation: 'Para ser ministro se requieren las mismas condiciones que para ser diputado provincial: ser argentino, mayor de 22 años y tener residencia en la Provincia.', practicalEffects: ['Los mismos requisitos democráticos que habilitan a ser legislador aplican al cargo de ministro', 'La Constitución exige un mínimo de idoneidad cívica para el ejercicio de la función ministerial'], examples: ['Un candidato a Ministro de Economía tiene 27 años y es ciudadano argentino naturalizado hace 3 años, sin los 6 años de ciudadanía requeridos para ser diputado. Aunque tenga gran idoneidad técnica, no cumple los requisitos constitucionales para ser ministro y no puede ser designado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos ministro', 'condiciones diputado', 'idoneidad', 'ministros secretarios'], order: 148, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-149', lawId: 'const-buenos-aires', number: '149', title: '', text: `Los ministros secretarios despacharán de acuerdo con el Gobernador y refrendarán con su firma las resoluciones de éste, sin cuyo requisito no tendrán efecto ni se les dará cumplimiento. Podrán, no obstante, expedirse por sí solos todo lo referente al régimen económico de sus respectivos departamentos y dictar resoluciones de trámite.`, plainLanguageExplanation: 'Los ministros despachan junto con el Gobernador y deben refrendar con su firma todos sus actos, sin cuya firma los actos carecen de validez. Pueden actuar solos solo en materia administrativa de sus propios departamentos.', practicalEffects: ['Las resoluciones del Gobernador sin firma ministerial son nulas e inaplicables', 'El ministro tiene autonomía para resolver trámites internos de su ministerio sin necesidad de que el Gobernador firme'], examples: ['El Gobernador firma un decreto de emergencia hídrica. El Ministro de Infraestructura, cuya cartera está involucrada, debe también firmarlo. Si el ministro se niega, el Gobernador puede reemplazarlo por quien acepte el refrendo: sin firma ministerial, el decreto no puede ejecutarse.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['refrendo', 'firma ministerial', 'validez actos ejecutivos', 'despacho ministerial'], order: 149, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-150', lawId: 'const-buenos-aires', number: '150', title: '', text: `Serán responsables de todas las órdenes y resoluciones que autorice, sin que puedan pretender eximirse de responsabilidad por haber procedido en virtud de orden del Gobernador.`, plainLanguageExplanation: 'Los ministros son personalmente responsables de todos los actos que autoricen con su firma, sin poder excusarse alegando que actuaron por orden del Gobernador.', practicalEffects: ['La orden del Gobernador no exime de responsabilidad al ministro: la firma implica responsabilidad propia', 'Este principio evita que los ministros actúen como meros ejecutores sin responsabilidad personal'], examples: ['La Legislatura investiga un decreto de obras públicas presuntamente irregular. Cita al Ministro de Infraestructura, quien debe responder por su refrendo: al co-firmar el decreto, asumió co-responsabilidad política y jurídica por el acto, y no puede excusarse alegando solo haber obedecido al Gobernador.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad ministerial', 'co-responsabilidad', 'actos del Ejecutivo', 'rendición de cuentas'], order: 150, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-151', lawId: 'const-buenos-aires', number: '151', title: '', text: `En los treinta días posteriores a la apertura del período legislativo, los ministros presentarán a la Asamblea la memoria detallada del estado de la administración correspondiente a cada uno de los ministerios, indicando en ellas las reformas que más aconsejen la experiencia y el estudio.`, plainLanguageExplanation: 'Dentro de los 30 días de iniciado el período legislativo, cada ministro debe presentar a la Asamblea una memoria detallada del estado de su ministerio, incluyendo las reformas que recomienda.', practicalEffects: ['La memoria ministerial es un mecanismo de rendición de cuentas ante el Poder Legislativo', 'Las propuestas de reforma incluidas en la memoria pueden convertirse en proyectos de ley'], examples: ['Al inicio del período legislativo, el Ministro de Educación presenta ante la Asamblea Legislativa la memoria anual de su cartera: detalla las obras realizadas, el presupuesto ejecutado, los programas implementados y los resultados obtenidos durante el año anterior.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['memoria ministerial', 'rendición de cuentas', 'Asamblea Legislativa', 'administración provincial'], order: 151, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-152', lawId: 'const-buenos-aires', number: '152', title: '', text: `Los ministros pueden concurrir a las sesiones de las Cámaras y tomar parte en las discusiones, pero no tendrán voto.`, plainLanguageExplanation: 'Los ministros pueden asistir a las sesiones de las Cámaras y participar en los debates, pero carecen de derecho a voto, ya que no son miembros del Poder Legislativo.', practicalEffects: ['Los ministros pueden defender proyectos oficiales directamente ante las Cámaras, fortaleciendo la comunicación entre poderes', 'La prohibición de votar preserva la distinción entre Ejecutivo y Legislativo'], examples: ['El Ministro de Seguridad asiste a una sesión de la Cámara de Diputados para exponer sobre un proyecto de reforma policial. Puede hablar, responder preguntas y argumentar, pero no puede votar el proyecto: su presencia es de información y coordinación, no de co-legislación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ministros en sesiones', 'asistencia legislativa', 'sin voto', 'separación de poderes'], order: 152, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-153', lawId: 'const-buenos-aires', number: '153', title: '', text: `Gozarán por sus servicios de un sueldo establecido por la ley, que no podrá ser aumentado ni disminuido en favor o en perjuicio de los que se hallen en ejercicio.`, plainLanguageExplanation: 'Los ministros cobran el sueldo que fija la ley, el cual no puede ser aumentado ni reducido mientras estén en ejercicio del cargo.', practicalEffects: ['La inamovilidad del sueldo protege la independencia de los ministros frente a presiones presupuestarias', 'El Legislativo no puede recortar el sueldo de un ministro en ejercicio para forzar su renuncia'], examples: ['La Legislatura no puede reducir el sueldo de los ministros durante su gestión como medida de presión política. Esto garantiza que los ministros ejerzan sus funciones sin depender de la voluntad del Legislativo para su sustento económico, preservando la independencia del Ejecutivo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sueldo ministros', 'inamovilidad salarial', 'independencia ministerial', 'remuneración'], order: 153, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-154', lawId: 'const-buenos-aires', number: '154', title: '', text: `El Gobernador y los ministros son responsables y pueden ser acusados ante el Senado, en la forma establecida en la sección del "Poder Legislativo", por las causas que determina el inciso 2° del artículo 73 de esta Constitución y por abuso de su posición oficial para realizar especulaciones de comercio.`, plainLanguageExplanation: 'El Gobernador y los ministros son políticamente responsables y pueden ser acusados ante el Senado por mal desempeño, delitos en el ejercicio de sus funciones y uso indebido de su cargo para especulaciones comerciales.', practicalEffects: ['El juicio político permite destituir al Gobernador sin necesidad de proceso penal ordinario', 'El aprovechamiento de la posición oficial para comerciar constituye causal autónoma de destitución'], examples: ['Un Gobernador que firmó contratos irregulares perjudicando al erario puede ser sometido a juicio político por mal desempeño. La Cámara de Diputados lo acusa, el Senado lo juzga y, si lo condena, queda destituido y habilitado para responder penalmente ante la justicia ordinaria.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad del Gobernador', 'juicio político', 'destitución', 'mal desempeño'], order: 154, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-155', lawId: 'const-buenos-aires', number: '155', title: '', text: `Habrá un Fiscal de Estado inamovible, encargado de defender el patrimonio del Fisco, que será parte legítima en los juicios contencioso-administrativos y en todos aquéllos en que se controviertan intereses del Estado. La ley determinará los casos y la forma en que ha de ejercer sus funciones. Para desempeñar este puesto se requieren las mismas condiciones exigidas para los miembros de la Suprema Corte de Justicia.`, plainLanguageExplanation: 'El Fiscal de Estado es inamovible y defiende el patrimonio del Fisco provincial, siendo parte legítima en los juicios contencioso-administrativos y en todo litigio donde esté en juego un interés del Estado.', practicalEffects: ['El Fiscal de Estado actúa como abogado del Estado provincial en los juicios que lo involucran', 'La inamovilidad lo protege frente a presiones políticas para que no defienda los intereses del Fisco'], examples: ['Una empresa demanda a la Provincia reclamando el cobro de una deuda por obras ejecutadas. El Fiscal de Estado interviene en el proceso representando y defendiendo los intereses del Estado provincial, debiendo velar por la legalidad de los actos del Ejecutivo y la integridad del patrimonio público.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Fiscal de Estado', 'defensa del Fisco', 'contencioso-administrativo', 'inamovilidad'], order: 155, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-156', lawId: 'const-buenos-aires', number: '156', title: '', text: `El Contador y Subcontador, el Tesorero y Subtesorero serán nombrados en la forma prescripta en el artículo 82 y durarán cuatro años, pudiendo ser reelectos.`, plainLanguageExplanation: 'El Contador, Subcontador, Tesorero y Subtesorero son designados por la Legislatura y tienen mandatos de cuatro años, pudiendo ser reelectos.', practicalEffects: ['Los cargos de control de la hacienda provincial tienen estabilidad temporal para actuar con independencia del Ejecutivo', 'La reelección permite la continuidad técnica en la gestión financiera del Estado'], examples: ['El Contador y el Tesorero provinciales son designados por el Poder Ejecutivo pero ejercen funciones de control financiero independiente. Ningún pago puede efectuarse sin la autorización del Contador ni sin la firma del Tesorero, creando un doble control sobre la hacienda provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Contador', 'Tesorero', 'hacienda provincial', 'control financiero'], order: 156, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-157', lawId: 'const-buenos-aires', number: '157', title: '', text: `El Contador y Subcontador no podrán autorizar pago alguno que no sea arreglado a la ley general de presupuesto o a leyes especiales, o en los casos del artículo 163.`, plainLanguageExplanation: 'El Contador solo puede autorizar pagos que estén previstos en la ley de presupuesto o en leyes especiales, actuando como control previo de legalidad del gasto público.', practicalEffects: ['Ningún pago puede realizarse sin previa autorización del Contador, que verifica su respaldo legal', 'El Contador actúa como primer filtro de legalidad presupuestaria antes de que el Tesorero ejecute el pago'], examples: ['El Ministerio de Obras Públicas solicita al Contador Provincial autorización para pagar una factura de $50 millones a un contratista. El Contador verifica que el gasto tenga partida presupuestaria y que el procedimiento licitatorio sea correcto; si detecta irregularidades, puede negarse a autorizar el pago.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Contador Provincial', 'autorización de pagos', 'presupuesto', 'control previo'], order: 157, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-158', lawId: 'const-buenos-aires', number: '158', title: '', text: `El Tesorero no podrá ejecutar pagos que no hayan sido previamente autorizados por el Contador.`, plainLanguageExplanation: 'El Tesorero solo puede efectuar pagos que hayan sido previamente autorizados por el Contador, estableciendo un sistema de doble control sobre el gasto público provincial.', practicalEffects: ['El doble control Contador-Tesorero previene pagos ilegales o no presupuestados', 'El Tesorero no tiene discrecionalidad: ejecuta solo lo que el Contador aprobó previamente'], examples: ['Una orden de pago llega a la Tesorería provincial. Aunque el Contador ya la autorizó, el Tesorero realiza su propio control: verifica disponibilidad de fondos y la legalidad del egreso. Con ambas firmas —Contador y Tesorero— el pago se efectiviza válidamente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Tesorero', 'control de pagos', 'doble firma', 'hacienda pública'], order: 158, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-159', lawId: 'const-buenos-aires', number: '159', title: '', text: `La Legislatura dictará la ley orgánica del Tribunal de Cuentas. Este se compondrá de un presidente abogado y cuatro vocales contadores públicos, todos inamovibles, nombrados por el Poder Ejecutivo con acuerdo del Senado. Podrán ser enjuiciados y removidos en la misma forma y en los mismos casos que los jueces de las Cámaras de Apelación. Dicho tribunal tendrá las siguientes atribuciones: 1° Examinar las cuentas de percepción e inversión de las rentas públicas, tanto provinciales como municipales, aprobarlas o desaprobarlas y en este último caso, indicar el funcionario o funcionarios responsables, como también el monto y la causa de los alcances respectivos. 2° Inspeccionar las oficinas provinciales o municipales que administren fondos públicos y tomar las medidas necesarias para prevenir cualquier irregularidad en la forma y con arreglo al procedimiento que determine la ley. Las acciones para la ejecución de las resoluciones del Tribunal corresponderán al Fiscal de Estado.`, plainLanguageExplanation: 'El Tribunal de Cuentas, integrado por un presidente abogado y cuatro vocales contadores inamovibles, examina las cuentas provinciales y municipales, aprueba o desaprueba inversiones e inspecciona organismos que manejan fondos públicos.', practicalEffects: ['El Tribunal de Cuentas puede desaprobar gastos y señalar responsables de irregularidades financieras', 'La inamovilidad de sus miembros garantiza independencia frente al Ejecutivo que los nombró'], examples: ['El Tribunal de Cuentas audita el balance del ejercicio anterior del Ministerio de Salud y detecta gastos sin respaldo documental. Puede formular reparos, exigir rendición de cuentas a los funcionarios responsables y, si hay mérito suficiente, remitir las actuaciones a la justicia penal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Tribunal de Cuentas', 'control financiero', 'cuentas provinciales', 'inamovilidad'], order: 159, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-160', lawId: 'const-buenos-aires', number: '160', title: '', text: `El Poder Judicial será desempeñado por una Suprema Corte de Justicia, Cámaras de Apelación, Jueces y demás Tribunales que la ley establezca.`, plainLanguageExplanation: 'El Poder Judicial provincial está integrado por la Suprema Corte de Justicia, Cámaras de Apelación, jueces de primera instancia y demás tribunales que la ley cree, garantizando la existencia de una estructura jerárquica de justicia.', practicalEffects: ['La estructura del Poder Judicial puede ampliarse por ley ordinaria sin necesidad de reforma constitucional', 'La Suprema Corte es la cúspide del sistema judicial provincial con facultad de control constitucional'], examples: ['En Buenos Aires, el Poder Judicial es independiente del Ejecutivo y del Legislativo. La Suprema Corte es el máximo tribunal provincial, pero coexiste con cámaras de apelación, juzgados de primera instancia, tribunales de familia, laborales y penales, todos parte del mismo Poder Judicial organizado por ley.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Poder Judicial', 'Suprema Corte', 'organización judicial', 'tribunales provinciales'], order: 160, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-161', lawId: 'const-buenos-aires', number: '161', title: '', text: `La Suprema Corte de Justicia tiene las siguientes atribuciones: 1° Ejerce la jurisdicción originaria y de apelación para conocer y resolver acerca de la constitucionalidad o inconstitucionalidad de leyes, decretos, ordenanzas o reglamentos que estatuyan sobre materia regida por esta Constitución y se controvierta por parte interesada. 2° Conoce y resuelve originaria y exclusivamente en las causas de competencia entre los poderes públicos de la Provincia y en las que se susciten entre los tribunales de justicia con motivo de su jurisdicción respectiva. 3° Conoce y resuelve en grado de apelación: a) De la aplicabilidad de la ley en que los tribunales de justicia en última instancia, funden su sentencia sobre la cuestión que por ella deciden, con las restricciones que las leyes de procedimientos establezcan a esta clase de recursos; b) De la nulidad arguída contra las sentencias definitivas pronunciadas en última instancia por los tribunales de justicia, cuando se alegue violación de las normas contenidas en los artículos 168 y 171 de esta Constitución. 4° Nombra y remueve directamente los secretarios y empleados del tribunal, y a propuesta de los jueces de primera instancia, funcionarios del ministerio público y jueces de paz, el personal de sus respectivas dependencias.`, plainLanguageExplanation: 'La Suprema Corte de Justicia ejerce jurisdicción originaria para resolver cuestiones de constitucionalidad, conflictos entre poderes públicos y recursos de apelación sobre la aplicación de la ley o nulidad de sentencias definitivas.', practicalEffects: ['Las personas pueden impugnar la constitucionalidad de normas directamente ante la Suprema Corte en ciertos casos', 'La Suprema Corte resuelve los conflictos de competencia entre tribunales del fuero provincial'], examples: ['Un municipio demanda a la Provincia por considerar inconstitucional una ley que recorta la coparticipación. La causa llega directamente a la Suprema Corte de Justicia bonaerense por competencia originaria, ya que involucra un conflicto entre el Estado provincial y un municipio sobre normas de rango constitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Suprema Corte', 'inconstitucionalidad', 'jurisdicción originaria', 'conflictos de competencia'], order: 161, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-162', lawId: 'const-buenos-aires', number: '162', title: '', text: `La presidencia de la Suprema Corte de Justicia, se turnará anualmente entre sus miembros, principiando por el de mayor edad.`, plainLanguageExplanation: 'La presidencia de la Suprema Corte rota anualmente entre sus miembros comenzando por el de mayor edad, garantizando que el liderazgo del tribunal sea compartido y no vitalicio en cabeza de un solo juez.', practicalEffects: ['La presidencia rotatoria previene la concentración de poder interno en manos de un solo miembro del tribunal', 'El criterio de antigüedad por edad es objetivo y evita disputas internas sobre quién debe presidir'], examples: ['La Suprema Corte bonaerense tiene 7 miembros. La presidencia del tribunal rota cada año entre sus miembros siguiendo el criterio de mayor edad, lo que evita que un mismo juez concentre indefinidamente el liderazgo del tribunal y distribuye esa responsabilidad entre todos sus integrantes.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presidencia Suprema Corte', 'rotación anual', 'mayor edad', 'gobierno del tribunal'], order: 162, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-163', lawId: 'const-buenos-aires', number: '163', title: '', text: `La Suprema Corte de Justicia, al igual que los restantes tribunales, dispone de la fuerza pública necesaria para el cumplimiento de sus decisiones. En las causas contencioso-administrativas, aquélla y los demás tribunales competentes estarán facultados para mandar a cumplir directamente sus sentencias por las autoridades o empleados correspondientes si el obligado no lo hiciere en el plazo de sesenta días de notificadas. Los empleados o funcionarios a que alude este artículo serán responsables por el incumplimiento de las decisiones judiciales.`, plainLanguageExplanation: 'La Suprema Corte y demás tribunales disponen de la fuerza pública para hacer cumplir sus decisiones. En causas contencioso-administrativas, pueden ordenar directamente a las autoridades que ejecuten las sentencias si el obligado no lo hace en 60 días.', practicalEffects: ['Los jueces pueden ordenar a funcionarios públicos que cumplan sus sentencias bajo pena de responsabilidad', 'Los funcionarios que incumplen sentencias judiciales incurren en responsabilidad personal'], examples: ['La Suprema Corte condena a la Provincia a pagar una indemnización por expropiación irregular. El Gobernador demora el pago. El tribunal puede intimar al Ejecutivo y, en última instancia, disponer medidas de ejecución forzada; el funcionario que obstruya el cumplimiento incurre en responsabilidad personal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cumplimiento de sentencias', 'fuerza pública', 'contencioso-administrativo', 'responsabilidad funcionarios'], order: 163, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-164', lawId: 'const-buenos-aires', number: '164', title: '', text: `La Suprema Corte de Justicia hará su reglamento y podrá establecer las medidas disciplinarias que considere conveniente a la mejor administración de justicia.`, plainLanguageExplanation: 'La Suprema Corte de Justicia dicta su propio reglamento interno y puede establecer medidas disciplinarias para garantizar la correcta administración de justicia en todo el fuero provincial.', practicalEffects: ['La autonomía reglamentaria de la Suprema Corte asegura su independencia del Poder Ejecutivo en la organización interna', 'Las medidas disciplinarias permiten a la Corte sancionar conductas que afecten el funcionamiento del sistema judicial'], examples: ['La Suprema Corte dicta su propio reglamento interno que regula las licencias de los jueces, los horarios de despacho y los criterios de distribución de causas, sin necesidad de aprobación del Ejecutivo ni del Legislativo. Esta potestad reglamentaria es una garantía de la independencia judicial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglamento Suprema Corte', 'autonomía judicial', 'disciplina judicial', 'autogobierno'], order: 164, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-165', lawId: 'const-buenos-aires', number: '165', title: '', text: `Debe pasar anualmente a la Legislatura una memoria o informa sobre el estado en que se halla dicha administración, a cuyo efecto puede pedir a los demás tribunales de la Provincia los datos que crea convenientes y proponer en forma de proyecto las reformas de procedimiento y organización que sean compatibles con lo estatuido en esta Constitución y tiendan a mejorarla.`, plainLanguageExplanation: 'La Suprema Corte debe enviar anualmente a la Legislatura una memoria o informe sobre el estado de la administración de justicia, y puede proponer proyectos de reforma del procedimiento judicial.', practicalEffects: ['La memoria anual de la Suprema Corte es un instrumento de rendición de cuentas del Poder Judicial al Legislativo', 'La Corte puede proponer reformas procesales, pero es la Legislatura quien las convierte en ley'], examples: ['La Suprema Corte presenta su memoria anual a la Legislatura, informando sobre el estado del servicio de justicia: tiempos promedio de resolución de causas, cantidad de juicios iniciados, cuellos de botella procesales y propuestas de reforma legislativa para mejorar el acceso a la justicia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['memoria judicial', 'Suprema Corte', 'reforma procesal', 'rendición de cuentas'], order: 165, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-166', lawId: 'const-buenos-aires', number: '166', title: '', text: `La Legislatura establecerá tribunales de justicia determinando los límites de su competencia territorial, los fueros, las materias y, en su caso, la cuantía. Organizará la Policía Judicial. Asimismo podrá establecer una instancia de revisión judicial especializada en materia de faltas municipales. Podrá disponer la supresión o transformación de tribunales, sin perjuicio de lo dispuesto por el artículo 176 y la creación de un cuerpo de magistrados suplentes, designados conforme al artículo 175 de esta Constitución, del que dispondrá la Suprema Corte de Justicia para cubrir vacantes transitorias. La ley establecerá un procedimiento expeditivo de queja por retardo de justicia. Los casos originados por la actuación u omisión de la Provincia, los municipios, los entes descentralizados y otras personas, en el ejercicio de funciones administrativas, serán juzgados por tribunales competentes en lo contencioso administrativo, de acuerdo a los procedimientos que determine la ley, la que establecerá los supuestos en que resulte obligatorio agotar la vía administrativa.`, plainLanguageExplanation: 'La Legislatura organiza los tribunales de justicia, define su competencia territorial, por materia y cuantía, y puede crear fueros especializados como el contencioso-administrativo para litigios contra el Estado.', practicalEffects: ['Las causas contra el Estado provincial, municipios y entes descentralizados son resueltas por tribunales especializados en lo contencioso-administrativo', 'La Policía Judicial depende del Poder Judicial y no del Ejecutivo, garantizando su independencia'], examples: ['La Legislatura crea una cámara de apelaciones en lo contencioso-administrativo en La Plata y otra en Mar del Plata para descongestionar la justicia administrativa. También organiza la Policía Judicial como cuerpo autónomo bajo supervisión del Poder Judicial, asegurando que las investigaciones penales no dependan de la policía del Ejecutivo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['organización judicial', 'fuero contencioso-administrativo', 'competencia territorial', 'Policía Judicial'], order: 166, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-167', lawId: 'const-buenos-aires', number: '167', title: '', text: `Corresponde a las Cámaras de Apelación el nombramiento y remoción de los secretarios y empleados de dependencia.`, plainLanguageExplanation: 'Las Cámaras de Apelación tienen autonomía para nombrar y remover a su propio personal administrativo (secretarios y empleados), reforzando la independencia interna del Poder Judicial.', practicalEffects: ['Los jueces de Cámara no dependen del Ejecutivo para designar a su personal de apoyo', 'Esta autonomía de recursos humanos es parte del autogobierno del Poder Judicial provincial'], examples: ['La Cámara de Apelaciones en lo Civil y Comercial de La Plata designa a sus propios secretarios y empleados de acuerdo con su reglamento interno. No necesita autorización del Ejecutivo para ello: la facultad de nombrar su propio personal es parte de la autonomía que la Constitución le otorga al Poder Judicial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Cámaras de Apelación', 'autogobierno judicial', 'nombramiento personal', 'independencia judicial'], order: 167, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-168', lawId: 'const-buenos-aires', number: '168', title: '', text: `Los tribunales de justicia deberán resolver todas las cuestiones que le fueren sometidas por las partes, en la forma y plazos establecidos al efecto por las leyes procesales. Los jueces que integran los tribunales colegiados, deberán dar su voto en todas las cuestiones esenciales a decidir. Para que exista sentencia debe concurrir mayoría de opiniones acerca de cada una de ellas.`, plainLanguageExplanation: 'Los tribunales deben resolver todas las cuestiones planteadas por las partes en los plazos fijados por la ley. En tribunales colegiados, cada juez debe votar en todas las cuestiones esenciales y la sentencia requiere mayoría.', practicalEffects: ['Un juez de cámara no puede abstenerse de votar: el voto es obligatorio en las cuestiones esenciales del caso', 'La exigencia de mayoría para sentenciar evita que decisiones importantes se tomen sin suficiente consenso judicial'], examples: ['En un tribunal de tres jueces, uno de ellos no puede abstenerse de votar argumentando que no estudió el expediente: la Constitución obliga a todos los miembros a emitir su voto. La sentencia se forma con la mayoría de los votos emitidos, garantizando que siempre haya una decisión definitiva.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['voto obligatorio jueces', 'tribunales colegiados', 'mayoría', 'sentencias'], order: 168, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-169', lawId: 'const-buenos-aires', number: '169', title: '', text: `Los procedimientos ante los tribunales son públicos; sus acuerdos y sentencia se redactarán en los libros que deben llevar y custodiar; y en los autos de las causas en que conocen, y publicarse en sus salas respectivas de audiencia, a menos que a juicio del tribunal ante quien penden, la publicidad sea peligrosa para las buenas costumbres, en cuyo caso debe declararlo así por medio de un auto.`, plainLanguageExplanation: 'Los procedimientos judiciales son públicos y las sentencias se publican en las salas de audiencia, salvo resolución fundada del tribunal cuando la publicidad sea perjudicial para las buenas costumbres.', practicalEffects: ['El principio de publicidad judicial garantiza que los ciudadanos puedan acceder a las actuaciones y sentencias', 'Solo por excepción fundada puede limitarse la publicidad en causas donde esté en riesgo la moral pública'], examples: ['Un ciudadano solicita acceder al expediente de un proceso civil entre dos empresas. Como el proceso es público, puede solicitar copias de las sentencias y actuaciones. Solo los procesos de familia o los que involucren menores pueden tener restricciones de acceso, conforme a la ley.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['publicidad judicial', 'procedimientos públicos', 'sentencias', 'principio de publicidad'], order: 169, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-170', lawId: 'const-buenos-aires', number: '170', title: '', text: `Queda establecida ante todos los tribunales de la Provincia la libre defensa en causa civil propia y la libre representación con las restricciones que establezca la ley de la materia.`, plainLanguageExplanation: 'Ante todos los tribunales provinciales se garantiza la libre defensa en causa propia y la libre representación profesional, con las restricciones que establezca la ley de la materia.', practicalEffects: ['Cualquier persona puede defenderse por sí misma en juicio civil propio sin necesidad de abogado', 'Las restricciones a la representación deben estar previstas en ley, no pueden imponerse de forma arbitraria'], examples: ['Un imputado en causa penal no tiene recursos para contratar abogado privado. La Constitución garantiza su derecho de defensa: el Estado debe proveerle un defensor oficial de forma gratuita. El juicio no puede avanzar sin que el acusado cuente con representación letrada.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libre defensa', 'representación judicial', 'autodefensa', 'acceso a la justicia'], order: 170, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-171', lawId: 'const-buenos-aires', number: '171', title: '', text: `Las sentencias que pronuncien los jueces y tribunales letrados, serán fundadas en el texto expreso de la ley; y a falta de éste, en los principios jurídicos de la legislación vigente en la materia respectiva, y en defecto de éstos, en los principios jurídicos de la legislación vigente en la materia respectiva, y en defecto de éstos, en los principios generales del derecho, teniendo en consideración las circunstancias del caso.`, plainLanguageExplanation: 'Las sentencias deben fundarse en la ley aplicable; en su defecto en los principios de la legislación vigente; y en último lugar en los principios generales del derecho, considerando las circunstancias del caso.', practicalEffects: ['Los jueces no pueden resolver arbitrariamente: siempre deben invocar el fundamento normativo de sus decisiones', 'La jerarquía de fuentes (ley, principios legales, principios generales) establece una guía clara para integrar lagunas normativas'], examples: ['Un juez dicta una sentencia que rechaza la demanda con una sola frase: "no hay mérito". Esa sentencia es nula por falta de fundamentación: la Constitución exige que los jueces expliquen en qué ley, doctrina o principio general del derecho basan su decisión, permitiendo que las partes la entiendan y eventualmente la apelen.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fundamentación sentencias', 'fuentes del derecho', 'principios generales', 'motivación judicial'], order: 171, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-172', lawId: 'const-buenos-aires', number: '172', title: '', text: `La legislatura establecerá Juzgados de Paz en todos los partidos de la Provincia que no sean cabecera de departamento judicial, pudiendo incrementar su número conforme al grado de litigiosidad, la extensión territorial y la población respectiva. Serán competentes, además de las materias que les fije la ley, en faltas provinciales, en causas de menor cuantía y vecinales. Asimismo podrá crear, donde no existan Juzgados de Paz, otros órganos jurisdiccionales letrados para entender en cuestiones de menor cuantía, vecinales y faltas provinciales.`, plainLanguageExplanation: 'La Legislatura crea Juzgados de Paz en los partidos sin cabecera judicial, competentes en faltas provinciales, causas menores y vecinales, garantizando acceso a la justicia en todo el territorio provincial.', practicalEffects: ['Los Juzgados de Paz resuelven conflictos de menor cuantía y vecinales sin la complejidad de un tribunal ordinario', 'Su presencia en todos los partidos acerca la justicia a las comunidades más alejadas de los centros judiciales'], examples: ['En un pueblo bonaerense sin juzgado civil, el Juzgado de Paz resuelve un conflicto de límites entre vecinos por una suma de $300.000. El juez de paz puede tramitar ese litigio localmente, evitando que los vecinos tengan que viajar varias horas hasta la ciudad cabecera para acceder a la justicia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Juzgados de Paz', 'justicia de paz', 'causas menores', 'acceso territorial a la justicia'], order: 172, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-173', lawId: 'const-buenos-aires', number: '173', title: '', text: `Los jueces a que alude el artículo anterior serán nombrados en la forma y bajo los requisitos establecidos para los de primera instancia. Se les exigirá una residencia inmediata previa de dos años en el lugar en que deban cumplir sus funciones. Conservarán sus cargos mientras dure su buena conducta y su responsabilidad se hará efectiva de conformidad con lo dispuesto en el Capítulo VI de la presente sección.`, plainLanguageExplanation: 'Los jueces de paz son designados con los mismos requisitos y formas que los de primera instancia, deben residir dos años en el lugar de sus funciones y son inamovibles mientras dure su buena conducta.', practicalEffects: ['Los jueces de paz tienen estabilidad en su cargo, lo que los protege de presiones de autoridades locales', 'El requisito de residencia previa garantiza que el juez conozca la comunidad donde ejercerá'], examples: ['Un candidato a juez de paz en General Lavalle lleva 6 meses viviendo en el partido. No cumple el requisito de residencia previa de 2 años en el municipio. Aunque tenga experiencia jurídica, su designación sería inconstitucional hasta que complete el tiempo de arraigo exigido.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['jueces de paz', 'requisitos', 'inamovilidad', 'residencia previa'], order: 173, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-174', lawId: 'const-buenos-aires', number: '174', title: '', text: `La ley establecerá, para las causas de menor cuantía y vecinales, un procedimiento predominantemente oral que garantice la inmediatez, informalidad, celeridad, accesibilidad y economía procesal. Se procurará, con preferencia, la conciliación.`, plainLanguageExplanation: 'Para las causas de menor cuantía y vecinales la ley establecerá un procedimiento oral que priorice la inmediatez, informalidad, celeridad, accesibilidad y economía procesal, promoviendo la conciliación.', practicalEffects: ['El proceso oral en causas menores es más rápido y accesible que el proceso escrito ordinario', 'La conciliación como método preferente reduce la carga del sistema judicial y fomenta soluciones autocompuestas'], examples: ['Dos vecinos de un pueblo rural discuten por el pago de una deuda de $80.000. Acuden al Juzgado de Paz, donde el juez convoca a una audiencia oral. En pocos minutos, escucha a ambas partes, propone una conciliación y el conflicto queda resuelto el mismo día, sin necesidad de presentaciones escritas ni abogados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['proceso oral', 'causas menores', 'conciliación', 'accesibilidad judicial'], order: 174, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-175', lawId: 'const-buenos-aires', number: '175', title: '', text: `Los jueces de la Suprema Corte de Justicia, el Procurador y el Subprocurador General, serán designados por el Poder Ejecutivo, con acuerdo del Senado, otorgado en sesión pública por mayoría absoluta de sus miembros. Los demás jueces e integrantes del ministerio público serán designados por el Poder Ejecutivo, de una terna vinculante propuesta por el Consejo de la Magistratura, con acuerdo del Senado otorgado en sesión pública. Será función indelegable del Consejo de la Magistratura seleccionar los postulantes mediante procedimientos que garanticen adecuada publicidad y criterios objetivos predeterminados de evaluación. Se privilegiará la solvencia moral, la idoneidad y el respeto por las instituciones democráticas y los derechos humanos. El consejo de la Magistratura se compondrá, equilibradamente, con representantes de los Poderes Ejecutivo y Legislativo, de los jueces de las distintas instancias y de la institución que regula la matrícula de los abogados en la Provincia. El Consejo de la Magistratura se conformará con un mínimo de quince miembros. Con carácter consultivo, y por Departamento Judicial, lo integrarán jueces y abogados; así como personalidades académicas especializadas. La ley determinará sus demás atribuciones, regulará su funcionamiento y la periodicidad de los mandatos.`, plainLanguageExplanation: 'Los jueces de la Suprema Corte son designados por el Ejecutivo con acuerdo del Senado. Los demás jueces son designados por el Ejecutivo a partir de ternas vinculantes del Consejo de la Magistratura, con acuerdo del Senado.', practicalEffects: ['El Consejo de la Magistratura actúa como filtro técnico y objetivo para seleccionar candidatos a la judicatura', 'La terna vinculante impide que el Ejecutivo elija libremente: debe optar entre los tres candidatos seleccionados'], examples: ['El Consejo de la Magistratura bonaerense convoca a concurso para cubrir una vacante en el fuero laboral de La Plata. Evalúa a los postulantes y eleva al Ejecutivo una terna con los tres mejor calificados. El Gobernador elige a uno de los tres y solicita el acuerdo del Senado, que tiene 15 días para pronunciarse.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['designación de jueces', 'Consejo de la Magistratura', 'terna vinculante', 'acuerdo del Senado'], order: 175, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-176', lawId: 'const-buenos-aires', number: '176', title: '', text: `Los Jueces letrados, el Procurador y Subprocurador General de la Suprema Corte de Justicia conservarán sus empleos mientras dure su buena conducta.`, plainLanguageExplanation: 'Los jueces letrados, el Procurador y Subprocurador General conservan sus cargos indefinidamente mientras mantengan buena conducta, garantizando la inamovilidad como pilar de la independencia judicial.', practicalEffects: ['Un juez no puede ser removido por el Ejecutivo ni el Legislativo por razones políticas o de discrepancia jurídica', 'La inamovilidad es la garantía más importante de la independencia del Poder Judicial frente a los otros poderes'], examples: ['Un juez dicta sentencias que perjudican al gobierno provincial. El Gobernador no puede removerlo ni trasladarlo por esa razón: la inamovilidad judicial garantiza que los jueces fallen sin presiones políticas. Solo puede ser removido por el Jurado de Enjuiciamiento si incurre en mal desempeño o delito.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inamovilidad judicial', 'buena conducta', 'independencia judicial', 'jueces'], order: 176, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-177', lawId: 'const-buenos-aires', number: '177', title: '', text: `Para ser juez de la Suprema Corte de Justicia, Procurador y Subprocurador General de ella, se requiere: Haber nacido en territorio argentino o ser hijo de ciudadano nativo si hubiese nacido en país extranjero, título o diploma que acredite suficiencia en la ciencia del derecho reconocido por autoridad competente en la forma que determine la ley; treinta años de edad y menos de setenta y diez a lo menos de ejercicio en la profesión de abogado o en el desempeño de alguna magistratura. Para serlo de las Cámaras de Apelación, bastarán seis años.`, plainLanguageExplanation: 'Para integrar la Suprema Corte se requiere ser argentino nativo o hijo de nativo, tener título de abogado reconocido, 30 años de edad, menos de 70 años, y al menos 10 años de ejercicio profesional o en la magistratura. Para las Cámaras basta con 6 años.', practicalEffects: ['El límite de 70 años de edad garantiza la renovación generacional del tribunal supremo', 'La experiencia mínima de 10 años asegura que los miembros de la Suprema Corte sean juristas formados'], examples: ['Un abogado con 10 años de ejercicio profesional y ciudadano argentino nativo postula a un cargo en la Suprema Corte bonaerense. Cumple los requisitos constitucionales: título de abogado, ciudadanía y experiencia mínima en la profesión. Si supera el concurso del Consejo, puede integrar el máximo tribunal provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos Suprema Corte', 'magistratura', 'título abogado', 'experiencia profesional'], order: 177, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-178', lawId: 'const-buenos-aires', number: '178', title: '', text: `Para ser juez de primera instancia se requiere: tres años de práctica en la profesión de abogado, seis años de ciudadanía en ejercicio y veinticinco años de edad.`, plainLanguageExplanation: 'Para ser juez de primera instancia se requieren tres años de práctica como abogado, seis años de ciudadanía activa y 25 años de edad mínima.', practicalEffects: ['Los requisitos de primera instancia son menos exigentes que los de Cámara o Suprema Corte, permitiendo incorporar juristas jóvenes al Poder Judicial', 'Los tres años de práctica garantizan experiencia real antes de asumir la responsabilidad de resolver casos'], examples: ['Una abogada de 29 años con 4 años de ejercicio profesional aspira a ser jueza de primera instancia en el fuero civil. Cumple los requisitos: es argentina, tiene título de abogada y experiencia suficiente. Si el Consejo de la Magistratura la incluye en la terna y el Gobernador la elige, puede asumir el cargo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos juez primera instancia', 'práctica profesional', 'ciudadanía', 'magistratura'], order: 178, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-179', lawId: 'const-buenos-aires', number: '179', title: '', text: `Los jueces de la Suprema Corte de Justicia prestarán juramento ante su presidente de desempeñar fielmente el cargo. El presidente lo prestará ante la Suprema Corte de Justicia, y los demás jueces ante quien determine el mismo tribunal.`, plainLanguageExplanation: 'Los jueces de la Suprema Corte prestan juramento ante el presidente del tribunal; el presidente jura ante la Corte en pleno; y los demás jueces ante quien determine la propia Suprema Corte.', practicalEffects: ['El juramento es requisito de validez del cargo: sin él el juez no puede ejercer jurisdicción', 'La Suprema Corte tiene autonomía para determinar ante quién juran los jueces de menor instancia'], examples: ['El nuevo juez designado para el Juzgado en lo Contencioso-Administrativo presta juramento ante la Suprema Corte de Justicia de la Provincia. Desde ese momento queda habilitado para dictar resoluciones, y su actuación anterior al juramento carece de valor jurídico.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juramento judicial', 'asunción del cargo', 'Suprema Corte', 'formalidad constitucional'], order: 179, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-180', lawId: 'const-buenos-aires', number: '180', title: '', text: `Los jueces de la Suprema Corte de Justicia, Cámara de Apelación y de Primera Instancia, no pueden ser suspendidos en el ejercicio de sus cargos, sino en el caso de acusación y con sujeción a lo que se dispone en esta Constitución.`, plainLanguageExplanation: 'Los jueces de la Suprema Corte, Cámaras y Primera Instancia no pueden ser suspendidos en el ejercicio de sus funciones salvo en el caso de acusación formal prevista en la Constitución.', practicalEffects: ['Un juez no puede ser separado preventivamente de su cargo por presión política o mediática', 'Solo el proceso constitucional de acusación (juicio político o jury) habilita la suspensión'], examples: ['Se formula acusación formal ante el Jurado de Enjuiciamiento contra un juez penal por cohecho. El juez queda automáticamente suspendido en sus funciones mientras dura el proceso. Si el Jurado lo absuelve, es reintegrado con todos sus haberes y derechos como si la suspensión no hubiera ocurrido.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['suspensión de jueces', 'inamovilidad', 'acusación', 'garantías judiciales'], order: 180, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-181', lawId: 'const-buenos-aires', number: '181', title: '', text: `Para ingresar al Poder Judicial debe justificarse dos años de residencia inmediata en la Provincia.`, plainLanguageExplanation: 'Para ingresar a cualquier cargo del Poder Judicial se requieren dos años de residencia inmediata y continua en la Provincia de Buenos Aires.', practicalEffects: ['Los candidatos a cargos judiciales deben haber vivido en la Provincia durante los dos años previos a su designación', 'Este requisito garantiza arraigo local y conocimiento de la realidad jurídica provincial'], examples: ['Un abogado de Córdoba que acaba de mudarse a La Plata postula para ser secretario de juzgado. Según la ley, debe acreditar un tiempo mínimo de domicilio en la Provincia antes de ingresar al Poder Judicial bonaerense. El requisito de residencia previa garantiza un mínimo de arraigo territorial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos Poder Judicial', 'residencia', 'ingreso judicial', 'magistratura'], order: 181, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-182', lawId: 'const-buenos-aires', number: '182', title: '', text: `Los jueces de las Cámaras de Apelación y de Primera Instancia y los miembros del Ministerio Público pueden ser denunciados o acusados por cualquiera del pueblo, por delitos o faltas cometidas en el desempeño de sus funciones, ante un jurado de once miembros que podrá funcionar con número no inferior a seis, integrado por el presidente de la Suprema Corte de Justicia que lo presidirá, cinco abogados inscriptos en la matrícula que reúnan las condiciones para ser miembro de dicho tribunal, y hasta cinco legisladores abogados. Los legisladores y abogados que deban integrar el jurado se designará por sorteo, en acto público, en cada caso; los legisladores por el presidente del Senado y los abogados por la Suprema Corte de Justicia, a cuyo cargo estará la confección de la lista de todos los abogados que reúnan las condiciones para ser conjueces. La ley determinará la forma de reemplazar a los abogados no legisladores en caso de vacante.`, plainLanguageExplanation: 'Los jueces de Cámara, de primera instancia y del Ministerio Público pueden ser acusados ante un jurado de 11 miembros (presidido por el Presidente de la Suprema Corte, cinco abogados y hasta cinco legisladores abogados, designados por sorteo) por delitos o faltas en el ejercicio de sus funciones.', practicalEffects: ['El jurado de enjuiciamiento es el mecanismo constitucional para remover jueces que no integran la Suprema Corte', 'La composición mixta (Corte + abogados + legisladores) busca equilibrar la independencia judicial con la responsabilidad pública'], examples: ['Un juez de cámara es acusado de mal desempeño por dictar sentencias sin fundamentación. El Jurado de Enjuiciamiento —integrado por legisladores, abogados y magistrados— tramita el proceso y, si lo declara culpable, lo destituye. Este tribunal especial garantiza que la remoción no sea arbitraria.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['jurado de enjuiciamiento', 'remoción de jueces', 'responsabilidad judicial', 'tribunal especial'], order: 182, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-183', lawId: 'const-buenos-aires', number: '183', title: '', text: `El juez acusado quedará suspendido en el ejercicio de su cargo desde el día en que el jurado admita la acusación.`, plainLanguageExplanation: 'Desde el momento en que el jurado admite formalmente la acusación, el juez queda automáticamente suspendido en el ejercicio de su cargo hasta que se dicte el veredicto.', practicalEffects: ['La suspensión es automática desde la admisión de la acusación: no requiere decisión adicional', 'Durante la suspensión el juez no puede ejercer jurisdicción ni firmar resoluciones'], examples: ['El Jurado de Enjuiciamiento admite la acusación contra un juez de primera instancia. Desde ese momento, el juez queda suspendido sin perjuicio de sus derechos económicos hasta la sentencia final. La causa sigue su trámite y el juez puede presentar su defensa ante el Jurado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['suspensión del juez', 'admisión de acusación', 'jurado de enjuiciamiento', 'proceso judicial'], order: 183, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-184', lawId: 'const-buenos-aires', number: '184', title: '', text: `El jurado dará su veredicto de culpabilidad, la causa se remitirá al juez competente para que aplique la ley penal cuando corresponda.`, plainLanguageExplanation: 'Si el jurado emite un veredicto de culpabilidad, el juez queda destituido del cargo. La causa puede entonces remitirse al juez penal competente para que aplique las sanciones criminales que correspondan.', practicalEffects: ['El veredicto de culpabilidad produce la destitución automática del juez, sin necesidad de otro acto', 'La separación del proceso disciplinario (jurado) del penal (justicia ordinaria) garantiza que ambas respondan a lógicas propias'], examples: ['El Jurado de Enjuiciamiento declara culpable a un juez por haberse parcializado sistemáticamente en favor de una de las partes. Como consecuencia, el juez es destituido del cargo. A partir de ese momento, la justicia penal ordinaria puede procesarlo por los delitos que hubiera cometido durante su gestión.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['veredicto culpabilidad', 'destitución judicial', 'proceso penal', 'responsabilidad del juez'], order: 184, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-185', lawId: 'const-buenos-aires', number: '185', title: '', text: `Pronunciado el veredicto de culpabilidad, la causa se remitirá al juez competente para que aplique la ley penal cuando corresponda.`, plainLanguageExplanation: 'Una vez pronunciado el veredicto de culpabilidad por el jurado, la causa se remite al juez penal competente para la aplicación de las penas previstas en la ley criminal cuando corresponda.', practicalEffects: ['El jurado de enjuiciamiento solo resuelve la responsabilidad disciplinaria; el juicio penal es independiente', 'La condena penal del juez requiere un proceso judicial ordinario separado del proceso de destitución'], examples: ['El Jurado de Enjuiciamiento destituye a un juez por irregularidades que podrían constituir el delito de prevaricato. El expediente es remitido al Ministerio Público Fiscal para que inicie la acción penal ante el juez ordinario competente, quien juzgará al ex magistrado como a cualquier ciudadano.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derivación al fuero penal', 'juicio penal del juez', 'responsabilidad criminal', 'enjuiciamiento'], order: 185, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-186', lawId: 'const-buenos-aires', number: '186', title: '', text: `La ley determinará los delitos y faltas de los jueces acusables ante el jurado y reglamentará el procedimiento que ante él debe observarse.`, plainLanguageExplanation: 'La ley determinará qué delitos y faltas habilitan la acusación de un juez ante el jurado y regulará el procedimiento que debe seguirse en dicho tribunal.', practicalEffects: ['La taxatividad de las causales de acusación protege a los jueces frente a acusaciones políticas infundadas', 'El procedimiento ante el jurado debe estar regulado por ley para garantizar el debido proceso al juez acusado'], examples: ['La ley que regula el enjuiciamiento de magistrados bonaerenses define como causal de acusación la mora reiterada e injustificada en dictar sentencias. Un juez que tiene centenares de expedientes sin resolver por años puede ser acusado ante el Jurado de Enjuiciamiento por esa causal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['causales de acusación', 'ley de enjuiciamiento', 'procedimiento judicial', 'responsabilidad de jueces'], order: 186, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-187', lawId: 'const-buenos-aires', number: '187', title: '', text: `Los jueces acusados de delitos ajenos a sus funciones serán juzgados en la misma forma que los demás habitantes de la Provincia, quedando suspendidos desde el día en que se haga lugar a la acusación.`, plainLanguageExplanation: 'Los jueces acusados por delitos cometidos fuera del ejercicio de sus funciones son juzgados como cualquier otro ciudadano, quedando suspendidos desde que se admite la acusación en el fuero penal ordinario.', practicalEffects: ['Un juez que comete un delito común (ej.: estafa, lesiones) es juzgado por el fuero penal ordinario, no por el jurado de enjuiciamiento', 'La suspensión opera de pleno derecho una vez que se habilita la acusación en el proceso penal'], examples: ['Un juez causa un accidente de tránsito grave fuera del horario de trabajo. Como el hecho no tiene relación con sus funciones judiciales, la causa penal ordinaria avanza sin necesidad de enjuiciamiento previo. Sin embargo, si el proceso llega a etapa de juicio oral, el juez puede ser suspendido preventivamente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['delito fuera de funciones', 'proceso penal ordinario', 'suspensión', 'responsabilidad penal de jueces'], order: 187, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-188', lawId: 'const-buenos-aires', number: '188', title: '', text: `La ley determinará el modo y forma como deben ser nombrados y removidos y la duración del período de los demás funcionarios que intervengan en los juicios.`, plainLanguageExplanation: 'La ley determinará el modo de designar y remover a los demás funcionarios judiciales (secretarios, auxiliares, etc.) que no están cubiertos directamente por las normas constitucionales.', practicalEffects: ['Los cargos auxiliares del Poder Judicial son creados, regulados y removidos por ley ordinaria', 'La delegación a la ley permite flexibilidad para adaptar la estructura judicial a las necesidades del sistema'], examples: ['La Ley Orgánica del Poder Judicial bonaerense regula el nombramiento y remoción de secretarios, prosecretarios, oficiales y demás auxiliares de los juzgados. Un secretario que incurre en irregularidades puede ser removido conforme al procedimiento que establece esa ley, sin que la Legislatura tenga que intervenir directamente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['funcionarios judiciales auxiliares', 'nombramiento', 'remoción', 'ley orgánica del Poder Judicial'], order: 188, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-189', lawId: 'const-buenos-aires', number: '189', title: '', text: `El Ministerio Público será desempeñado por el Procurador y Subprocurador General de la Suprema Corte de Justicia; por los Fiscales de Cámaras, quienes deberán reunir las condiciones requeridas para ser jueces de las Cámaras de Apelación; por agentes fiscales, asesores de menores y defensores de pobres y ausentes, quienes deberán reunir las condiciones requeridas para ser jueces de primera instancia. El Procurador General ejercerá superintendencia sobre los demás miembros del Ministerio Público.`, plainLanguageExplanation: 'El Ministerio Público está integrado por el Procurador y Subprocurador General, los Fiscales de Cámara, agentes fiscales, asesores de menores y defensores de pobres y ausentes. El Procurador General ejerce superintendencia sobre todos ellos.', practicalEffects: ['El Ministerio Público tiene una estructura jerarquizada encabezada por el Procurador General de la Suprema Corte', 'Los defensores de pobres garantizan el acceso a la justicia de personas sin recursos ante los tribunales provinciales'], examples: ['Un detenido sin recursos solicita asesoramiento legal. El Defensor Oficial del Ministerio Público lo asiste gratuitamente durante todo el proceso penal. Paralelamente, el Fiscal del Ministerio Público sostiene la acusación: ambos son parte del mismo Ministerio Público pero ejercen funciones contrapuestas, garantizando el equilibrio procesal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Ministerio Público', 'Procurador General', 'defensores de pobres', 'fiscales'], order: 189, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-190', lawId: 'const-buenos-aires', number: '190', title: '', text: `La administración de los intereses y servicios locales en la Capital y cada uno de los partidos que formen la Provincia, estará a cargo de una municipalidad, compuesta de un departamento ejecutivo unipersonal y un departamento deliberativo, cuyos miembros, que no podrán ser menos de seis ni más de veinticuatro, durarán cuatro años en sus funciones, renovándose cada dos años por mitad y serán elegidos en el mismo acto que se elijan los senadores y diputados, en la forma que determine la ley.`, plainLanguageExplanation: 'Cada partido provincial tiene una municipalidad compuesta por un Departamento Ejecutivo unipersonal (intendente) y un Departamento Deliberativo (concejo deliberante) cuyos miembros duran cuatro años y se renuevan por mitad cada dos años.', practicalEffects: ['El intendente y los concejales son elegidos directamente por el pueblo en los mismos comicios legislativos', 'La renovación bienal del concejo garantiza continuidad institucional y representación actualizada'], examples: ['El municipio de Tandil tiene su propio gobierno: el Intendente conduce el Ejecutivo local y el Concejo Deliberante dicta ordenanzas. Ambos son elegidos directamente por los vecinos del partido. El gobierno provincial no puede designar ni remover al Intendente: la autonomía municipal está constitucionalmente garantizada.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['municipalidad', 'intendente', 'concejo deliberante', 'régimen municipal'], order: 190, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-191', lawId: 'const-buenos-aires', number: '191', title: '', text: `La Legislatura deslindará las atribuciones y responsabilidades de cada departamento, confiriéndoles las facultades necesarias para que ellos puedan atender eficazmente a todos los intereses y servicios locales, con sujeción a las siguientes bases: 1° El número de miembros del departamento deliberativo se fijará con relación a la población de cada distrito. 2° Serán electores los ciudadanos inscriptos en el registro electoral del distrito y además los extranjeros mayores de edad que sepan leer y escribir en idioma nacional, con dos años de residencia inmediata en el municipio, que estén inscriptos en un registro especial y paguen anualmente impuestos fiscales o municipales que en conjunto no bajen de doscientos pesos. 3° Serán elegibles todos los ciudadanos mayores de veinticinco años, que sepan leer y escribir, vecinos del distrito, con un año de domicilio anterior a la elección y sí son extranjeros, tengan además cinco años de residencia y estén inscriptos en el registro especial. 4° Las funciones municipales serán carga pública, de la que nadie podrá excusarse sino por excepción fundada en la ley de la materia. 5° El ciudadano a cargo del departamento ejecutivo durará cuatro años en sus funciones. Para desempeñar este cargo se requiere ciudadanía en ejercicio y las condiciones necesarias para ser concejal. 6° Los concejales extranjeros no podrán exceder de la tercera parte del número total de los miembros del concejo deliberante.`, plainLanguageExplanation: 'La Legislatura define las atribuciones y responsabilidades municipales, establece las bases para el número de concejales, el padrón electoral municipal (incluidos extranjeros con dos años de residencia y contribuyentes), y fija los requisitos para ser elegible concejal.', practicalEffects: ['Los extranjeros con dos años de residencia y que paguen tributos pueden votar en elecciones municipales', 'Los concejales extranjeros no pueden superar la tercera parte del total del cuerpo deliberativo'], examples: ['Un ciudadano italiano que vive hace 5 años en Luján puede votar en las elecciones municipales de ese partido, aunque no tenga ciudadanía argentina: la Constitución bonaerense permite que los extranjeros residentes voten en comicios locales. Incluso puede ser elegido concejal si cumple los requisitos de la ley municipal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribuciones municipales', 'padrón municipal', 'extranjeros votantes', 'concejales'], order: 191, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-192', lawId: 'const-buenos-aires', number: '192', title: '', text: `Son atribuciones inherentes al régimen municipal, las siguientes: 1° Convocar a los electores del distrito para elegir municipales y consejeros escolares, con quince días de anticipación por lo menos, cuando el Poder Ejecutivo dejare transcurrir los términos legales sin hacerlo. 2° Proponer al Poder Ejecutivo, en la época que corresponda, las ternas para nombramientos de jueces de paz y suplentes. 3° Nombrar los funcionarios municipales. 4° Tener a su cargo el ornato y salubridad, los establecimientos de beneficencia que no estén a cargo de sociedades particulares, asilos de inmigrantes que sostengan la Provincia, las cárceles locales de detenidos y la vialidad pública. 5° Votar anualmente su presupuesto y los recursos para costearlo administrar los bienes raíces municipales, con facultad de enajenar tanto éstos como los diversos ramos de las rentas del año corriente; examinar y resolver sobre las cuentas del año vencido, remitiéndolas enseguida al Tribunal de Cuentas. Vencido el ejercicio administrativo sin que el concejo deliberante sancione el presupuesto de gastos, el intendente deberá regirse por el sancionado para el año anterior. Las ordenanzas impositivas mantendrán su vigencia hasta que sean modificadas o derogadas por otras. El presupuesto será proyectado por el departamento ejecutivo y el deliberativo no está facultado para aumentar su monto total. Si aquél no lo remitiera antes del 31 de octubre, el concejo deliberante podrá proyectarlo y sancionarlo, pero su monto no podrá exceder del total de la recaudación habida en el año inmediato anterior. En caso de veto total o parcial, si el concejo deliberante insistiera por dos tercios de votos, el intendente está obligado a promulgarlo. Toda ordenanza especial que autorice gastos no previstos en el presupuesto, deberá establecer los recursos con que han de ser cubiertos. 6° Dictar ordenanzas y reglamentos dentro de estas atribuciones. 7° Recaudar, distribuir y oblar en la tesorería del Estado las contribuciones que la Legislatura imponga al distrito par las necesidades generales, sin perjuicio de que el Poder Ejecutivo nombra funcionarios especiales para este objeto, si lo cree más conveniente. 8° Constituir consorcios de municipalidades y cooperativas de vecinos a los fines de la creación de superusinas generadoras de energía eléctrica.`, plainLanguageExplanation: 'Las municipalidades tienen atribuciones inherentes: convocar elecciones, gestionar el ornato, salubridad, establecimientos de beneficencia, cárceles locales, vialidad pública, votar el presupuesto anual y dictar ordenanzas dentro de sus competencias.', practicalEffects: ['El municipio puede convocar elecciones locales si el Poder Ejecutivo omite hacerlo en término', 'El concejo deliberante no puede aumentar el monto total del presupuesto proyectado por el intendente'], examples: ['El Concejo Deliberante de Azul aprueba una ordenanza que establece horarios de cierre obligatorio para los comercios locales. Esa ordenanza tiene fuerza de ley dentro del municipio. Simultáneamente, aprueba el presupuesto municipal para el ejercicio siguiente y regula el alumbrado y la recolección de residuos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribuciones municipales', 'presupuesto municipal', 'ordenanzas', 'servicios locales'], order: 192, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-193', lawId: 'const-buenos-aires', number: '193', title: '', text: `Las atribuciones expresadas tienen las siguientes limitaciones: 1° Dar publicidad por la prensa a todos sus actos, reseñándolos en una memoria anual, en la que se hará constar detalladamente la percepción e inversión de sus rentas. 2° Todo aumento o creación de impuestos o contribución de mejoras, necesita ser sancionado por mayoría absoluta de votos de una asamblea compuesta por los miembros del Concejo Deliberante y un número igual de mayores contribuyentes de impuestos municipales. 3° No podrá autorizarse empréstito alguno sobre el crédito general de la municipalidad, sino por ordenanza sancionada en la forma que determina el inciso anterior; pero en ningún caso podrá sancionarse ordenanza de esta clase cuando el total de los servicios de amortización e intereses, afecte en más del 25 por ciento los recursos ordinarios de la municipalidad. Cuando se trate de contratar empréstitos en el extranjero o enajenar o gravar los edificios municipales, se requerirá, además, autorización legislativa. 4° Siempre que se haga uso del crédito será para obras señaladas de mejoramiento o para casos eventuales, y se votará una suma anual para el servicio de la deuda, no pudiendo aplicarse los fondos a otro objeto que el indicado. 5° Las enajenaciones sólo podrán hacerse en remate público. 6° Siempre que hubiere de construirse una obra municipal, de cualquier género que fuere, en la que hubieren de invertirse fondos del común, la municipalidad nombrará una comisión de propietarios electores del distrito, para que la fiscalice. 7° Las obras públicas cuyo importe exceda de mil pesos nacionales, deberán sacarse siempre a licitación.`, plainLanguageExplanation: 'Las atribuciones municipales tienen límites: publicidad de actos por memoria anual, mayoría especial para crear impuestos, restricciones al endeudamiento (máximo 25% de recursos ordinarios en servicios de deuda), licitación pública para obras que superen mil pesos, y control ciudadano de obras municipales.', practicalEffects: ['Crear o aumentar impuestos municipales requiere aprobación de una asamblea mixta de concejales y mayores contribuyentes', 'El endeudamiento municipal tiene techo constitucional: no puede comprometer más del 25% de los recursos ordinarios'], examples: ['El municipio de Bahía Blanca quiere construir un nuevo hospital y necesita endeudarse. La Constitución le impone que el financiamiento sea aprobado por la Legislatura provincial antes de contraer la deuda. Además, cualquier obra de esa magnitud debe licitarse públicamente para garantizar transparencia en el gasto.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['límites municipales', 'impuestos locales', 'deuda municipal', 'licitación pública'], order: 193, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-194', lawId: 'const-buenos-aires', number: '194', title: '', text: `Los municipales, funcionarios y empleados, son personalmente responsables, no sólo de cualquier acto definido y penado por la ley, sino también por los daños y perjuicios provenientes de la falta de cumplimiento a sus deberes. La ley determinará las causas, forma y oportunidad de destitución de los municipales, funcionarios y empleados, que, por deficiencias de conducta o incapacidad sean inconvenientes o perjudiciales en el desempeño de sus cargos.`, plainLanguageExplanation: 'Los funcionarios y empleados municipales son personalmente responsables tanto por actos delictivos como por los daños derivados de incumplir sus deberes. La ley fija las causas y formas para destituirlos.', practicalEffects: ['Un concejal o funcionario municipal puede ser demandado civilmente por los daños causados por su negligencia o incumplimiento', 'La responsabilidad personal impide que el municipio sea el único responsable ante los vecinos por la mala gestión'], examples: ['Un Intendente municipal adjudica una licitación a una empresa vinculada a sus familiares sin respetar el procedimiento. Los vecinos afectados pueden demandar al municipio por daños y perjuicios, y la Legislatura provincial puede promover el juicio político del Intendente por mal desempeño de funciones.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad municipal', 'funcionarios municipales', 'daños y perjuicios', 'destitución'], order: 194, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-195', lawId: 'const-buenos-aires', number: '195', title: '', text: `Todos los actos y contratos emanados de autoridades municipales que no estén constituidas en la forma que prescribe esta Constitución, serán de ningún valor.`, plainLanguageExplanation: 'Los actos y contratos emanados de autoridades municipales que no estén constituidas conforme a la Constitución son absolutamente nulos y carecen de todo efecto jurídico.', practicalEffects: ['Un concejo deliberante o intendencia irregular no puede dictar actos válidos', 'La nulidad es absoluta e insanable: ningún otro acto puede convalidar la actuación de una autoridad municipal de facto'], examples: ['Un grupo de ciudadanos toma por la fuerza el palacio municipal y designa un "intendente provisorio" no electo. Todos los actos que dicte esa autoridad de facto son nulos de nulidad absoluta. Los contratos firmados, las ordenanzas dictadas y los nombramientos realizados no tienen validez jurídica.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nulidad actos municipales', 'autoridades irregulares', 'municipalidad de facto', 'validez jurídica'], order: 195, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-196', lawId: 'const-buenos-aires', number: '196', title: '', text: `Los conflictos internos de las municipalidades sea que se produzcan entre los departamentos ejecutivo y deliberativo, sea que ocurran en el seno de este último, los de las distintas municipalidades entre sí o con otras autoridades de la Provincia, serán dirimidos por la Suprema Corte de Justicia.`, plainLanguageExplanation: 'Los conflictos internos de los municipios (entre intendente y concejo o dentro del concejo) y los conflictos entre municipios o entre un municipio y otra autoridad provincial son resueltos por la Suprema Corte de Justicia.', practicalEffects: ['La Suprema Corte actúa como árbitro constitucional en los conflictos intermunicipales o intra-municipales', 'No existe un tribunal intermedio para estos conflictos: el máximo tribunal los resuelve directamente'], examples: ['El municipio de Pilar y el de Malvinas Argentinas disputan la competencia sobre la regulación de un corredor industrial limítrofe. Ningún organismo provincial inferior puede resolver el conflicto: el caso debe llevarse ante la Suprema Corte de Justicia bonaerense, que tiene competencia originaria para dirimir estas controversias entre municipios.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conflictos municipales', 'Suprema Corte', 'arbitraje institucional', 'competencia'], order: 196, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-197', lawId: 'const-buenos-aires', number: '197', title: '', text: `En caso de acefalía de una municipalidad, el Poder Ejecutivo convocará inmediatamente a elecciones para constituirla.`, plainLanguageExplanation: 'Ante la acefalía de una municipalidad (cuando no hay intendente ni concejo válidos), el Poder Ejecutivo provincial debe convocar de inmediato a elecciones para reconstituirla.', practicalEffects: ['El Ejecutivo provincial tiene obligación de actuar rápidamente ante la acefalía municipal', 'No existe un régimen de intervención permanente: la normalización pasa por convocar a elecciones'], examples: ['El Intendente y el presidente del Concejo Deliberante de un municipio renuncian simultáneamente. La Constitución prevé que el Poder Ejecutivo provincial intervenga para convocar a elecciones municipales y normalizar la institución, garantizando que los vecinos elijan sus propias autoridades en el menor plazo posible.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acefalía municipal', 'elecciones municipales', 'Poder Ejecutivo', 'normalización institucional'], order: 197, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-198', lawId: 'const-buenos-aires', number: '198', title: '', text: `La Cultura y la Educación constituyen derechos humanos fundamentales. Toda persona tiene derecho a la educación y a tomar parte, libremente, en la vida cultural de la comunidad. La Provincia reconoce a la Familia como agente educador y socializador primario. La Educación es responsabilidad indelegable de la Provincia, la cual coordinará institucionalmente el sistema educativo y proveerá los servicios correspondientes, asegurando el libre acceso, permanencia y egreso a la educación en igualdad de oportunidades y posibilidades.`, plainLanguageExplanation: 'La cultura y la educación son derechos humanos fundamentales. La Provincia reconoce a la familia como agente educador primario y asume la responsabilidad indelegable de garantizar el acceso libre e igualitario a la educación en todos sus niveles.', practicalEffects: ['El Estado provincial no puede delegar la responsabilidad educativa en otros niveles de gobierno', 'El acceso libre e igualitario a la educación es justiciable: las personas pueden exigirlo ante los tribunales'], examples: ['Una familia de escasos recursos en un barrio periférico de La Matanza tiene derecho a que sus hijos accedan a educación pública gratuita y de calidad. El Estado provincial tiene la obligación constitucional de garantizar ese acceso, incluyendo la provisión de infraestructura, docentes y materiales didácticos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho a la educación', 'cultura', 'familia', 'igualdad de oportunidades'], order: 198, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-199', lawId: 'const-buenos-aires', number: '199', title: '', text: `La Educación tendrá por objeto la formación integral de la persona con dimensión trascendente y el respeto a los derechos humanos y libertades fundamentales, formando el carácter de los niños en el culto de las instituciones patrias, en el respeto a los símbolos nacionales y en los principios de la moral cristiana, respetando la libertad de conciencia.`, plainLanguageExplanation: 'La educación tiene por objeto la formación integral de la persona, el respeto por los derechos humanos, la formación en los valores patrios, los símbolos nacionales y los principios de la moral cristiana, con respeto a la libertad de conciencia.', practicalEffects: ['El currículo escolar provincial debe incluir la formación en instituciones democráticas y derechos humanos', 'La referencia a la moral cristiana convive con el respeto a la libertad de conciencia, garantizando que no sea excluyente'], examples: ['Los programas de estudio de las escuelas bonaerenses deben incluir educación en derechos humanos y formación ciudadana. Una escuela que adoctrine a sus alumnos en una única ideología política viola el mandato constitucional de formar personas con pensamiento crítico y libertad de conciencia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['objetivo educativo', 'formación integral', 'derechos humanos', 'libertad de conciencia'], order: 199, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-200', lawId: 'const-buenos-aires', number: '200', title: '', text: `La prestación del servicio educativo, se realizará a través del sistema educativo provincial, constituido por las unidades funcionales creadas al efecto y que abarcarán los distintos niveles y modalidades de la educación. La legislación de base del sistema educativo provincial se ajustara a los principios siguientes: 1.- La Educación pública de gestión oficial es gratuita en todos los niveles. 2.- La Educación es obligatoria en el nivel general básico. 3.- El sistema educativo garantizará una calidad educativa equitativa que enfatice el acervo cultural y la protección y preservación del medio ambiente, reafirmando la identidad bonaerense. 4.- El servicio educativo podrá ser prestado por otros sujetos privados o públicos no estatales, dentro del sistema educativo provincial y bajo control estatal.`, plainLanguageExplanation: 'El sistema educativo provincial garantiza educación pública gratuita en todos los niveles, educación obligatoria en el nivel general básico y permite la prestación privada bajo control estatal.', practicalEffects: ['La educación primaria y secundaria básica es obligatoria y gratuita, con responsabilidad del Estado de garantizarla', 'Las escuelas privadas pueden operar dentro del sistema educativo bajo supervisión del Estado provincial'], examples: ['Un niño en edad escolar que no asiste a la escuela activa la responsabilidad del Estado: la educación básica es obligatoria en la Provincia. Si la familia no puede afrontar costos, la educación pública es gratuita. Las escuelas privadas pueden cobrar cuota pero deben cumplir los lineamientos curriculares provinciales.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['educación gratuita', 'educación obligatoria', 'escuelas privadas', 'sistema educativo'], order: 200, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-201', lawId: 'const-buenos-aires', number: '201', title: '', text: `El Gobierno y la Administración del sistema cultural y educativo provincial, estarán a cargo de una Dirección General de Cultura y Educación, autárquica y con idéntico rango al establecido en el artículo 147. La titularidad del mencionado organismo será ejercida por un Director General de Cultura y Educación, designado por el Poder Ejecutivo con acuerdo del Senado. Durará cuatro años en su mandato pudiendo ser reelecto, deberá ser idóneo para la gestión educativa y cumplir con los mismos requisitos que para ser senador. El Director General de Cultura y Educación priorizará el control de la calidad en la prestación del servicio educativo. Corresponde al Director General de Cultura y Educación el nombramiento y remoción de todo el personal técnico, administrativo y docente.`, plainLanguageExplanation: 'El sistema educativo provincial es gobernado por la Dirección General de Cultura y Educación, organismo autárquico cuyo Director General es designado por el Ejecutivo con acuerdo del Senado por un período de cuatro años.', practicalEffects: ['La autarquía de la DGCyE le otorga independencia del Ejecutivo en la gestión educativa cotidiana', 'El requisito de idoneidad en gestión educativa y las condiciones de senador garantizan un mínimo de calidad en quien conduce el sistema'], examples: ['La Dirección General de Cultura y Educación elabora el diseño curricular bonaerense y lo implementa sin necesidad de aprobación del Ministerio de Educación nacional en lo que respecta a materias provinciales. Su carácter autárquico le permite manejar su presupuesto con relativa independencia del Poder Ejecutivo provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Dirección General de Cultura y Educación', 'autarquía educativa', 'Director General', 'gestión educativa'], order: 201, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-202', lawId: 'const-buenos-aires', number: '202', title: '', text: `El titular de la Dirección General de Cultura y Educación contará con el asesoramiento de un Consejo General de Cultura y Educación en los términos que establezca la legislación respectiva. El Consejo General de Cultura y Educación estará integrado -además del Director General, quien lo presidirá- por diez miembros, designados por el Poder Ejecutivo con acuerdo de la Cámara de Diputados: seis de ellos, por propia iniciativa; y los otros cuatro, a propuesta de los docentes en ejercicio. Los consejeros generales durarán en sus funciones un año, pudiendo ser reelectos.`, plainLanguageExplanation: 'El Director General de Cultura y Educación cuenta con un Consejo General de Cultura y Educación de 10 miembros, con mandatos anuales, designados por el Ejecutivo con acuerdo de la Cámara de Diputados, incluyendo cuatro propuestos por los docentes en ejercicio.', practicalEffects: ['La participación de representantes docentes en el Consejo garantiza que los propios educadores tengan voz en las políticas educativas', 'El mandato anual permite renovar el asesoramiento de manera continua y actualizada'], examples: ['El Consejo General de Educación, integrado entre otros por consejeros elegidos por los docentes, asesora a la Dirección General de Cultura y Educación sobre los lineamientos curriculares y las condiciones laborales docentes. Su composición participativa garantiza que la voz de los propios educadores sea parte del sistema de gobierno educativo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Consejo General de Educación', 'consejeros docentes', 'asesoramiento educativo', 'Cámara de Diputados'], order: 202, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-203', lawId: 'const-buenos-aires', number: '203', title: '', text: `La Administración de los servicios educativos, en el ámbito de competencia territorial distrital, con exclusión de los aspectos técnicos pedagógicos estará a cargo de órganos desconcentrados de la Dirección General de Cultura y Educación denominados Consejos Escolares. Estos órganos serán colegiados, integrados por ciudadanos elegidas por el voto popular, en número que se fijará con relación a la cantidad de servicios educativos existentes en cada distrito, y que no será menor a cuatro ni mayor a diez miembros. Los Consejeros Escolares durarán en sus funciones cuatro años, renovándose cada dos años por mitades, pudiendo ser reelectos. Serán electores los ciudadanos argentinos y los extranjeros en las condiciones que determine la ley inscriptos en el registro electoral del distrito, y serán condiciones para ser elegidos: ser mayor de edad y vecino del distrito con no menos de dos años de domicilio inmediato anterior a la elección.`, plainLanguageExplanation: 'La administración educativa distrital no pedagógica está a cargo de Consejos Escolares, órganos colegiados elegidos por voto popular con entre 4 y 10 miembros que duran cuatro años y se renuevan por mitad cada dos años.', practicalEffects: ['Los Consejos Escolares son elegidos directamente por la ciudadanía, garantizando representación local en la gestión educativa', 'La renovación bienal por mitades garantiza continuidad administrativa en cada distrito escolar'], examples: ['Los vecinos de Olavarría eligen a sus Consejeros Escolares junto con las demás autoridades locales. Una vez en funciones, el Consejo Escolar del distrito gestiona el mantenimiento edilicio de las escuelas, administra los fondos del Fondo Educativo y colabora con la Dirección General en las necesidades educativas locales.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Consejos Escolares', 'gestión educativa distrital', 'elección popular', 'representación local'], order: 203, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-204', lawId: 'const-buenos-aires', number: '204', title: '', text: `El presupuesto de gastos dispondrá los recursos necesarios para la prestación adecuada de los servicios educativos, constituyendo además en forma simultánea y específica, un Fondo Provincial de Educación. Los recursos que conformen dicho fondo, ingresarán directamente al mismo y serán administrados por la Dirección General de Cultura y Educación.`, plainLanguageExplanation: 'El presupuesto provincial debe destinar los recursos necesarios para la educación. Se constituye simultáneamente un Fondo Provincial de Educación cuyos recursos ingresan directamente a él y son administrados por la Dirección General de Cultura y Educación.', practicalEffects: ['El Fondo Provincial de Educación tiene recursos específicamente afectados y no pueden redirigirse a otros fines', 'La DGCyE administra directamente los fondos educativos, garantizando que sean utilizados en educación'], examples: ['La Legislatura debe destinar un porcentaje mínimo del presupuesto provincial al Fondo de Educación. Si en un año de crisis fiscal el Ejecutivo propone reducir ese fondo por debajo del piso constitucional, la Legislatura puede rechazar esa parte del presupuesto y restituir los créditos educativos al nivel mínimo garantizado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Fondo Provincial de Educación', 'presupuesto educativo', 'financiamiento', 'DGCyE'], order: 204, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-205', lawId: 'const-buenos-aires', number: '205', title: '', text: `Las leyes orgánicas y reglamentarias de la Educación Universitaria, se ajustarán a las reglas siguientes: 1°.- La Educación Universitaria estará a cargo de las universidades que se fundaren en adelante. 2°.- La enseñanza será accesible para todos los habitantes de la Provincia, y gratuita, con las limitaciones que la ley establezca. 3°.- Las universidades se compondrán de un consejo superior, presidido por el rector y de las diversas facultades establecidas en aquéllas por las leyes de su creación. 4°.- El consejo universitario será formado por los decanos y delegados de las diversas facultades; y éstas serán integradas por miembros ad honorem, cuyas condiciones y nombramiento determinará la ley. 5°.- Corresponderá al consejo universitario: dictar los reglamentos que exijan el orden y disciplina de los establecimientos de su dependencia; la aprobación de los presupuestos anuales que deben ser sometidos a la sanción legislativa; la jurisdicción superior policial y disciplinaria que las leyes y reglamentos le acuerden, y la decisión en última instancia de todas las cuestiones contenciosas decididas en primera instancia por una de las facultades; promover el perfeccionamiento de la enseñanza; proponer la creación de nuevas facultades y cátedras; reglamentar la expedición de matrículas y diplomas y fijar los derechos que puedan cobrarse por ellos. 6°.- Corresponderá a las facultades: la elección de su decano y secretario; el nombramiento de profesores titulares o interinos; la dirección de la enseñanza, formación de los programas y la recepción de exámenes y pruebas en sus respectivos ramos científicos; fijar las condiciones de admisibilidad de los alumnos; administrar los fondos que les corresponden, rindiendo cuenta al consejo; proponer a éste los presupuestos anuales, y toda medida conducente a la mejora de los estudios o régimen interno de las facultades.`, plainLanguageExplanation: 'La educación universitaria es gratuita y accesible para todos. Las universidades se gobiernan a través de un Consejo Superior presidido por el Rector y las facultades, que tienen autonomía para nombrar profesores, fijar programas y gestionar sus fondos.', practicalEffects: ['La gratuidad universitaria es un mandato constitucional que no puede ser derogado por ley ordinaria', 'Las facultades tienen autonomía para designar profesores, fijar programas y administrar sus presupuestos'], examples: ['La UNLP (Universidad Nacional de La Plata) está radicada en la Provincia pero es una institución nacional autónoma: se gobierna a sí misma, elige sus autoridades y define sus programas. La Provincia reconoce esa autonomía y no puede interferir en sus decisiones académicas ni presupuestarias.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['educación universitaria', 'gratuidad universitaria', 'autonomía universitaria', 'gobierno universitario'], order: 205, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-206', lawId: 'const-buenos-aires', number: '206', title: '', text: `Esta Constitución sólo podrá ser reformada por el siguiente procedimiento: a) El proyecto de reforma será tramitado en la forma establecida para la sanción de las leyes, debiendo contar con el voto afirmativo de dos tercios del total de los miembros de ambas cámaras para ser aprobado. La ley indicará si la reforma será total o parcial y, en este último caso, las partes o los artículos que serán reformados; b) La misma ley establecerá si ha de convocarse o no, a una convención reformadora. En este último caso la ley contendrá la enmienda proyectada y ésta será sometida a plebiscito en la primera elección que se realice. El voto será expresado en pro o en contra de la enmienda y su resultado será comunicado por la Junta Electoral al Poder Ejecutivo y a la Legislatura, para su cumplimiento.`, plainLanguageExplanation: 'La Constitución solo puede reformarse mediante ley aprobada por dos tercios de ambas cámaras. Puede hacerse por convención reformadora o, para enmiendas parciales, por plebiscito sin convención. En ambos casos la reforma debe ser ratificada democráticamente.', practicalEffects: ['La exigencia de dos tercios en ambas cámaras hace que la reforma constitucional requiera un amplio consenso político', 'Las enmiendas por plebiscito sin convención son más ágiles pero igualmente requieren ratificación popular'], examples: ['La Legislatura bonaerense aprueba con dos tercios de sus miembros la necesidad de reformar la Constitución para incorporar mecanismos de democracia directa. Esa declaración activa el proceso constituyente: se convoca a los ciudadanos a elegir convencionales constituyentes que debatirán y aprobarán los cambios.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reforma constitucional', 'dos tercios', 'convención reformadora', 'plebiscito'], order: 206, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-207', lawId: 'const-buenos-aires', number: '207', title: '', text: `En caso de convocarse a una convención reformadora, la ley expresará la forma de su funcionamiento y el plazo dentro del cual deberá dar término a su cometido.`, plainLanguageExplanation: 'Si se convoca una Convención Reformadora, la ley de convocatoria debe establecer cómo funcionará la convención y fijar el plazo máximo dentro del cual debe concluir su tarea.', practicalEffects: ['La convención no puede extenderse indefinidamente: el plazo fijado por la ley la obliga a concluir sus trabajos', 'La ley de convocatoria delimita el alcance de la convención, que no puede exceder los temas habilitados'], examples: ['La Convención Constituyente bonaerense se reúne con un plazo de 6 meses para debatir los puntos habilitados por la Legislatura. Si la Convención no termina su trabajo en ese plazo, la reforma no puede seguir adelante: debe disolverse y el proceso reiniciarse si la Legislatura lo vuelve a declarar necesario.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Convención Reformadora', 'plazo reforma', 'convocatoria', 'reforma constitucional'], order: 207, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-208', lawId: 'const-buenos-aires', number: '208', title: '', text: `La convención será formada por ciudadanos que reúna las condiciones necesarias para ser diputados y se compondrá del mismo número de miembros que la Asamblea Legislativa. La elección se llevará a cabo en la misma forma y por los mismos medios que la de diputados y senadores. La ley determinará las incompatibilidades para ser diputados convencional.`, plainLanguageExplanation: 'La Convención Reformadora se integra con el mismo número de miembros que la Asamblea Legislativa, elegidos en la misma forma que diputados y senadores, debiendo reunir las condiciones para ser diputado.', practicalEffects: ['La magnitud de la convención asegura representatividad pluralista en la reforma constitucional', 'Los convencionales son elegidos directamente por la ciudadanía, reforzando el origen democrático de la reforma'], examples: ['Los ciudadanos bonaerenses eligen a los convencionales constituyentes por voto directo, siguiendo reglas similares a las elecciones legislativas. Los convencionales electos se reúnen en Convención y debaten solo los puntos habilitados por la Legislatura: no pueden reformar artículos que no estén en el temario aprobado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['convencionales constituyentes', 'Convención Reformadora', 'elección', 'representatividad'], order: 208, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-209', lawId: 'const-buenos-aires', number: '209', title: '', text: `Las enmiendas aprobada en plebiscito y las sanciones de la convención reformadora, serán promulgadas y publicadas como parte integrante de la Constitución.`, plainLanguageExplanation: 'Las enmiendas aprobadas en plebiscito y las sanciones de la Convención Reformadora son promulgadas y publicadas como parte integrante de la Constitución provincial, con la misma jerarquía que el texto original.', practicalEffects: ['Una vez aprobada por plebiscito o convención, la reforma pasa a tener pleno valor constitucional sin necesidad de ratificación legislativa', 'La promulgación y publicación oficial dan certeza jurídica sobre el texto reformado'], examples: ['La Convención Constituyente aprueba las reformas. Según la Constitución, el nuevo texto reformado entra en vigor una vez promulgado, sin necesidad de ratificación popular adicional salvo que la Convención así lo disponga. El texto reformado es publicado en el Boletín Oficial y pasa a ser la nueva Constitución de la Provincia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['promulgación reforma', 'texto constitucional', 'plebiscito', 'Convención Reformadora'], order: 209, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-210', lawId: 'const-buenos-aires', number: '210', title: '', text: `Los institutos de formas de democracia semidirecta establecidos en esta Constitución serán reglamentados en un plazo que no exceda el próximo período legislativo (corresponde al artículo 67).`, plainLanguageExplanation: 'Disposición transitoria que ordena reglamentar los mecanismos de democracia semidirecta (iniciativa popular y referéndum) dentro del período legislativo inmediato siguiente a la reforma constitucional de 1994.', practicalEffects: ['Esta disposición tiene carácter transitorio y fue cumplida cuando la Legislatura dictó las leyes reglamentarias de los arts. 67 (iniciativa popular) y referéndum', 'La omisión de reglamentación no podría impedir el ejercicio de estos derechos directamente operativos'], examples: ['La Constitución incorporó la iniciativa popular como mecanismo de democracia directa, pero su ejercicio queda supeditado a que la Legislatura dicte la ley reglamentaria. Hasta que esa ley no existe, los ciudadanos no pueden ejercer el derecho aunque la Constitución lo reconozca formalmente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'democracia semidirecta', 'reglamentación', 'iniciativa popular'], order: 210, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-211', lawId: 'const-buenos-aires', number: '211', title: '', text: `La Ley Orgánica de las Municipalidades deberá contemplar la posibilidad que los municipios accedan a los institutos de democracia semidirecta.`, plainLanguageExplanation: 'Disposición transitoria que ordena que la Ley Orgánica de las Municipalidades contemple la posibilidad de que los municipios apliquen mecanismos de democracia semidirecta como el referéndum local o la consulta popular.', practicalEffects: ['Los municipios pueden eventualmente adoptar mecanismos de participación ciudadana directa en la gestión local', 'La habilitación constitucional depende de que la ley orgánica municipal desarrolle estos institutos'], examples: ['El Concejo Deliberante de Mar del Plata quiere someter a consulta popular la aprobación de un proyecto de urbanización costera. Para hacerlo, debe esperar que la Legislatura provincial reglamente el mecanismo de democracia directa municipal previsto en la Constitución. Mientras esa ley no exista, el referéndum local no puede realizarse.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['democracia semidirecta municipal', 'referéndum local', 'participación ciudadana', 'disposición transitoria'], order: 211, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-212', lawId: 'const-buenos-aires', number: '212', title: '', text: `En el próximo período legislativo se determinará que las construcciones con acceso al público preverán el desplazamiento normal de las personas discapacitadas. Buscará rectificar las normas de construcción vigentes y establecerá los plazos para adecuar las existentes (corresponde artículo 36 inciso 5).`, plainLanguageExplanation: 'Disposición transitoria relacionada con el art. 36 inc. 5 (discapacidad): la Legislatura debía establecer en el período siguiente la obligación de que las construcciones con acceso al público prevean el desplazamiento normal de personas con discapacidad.', practicalEffects: ['Esta disposición impulsó la legislación de accesibilidad edilicia para personas con discapacidad en la Provincia', 'Los plazos para adecuar construcciones existentes debían ser fijados por ley en el período siguiente a la reforma'], examples: ['Una persona con movilidad reducida denuncia que el nuevo edificio de la municipalidad no tiene rampa de acceso. La disposición transitoria obliga al Estado a adecuar sus construcciones a la normativa de accesibilidad en un plazo determinado. Mientras esa adecuación no se cumpla, existe una omisión constitucional exigible judicialmente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accesibilidad', 'discapacidad', 'construcciones públicas', 'disposición transitoria'], order: 212, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-213', lawId: 'const-buenos-aires', number: '213', title: '', text: `La ley que regule el voto de los extranjeros deberá determinar el plazo a partir del cual se hará efectivo su ejercicio, el que no podrá ser superior a dos años contados desde la sanción de la presente reforma constitucional. (corresponde al artículo 59).`, plainLanguageExplanation: 'Disposición transitoria vinculada al art. 59: la ley que regule el voto de extranjeros en elecciones municipales debía determinar la fecha de vigencia, con un máximo de dos años desde la reforma de 1994.', practicalEffects: ['El sufragio de los extranjeros en elecciones municipales fue implementado mediante ley luego de la reforma de 1994', 'El plazo máximo de dos años obligaba a la Legislatura a actuar rápidamente en la reglamentación'], examples: ['Antes de la reforma de 1994, solo los ciudadanos argentinos votaban en elecciones municipales. La cláusula transitoria estableció que los extranjeros residentes podían sufragar en los comicios locales una vez que la Legislatura dictara la ley reglamentaria habilitante, ampliando el padrón electoral municipal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['voto extranjeros', 'elecciones municipales', 'sufragio', 'disposición transitoria'], order: 213, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-214', lawId: 'const-buenos-aires', number: '214', title: '', text: `El artículo 123 de la presente Constitución regirá a partir del período de gobierno iniciado por las autoridades ejecutivas electas en el año 1995; pero su aplicación inmediata podrá ponerse a consideración popular a través de un plebiscito a realizarse hasta sesenta días después de sancionada la presente, de voto obligatorio y vinculantes, en el cual la reelección deberá obtener, como mínimo, la mitad más uno de los votos válidamente emitidos. A este efecto se computarán únicamente los votos positivos y negativos. Dicho plebiscito podrá ser convocado al efecto por el Poder Ejecutivo en los términos de la Ley Electoral vigente, a cuyo efecto podrá adecuar y modificar todos los plazos previstos en la misma. La Provincia será considerada como un distrito único y se utilizará el mismo padrón electoral del comicio del 10 de abril de 1994, dejando sin efecto lo que contempla el artículo 3° inciso 2 apartado b) de la ley 5109. En caso de ser aprobada por plebiscito la aplicación inmediata del artículo 123 de la presente Constitución, el período actual de gobierno del Ejecutivo Provincial será considerado primer período de gobierno. (corresponde al artículo 123).`, plainLanguageExplanation: 'Disposición transitoria sobre la reelección del Gobernador (art. 123): establece que la norma rige desde el período iniciado en 1995, con posibilidad de aplicación inmediata si se aprobaba por plebiscito vinculante con mayoría simple.', practicalEffects: ['Esta cláusula transitoria permitió al entonces gobernador Eduardo Duhalde buscar la reelección en 1995 si el plebiscito la aprobaba', 'El plebiscito fue vinculante y de voto obligatorio, computando solo votos positivos y negativos'], examples: ['La reforma de 1994 introdujo la reelección del Gobernador. La cláusula transitoria fijó las reglas de cómputo para quienes ya habían ejercido el cargo antes de la reforma: estableció a partir de cuándo empezaba a contar el límite de mandatos, evitando retroactividad y garantizando previsibilidad para los mandatarios vigentes.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reelección Gobernador', 'plebiscito 1994', 'cláusula transitoria', 'período de gobierno'], order: 214, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-215', lawId: 'const-buenos-aires', number: '215', title: '', text: `La Legislatura establecerá el fuero contencioso administrativo antes del 1° de octubre de 1997 y sancionará el Código Procesal respectivo, para su entrada en vigencia conjunta. Hasta tanto comiencen las funciones de los tribunales en lo contencioso administrativo, la Suprema Corte de Justicia decidirá, en única instancia y juicio pleno, todas las causas correspondientes al referido fuero que se hubieren iniciado, hasta su finalización. (corresponde al artículo 166).`, plainLanguageExplanation: 'Disposición transitoria vinculada al art. 166: la Legislatura debía crear el fuero contencioso-administrativo antes del 1° de octubre de 1997. Hasta que esos tribunales comenzaran a funcionar, la Suprema Corte resolvía esas causas en única instancia.', practicalEffects: ['La transición evitó un vacío jurisdiccional: la Suprema Corte continuó resolviendo las causas contencioso-administrativas hasta la creación del nuevo fuero', 'El plazo de 1997 era vinculante para la Legislatura, que debía tanto crear el fuero como dictar el Código Procesal Contencioso-Administrativo'], examples: ['Antes de que se crearan los juzgados contencioso-administrativos descentralizados, la Suprema Corte tenía competencia originaria en esas causas. La cláusula transitoria reguló cómo se distribuirían los expedientes en trámite entre el viejo sistema y los nuevos tribunales al momento de su puesta en funcionamiento.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fuero contencioso-administrativo', 'Suprema Corte', 'transición judicial', 'disposición transitoria'], order: 215, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-216', lawId: 'const-buenos-aires', number: '216', title: '', text: `En los partidos donde no existieren Juzgados de Paz, y hasta tanto entre en funciones los órganos previstos en el artículo 172 entenderán en materia de faltas provinciales o contravencionales los Juzgados Criminales y Correccionales en la forma que determine la ley. (corresponde al artículo 172).`, plainLanguageExplanation: 'Disposición transitoria vinculada al art. 172: mientras no estuviesen en funcionamiento los Juzgados de Paz en todos los partidos, los Juzgados Criminales y Correccionales entenderían provisoriamente en materia de faltas provinciales y contravenciones.', practicalEffects: ['Esta norma evitó lagunas de jurisdicción en materia contravencional durante el período de implementación de los Juzgados de Paz', 'La vigencia de esta cláusula era transitoria y cesó cuando se crearon los Juzgados de Paz en cada partido'], examples: ['Con la reforma de 1994, los Juzgados de Paz asumieron nuevas competencias en materia de faltas provinciales. La disposición transitoria aseguró que los procesos ya iniciados ante los órganos anteriores continuaran su trámite sin interrupción, hasta que los nuevos juzgados estuvieran operativos en todo el territorio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Juzgados de Paz', 'faltas provinciales', 'transición jurisdiccional', 'disposición transitoria'], order: 216, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-217', lawId: 'const-buenos-aires', number: '217', title: '', text: `Se mantiene la vigencia del anterior sistema de designación de magistrados y funcionarios del Poder Judicial, por el plazo máximo de dos años. La presente cláusula no regirá para la designación de los jueces que integren el nuevo fuero contencioso-administrativo. (corresponde al artículo 175).`, plainLanguageExplanation: 'Disposición transitoria relacionada con el art. 175: durante los dos años siguientes a la reforma, continuó vigente el sistema anterior de designación de magistrados, con excepción de los jueces del nuevo fuero contencioso-administrativo que debían aplicar el nuevo sistema.', practicalEffects: ['La cláusula garantizó continuidad en la designación de jueces mientras se implementaba el nuevo Consejo de la Magistratura', 'Los jueces del nuevo fuero contencioso-administrativo debían ser designados desde el inicio bajo las nuevas reglas'], examples: ['La Constitución de 1994 creó el Consejo de la Magistratura para designar jueces por concurso. La cláusula transitoria estableció que los jueces ya designados bajo el sistema anterior mantienen sus cargos y su inamovilidad: el nuevo sistema rige solo para las vacantes que se produzcan a partir de la vigencia de la reforma.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Consejo de la Magistratura', 'designación de jueces', 'sistema transitorio', 'disposición transitoria'], order: 217, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-218', lawId: 'const-buenos-aires', number: '218', title: '', text: `Esta reforma entra en vigencia el día quince de Septiembre de 1994.`, plainLanguageExplanation: 'La reforma constitucional sancionada por la Convención en septiembre de 1994 entró en vigencia el 15 de septiembre de 1994, desde cuya fecha sustituyó al texto anterior de la Constitución de Buenos Aires.', practicalEffects: ['Desde el 15 de septiembre de 1994, el texto reformado es la Constitución vigente de la Provincia de Buenos Aires', 'Los actos producidos entre la sanción (13/09/1994) y la vigencia (15/09/1994) quedan regidos por la norma anterior'], examples: ['La Constitución reformada en 1994 entró en vigor a partir del día indicado en la propia Convención. Desde ese momento, las normas anteriores contrarias a la nueva Constitución quedaron derogadas automáticamente, sin necesidad de que la Legislatura dictara leyes derogatorias expresas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['entrada en vigencia', 'reforma 1994', 'Constitución de Buenos Aires', 'fecha de vigencia'], order: 218, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-219', lawId: 'const-buenos-aires', number: '219', title: '', text: `Los miembros de la Convención Reformadora de esta Constitución, el Gobernador de la Provincia, los presidentes de ambas cámaras legislativas y el Presidente de la Suprema Corte de Justicia, prestarán juramento en un mismo acto el día diecinueve de septiembre de 1994. Cada poder del Estado dispondrá lo necesario, para que los funcionarios que la integran juren esta Constitución.`, plainLanguageExplanation: 'El 19 de septiembre de 1994 los convencionales, el Gobernador, los presidentes de ambas Cámaras y el Presidente de la Suprema Corte prestaron juramento conjunto ante la nueva Constitución. Cada poder debía hacer jurar a sus propios funcionarios.', practicalEffects: ['El juramento colectivo del 19 de septiembre fue el acto simbólico de la puesta en vigencia de la Constitución reformada', 'La obligación de los poderes de hacer jurar a sus funcionarios garantizó la adhesión institucional al nuevo texto constitucional'], examples: ['El 13 de septiembre de 1994, los convencionales constituyentes firmaron y juraron el nuevo texto de la Constitución bonaerense. Ese acto solemne ante la ciudadanía marcó el momento en que el poder constituyente originado en el pueblo formalizó la voluntad de darse una nueva norma fundamental.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juramento constitucional', 'Convención Reformadora', 'septiembre 1994', 'acto de promulgación'], order: 219, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-220', lawId: 'const-buenos-aires', number: '220', title: '', text: `El texto constitucional ordenado, sancionado por la Convención reformadora de la Constitución, reemplaza al hasta ahora vigente.`, plainLanguageExplanation: 'El texto constitucional ordenado y sancionado por la Convención Reformadora de 1994 reemplaza al texto anterior: la vieja Constitución de Buenos Aires dejó de regir y en su lugar rige el texto consolidado aprobado por la convención.', practicalEffects: ['El texto vigente es el "texto ordenado": incluye tanto los artículos históricos no modificados como los nuevos incorporados por la reforma', 'Las referencias a artículos de la Constitución anterior que se encuentren en normas vigentes deben leerse según el nuevo texto'], examples: ['La Convención de 1994 no dictó una Constitución completamente nueva: actualizó y reformó la Constitución de 1934 incorporando los cambios aprobados. El texto resultante es el vigente y reemplazó al anterior en su integridad, siendo el documento que rige todos los poderes públicos bonaerenses.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['texto ordenado', 'reemplazo Constitución', 'Convención Reformadora', 'texto vigente'], order: 220, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-221', lawId: 'const-buenos-aires', number: '221', title: '', text: `Sancionado el texto ordenado de la Constitución se remitirá un ejemplar auténtico al Archivo Histórico de la Provincia, al Registro de leyes de la Provincia y al Archivo General de la Nación.`, plainLanguageExplanation: 'Una vez sancionado el texto constitucional ordenado, debía remitirse un ejemplar auténtico al Archivo Histórico de la Provincia, al Registro de Leyes y al Archivo General de la Nación para su preservación y publicidad.', practicalEffects: ['La entrega de ejemplares a los archivos oficiales garantiza la preservación auténtica del texto constitucional aprobado', 'El Archivo General de la Nación conserva una copia federal del texto constitucional provincial'], examples: ['El original firmado de la Constitución bonaerense se conserva en el Archivo Histórico de la Provincia. Si existe una controversia sobre el texto auténtico de un artículo, ese documento es la referencia definitiva. Cualquier ciudadano puede solicitar acceso al texto para verificar su contenido.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['archivo constitucional', 'texto auténtico', 'Archivo Histórico', 'registro oficial'], order: 221, segments: [], amendments: [] },
  { id: 'const-buenos-aires-art-222', lawId: 'const-buenos-aires', number: '222', title: '', text: `Téngase por sancionada y promulgado el texto constitucional ordenado, comuníquese, publíquese y cúmplase en todo el territorio de la Provincia de Buenos Aires. Firmantes En la Sala de la Honorable Convención Constituyente, en la ciudad de La Plata, a los trece días del mes de septiembre de 1994. MANUEL EDUARDO ISASI Secretario Legislativo H. Convención Constituyente de la Pcia. de Buenos Aires- OSVALDO JOSE MERCURI Presidente H. Convención Constituyente de la Pcia. de Buenos Aires`, plainLanguageExplanation: 'Cláusula promulgatoria final: ordena que el texto constitucional ordenado sea promulgado y publicado para su vigencia y cumplimiento en todo el territorio de la Provincia de Buenos Aires, firmado el 13 de septiembre de 1994.', practicalEffects: ['Esta cláusula cierra formalmente el proceso constituyente: la Constitución queda sancionada, promulgada y en vigencia', 'La firma del Presidente y Secretario de la Convención certifica la autenticidad del texto aprobado'], examples: ['Este artículo es la disposición de sanción formal de la Constitución bonaerense: certifica que la Convención Constituyente de 1994 aprobó el texto y lo promulgó como la Ley Suprema de la Provincia. Es el cierre del acto constituyente que da fuerza normativa obligatoria a todo lo anterior.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['promulgación', 'Constitución de Buenos Aires', 'Convención Constituyente 1994', 'sanción'], order: 222, segments: [], amendments: [] },
];
